/**
 * API для сохранения и загрузки игры
 * Использует Turso/libSQL напрямую
 *
 * POST /api/save - сохранить игру
 * GET /api/save - загрузить игру
 * DELETE /api/save - удалить сохранение (сбросить прогресс)
 */

import { NextRequest, NextResponse } from 'next/server'
import { getDb, initDb } from '@/lib/db'
import { randomUUID } from 'crypto'
import {
  SAVE_PAYLOAD_MAX_BYTES,
  saveRequestBodySchema,
} from '@/lib/save-payload-schema'
import { getServerSession } from 'next-auth'
import { authOptions } from '@/lib/auth-config'

// Демо-игрок для разработки (без авторизации)
const DEMO_PLAYER_ID = 'demo-player'

async function resolvePlayerId(request: NextRequest): Promise<string> {
  if (process.env.ENFORCE_SAVE_AUTH === 'true') {
    const session = await getServerSession(authOptions)
    if (!session?.user?.id) {
      throw Object.assign(new Error('Unauthorized'), { status: 401 })
    }
    return session.user.id
  }
  return request.headers.get('x-player-id') || DEMO_PLAYER_ID
}

// ================================
// GET - Загрузка сохранения
// ================================
export async function GET(request: NextRequest) {
  try {
    const db = await initDb()

    if (!db) {
      return NextResponse.json({
        success: false,
        error: 'Database not configured',
        details: 'TURSO_DATABASE_URL and TURSO_AUTH_TOKEN must be set',
        needsConfig: true,
      }, { status: 503 })
    }

    let playerId: string
    try {
      playerId = await resolvePlayerId(request)
    } catch (e) {
      const status = (e as { status?: number }).status ?? 500
      if (status === 401) {
        return NextResponse.json({ success: false, error: 'Unauthorized' }, { status: 401 })
      }
      throw e
    }

    const result = await db.execute({
      sql: 'SELECT * FROM game_saves WHERE playerId = ?',
      args: [playerId],
    })

    if (result.rows.length === 0) {
      const newSave = await createNewSave(db, playerId)
      if (!newSave) {
        return NextResponse.json(
          { success: false, error: 'Failed to create save' },
          { status: 500 }
        )
      }
      console.log('[Save API] Created new save for:', playerId)
      return NextResponse.json({
        success: true,
        data: formatSaveData(newSave as Record<string, unknown>),
        isNew: true,
      })
    }

    console.log('[Save API] Loaded save for:', playerId)
    return NextResponse.json({
      success: true,
      data: formatSaveData(result.rows[0] as Record<string, unknown>),
      isNew: false,
    })
  } catch (error) {
    console.error('[Save API] Load error:', error)
    const errorMessage = error instanceof Error ? error.message : 'Unknown error'
    return NextResponse.json({
      success: false,
      error: 'Failed to load save',
      details: errorMessage,
    }, { status: 500 })
  }
}

// ================================
// POST - Сохранение игры
// ================================
export async function POST(request: NextRequest) {
  try {
    const db = await initDb()

    if (!db) {
      return NextResponse.json({
        success: false,
        error: 'Database not configured',
        needsConfig: true,
      }, { status: 503 })
    }

    let playerId: string
    try {
      playerId = await resolvePlayerId(request)
    } catch (e) {
      const status = (e as { status?: number }).status ?? 500
      if (status === 401) {
        return NextResponse.json({ success: false, error: 'Unauthorized' }, { status: 401 })
      }
      throw e
    }

    const contentLength = request.headers.get('content-length')
    if (contentLength != null && Number(contentLength) > SAVE_PAYLOAD_MAX_BYTES) {
      return NextResponse.json(
        { success: false, error: 'Payload too large' },
        { status: 413 }
      )
    }

    const text = await request.text()
    if (text.length > SAVE_PAYLOAD_MAX_BYTES) {
      return NextResponse.json(
        { success: false, error: 'Payload too large' },
        { status: 413 }
      )
    }

    let raw: unknown
    try {
      raw = JSON.parse(text) as unknown
    } catch {
      return NextResponse.json(
        { success: false, error: 'Invalid JSON' },
        { status: 400 }
      )
    }

    const zodResult = saveRequestBodySchema.safeParse(raw)
    if (!zodResult.success) {
      return NextResponse.json(
        {
          success: false,
          error: 'Invalid save payload',
          details: zodResult.error.issues,
        },
        { status: 400 }
      )
    }

    const validatedData = validateSaveData(zodResult.data as Record<string, unknown>)

    // Проверяем, существует ли сохранение
    const existing = await db.execute({
      sql: 'SELECT id FROM game_saves WHERE playerId = ?',
      args: [playerId],
    })

    const now = new Date().toISOString()

    if (existing.rows.length > 0) {
      // Обновляем
      await db.execute({
        sql: `UPDATE game_saves SET
          level = ?, experience = ?, fame = ?,
          resources = ?, statistics = ?, workers = ?, buildings = ?,
          maxWorkers = ?, activeCraft = ?, activeRefining = ?,
          weaponInventory = ?, unlockedRecipes = ?, recipeSources = ?,
          unlockedEnchantments = ?, guild = ?, knownAdventurers = ?,
          orders = ?, tutorial = ?, materialKnowledge = ?, playTime = ?, saveVersion = ?, updatedAt = ?
        WHERE playerId = ?`,
        args: [
          validatedData.player.level,
          validatedData.player.experience,
          validatedData.player.fame,
          JSON.stringify(validatedData.resources),
          JSON.stringify(validatedData.statistics),
          JSON.stringify(validatedData.workers),
          JSON.stringify(validatedData.buildings),
          validatedData.maxWorkers,
          JSON.stringify(validatedData.activeCraft),
          JSON.stringify(validatedData.activeRefining),
          JSON.stringify(validatedData.weaponInventory),
          JSON.stringify(validatedData.unlockedRecipes),
          JSON.stringify(validatedData.recipeSources),
          JSON.stringify(validatedData.unlockedEnchantments),
          JSON.stringify(validatedData.guild),
          JSON.stringify(validatedData.knownAdventurers),
          JSON.stringify(validatedData.orders),
          JSON.stringify(validatedData.tutorial),
          JSON.stringify(validatedData.materialKnowledge),
          validatedData.playTime,
          validatedData.saveVersion,
          now,
          playerId,
        ],
      })
    } else {
      // Создаём новое
      await db.execute({
        sql: `INSERT INTO game_saves (
          id, playerId, level, experience, fame,
          resources, statistics, workers, buildings, maxWorkers,
          activeCraft, activeRefining, weaponInventory, unlockedRecipes,
          recipeSources, unlockedEnchantments, guild, knownAdventurers,
          orders, tutorial, materialKnowledge, playTime, saveVersion, updatedAt
        ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
        args: [
          randomUUID(),
          playerId,
          validatedData.player.level,
          validatedData.player.experience,
          validatedData.player.fame,
          JSON.stringify(validatedData.resources),
          JSON.stringify(validatedData.statistics),
          JSON.stringify(validatedData.workers),
          JSON.stringify(validatedData.buildings),
          validatedData.maxWorkers,
          JSON.stringify(validatedData.activeCraft),
          JSON.stringify(validatedData.activeRefining),
          JSON.stringify(validatedData.weaponInventory),
          JSON.stringify(validatedData.unlockedRecipes),
          JSON.stringify(validatedData.recipeSources),
          JSON.stringify(validatedData.unlockedEnchantments),
          JSON.stringify(validatedData.guild),
          JSON.stringify(validatedData.knownAdventurers),
          JSON.stringify(validatedData.orders),
          JSON.stringify(validatedData.tutorial),
          JSON.stringify(validatedData.materialKnowledge),
          validatedData.playTime,
          validatedData.saveVersion,
          now,
        ],
      })
    }

    console.log(`[Save API] Saved for player ${playerId}`)

    return NextResponse.json({
      success: true,
      savedAt: now,
    })
  } catch (error) {
    console.error('[Save API] Save error:', error)
    const errorMessage = error instanceof Error ? error.message : 'Unknown error'
    return NextResponse.json({
      success: false,
      error: 'Failed to save',
      details: errorMessage,
    }, { status: 500 })
  }
}

// ================================
// DELETE - Удаление сохранения (сброс)
// ================================
export async function DELETE(request: NextRequest) {
  try {
    const db = await initDb()

    if (!db) {
      return NextResponse.json({
        success: false,
        error: 'Database not configured',
        needsConfig: true,
      }, { status: 503 })
    }

    let playerId: string
    try {
      playerId = await resolvePlayerId(request)
    } catch (e) {
      const status = (e as { status?: number }).status ?? 500
      if (status === 401) {
        return NextResponse.json({ success: false, error: 'Unauthorized' }, { status: 401 })
      }
      throw e
    }

    const row = await db.execute({
      sql: 'SELECT id FROM game_saves WHERE playerId = ?',
      args: [playerId],
    })

    const gameSaveId = row.rows[0]?.['id'] as string | undefined
    if (gameSaveId) {
      await db.execute({
        sql: 'DELETE FROM save_history WHERE gameSaveId = ?',
        args: [gameSaveId],
      })
    }

    await db.execute({
      sql: 'DELETE FROM game_saves WHERE playerId = ?',
      args: [playerId],
    })

    console.log(`[Save API] Deleted save for player ${playerId}`)

    return NextResponse.json({ success: true })
  } catch (error) {
    console.error('[Save API] Delete error:', error)
    const errorMessage = error instanceof Error ? error.message : 'Unknown error'
    return NextResponse.json({
      success: false,
      error: 'Failed to delete save',
      details: errorMessage,
    }, { status: 500 })
  }
}

// ================================
// HELPER FUNCTIONS
// ================================

function formatSaveData(row: Record<string, unknown>) {
  return {
    id: row['id'],
    playerId: row['playerId'],
    level: row['level'],
    experience: row['experience'],
    fame: row['fame'],
    resources: safeJsonParse(row['resources'] as string, {}),
    statistics: safeJsonParse(row['statistics'] as string, {}),
    workers: safeJsonParse(row['workers'] as string, []),
    buildings: safeJsonParse(row['buildings'] as string, []),
    maxWorkers: row['maxWorkers'],
    activeCraft: safeJsonParse(row['activeCraft'] as string, {}),
    activeRefining: safeJsonParse(row['activeRefining'] as string, {}),
    weaponInventory: safeJsonParse(row['weaponInventory'] as string, { weapons: [] }),
    unlockedRecipes: safeJsonParse(row['unlockedRecipes'] as string, {
      weaponRecipes: [],
      refiningRecipes: [],
    }),
    recipeSources: safeJsonParse(row['recipeSources'] as string, []),
    unlockedEnchantments: safeJsonParse(row['unlockedEnchantments'] as string, []),
    guild: safeJsonParse(row['guild'] as string, {}),
    knownAdventurers: safeJsonParse(row['knownAdventurers'] as string, []),
    orders: safeJsonParse(row['orders'] as string, {}),
    tutorial: safeJsonParse(row['tutorial'] as string, { isActive: true, currentStep: 0 }),
    materialKnowledge: safeJsonParse(row['materialKnowledge'] as string, {}),
    playTime: row['playTime'],
    saveVersion: row['saveVersion'],
    createdAt: row['createdAt'],
    updatedAt: row['updatedAt'],
    serverTimestamp: row['updatedAt'],
  }
}

function safeJsonParse(str: string | null | undefined, fallback: unknown) {
  if (!str) return fallback
  try {
    return JSON.parse(str)
  } catch {
    return fallback
  }
}

async function createNewSave(db: ReturnType<typeof getDb>, playerId: string) {
  const initialResources = {
    gold: 100,
    wood: 20,
    stone: 10,
    iron: 5,
    coal: 5,
    copper: 0,
    tin: 0,
    silver: 0,
    goldOre: 0,
    mithril: 0,
    soulEssence: 0,
    planks: 0,
    stoneBlocks: 0,
    copperIngot: 0,
    tinIngot: 0,
    bronzeIngot: 0,
    ironIngot: 0,
    steelIngot: 0,
    silverIngot: 0,
    goldIngot: 0,
    mithrilIngot: 0,
  }

  const initialStatistics = {
    totalCrafts: 0,
    totalRefines: 0,
    totalGoldEarned: 0,
    totalWorkersHired: 0,
    playTime: 0,
    weaponsSold: 0,
    recipesUnlocked: 6,
    ordersCompleted: 0,
    weaponsSacrificed: 0,
    enchantmentsApplied: 0,
  }

  const initialGuild = {
    level: 1,
    glory: 0,
    adventurers: [],
    activeExpeditions: [],
    recoveryQuests: [],
    history: [],
    adventurerRefreshAt: Date.now(),
  }

  const now = new Date().toISOString()
  const id = randomUUID()

  await db!.execute({
    sql: `INSERT INTO game_saves (
      id, playerId, level, experience, fame,
      resources, statistics, workers, buildings, maxWorkers,
      activeCraft, activeRefining, weaponInventory, unlockedRecipes,
      recipeSources, unlockedEnchantments, guild, knownAdventurers,
      orders, tutorial, materialKnowledge, playTime, saveVersion, updatedAt
    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
    args: [
      id,
      playerId,
      1, 0, 0,
      JSON.stringify(initialResources),
      JSON.stringify(initialStatistics),
      '[]', '[]', 3,
      '{}', '{}',
      '{"weapons":[]}',
      '{"weaponRecipes":["sword_iron","dagger_iron","sword_bronze","dagger_bronze","sword_copper","dagger_copper"],"refiningRecipes":[]}',
      '[]', '[]',
      JSON.stringify(initialGuild),
      '[]',
      '{}',
      '{"isActive":true,"currentStep":0}',
      '{}',
      0, 2, now,
    ],
  })

  // Возвращаем созданный save
  const result = await db!.execute({
    sql: 'SELECT * FROM game_saves WHERE id = ?',
    args: [id],
  })

  return result.rows[0]
}

function validateSaveData(data: Record<string, unknown>) {
  const player = data['player'] as Record<string, unknown> | undefined

  return {
    player: {
      level: Math.max(1, Number(player?.['level']) || 1),
      experience: Math.max(0, Number(player?.['experience']) || 0),
      fame: Math.max(0, Number(player?.['fame']) || 0),
    },
    resources: (data['resources'] as Record<string, unknown>) || {},
    statistics: (data['statistics'] as Record<string, unknown>) || {},
    workers: (data['workers'] as unknown[]) || [],
    buildings: (data['buildings'] as unknown[]) || [],
    maxWorkers: Math.max(1, Number(data['maxWorkers']) || 3),
    activeCraft: (data['activeCraft'] as Record<string, unknown>) || {},
    activeRefining: (data['activeRefining'] as Record<string, unknown>) || {},
    weaponInventory: (data['weaponInventory'] as Record<string, unknown>) || { weapons: [] },
    unlockedRecipes: (data['unlockedRecipes'] as Record<string, unknown>) || { weaponRecipes: [], refiningRecipes: [] },
    recipeSources: (data['recipeSources'] as unknown[]) || [],
    unlockedEnchantments: (data['unlockedEnchantments'] as unknown[]) || [],
    guild: (data['guild'] as Record<string, unknown>) || {},
    knownAdventurers: (data['knownAdventurers'] as unknown[]) || [],
    orders: (data['orders'] as Record<string, unknown>) || {},
    tutorial: (data['tutorial'] as Record<string, unknown>) || { isActive: true, currentStep: 0 },
    materialKnowledge: (data['materialKnowledge'] as Record<string, unknown>) || {},
    playTime: Math.max(0, Number(data['playTime']) || 0),
    saveVersion: Number(data['saveVersion']) || 2,
  }
}

/**
 * Enchant Weapon Modal
 * Модальное окно зачарования оружия
 */

'use client'

import { motion } from 'framer-motion'
import { X, Lock, CheckCircle } from 'lucide-react'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { cn } from '@/lib/utils'
import { useGameStore } from '@/store'
import { 
  enchantments, 
  enchantmentSchools, 
  enchantmentSchoolInfo, 
  getEnchantment,
  type EnchantmentSchool 
} from '@/data/enchantments'

interface EnchantWeaponModalProps {
  weapon: any
  onClose: () => void
  onEnchant: (enchantmentId: string) => void
}

export function EnchantWeaponModal({
  weapon,
  onClose,
  onEnchant
}: EnchantWeaponModalProps) {
  const unlockedEnchantments = useGameStore((state) => state.unlockedEnchantments)
  
  // Фильтруем доступные зачарования
  const availableEnchantments = enchantments.filter(e => 
    unlockedEnchantments.includes(e.id) || e.unlocked
  )
  
  // Проверяем какие зачарования уже есть на оружии
  const existingEnchantmentIds = (weapon.enchantments || []).map((e: any) => e.enchantmentId)
  
  // Группируем по школам
  const groupedBySchool = availableEnchantments.reduce((acc, e) => {
    if (!acc[e.school]) acc[e.school] = []
    acc[e.school].push(e)
    return acc
  }, {} as Record<EnchantmentSchool, typeof enchantments>)
  
  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      exit={{ opacity: 0 }}
      className="fixed inset-0 bg-black/70 flex items-center justify-center z-50 p-4"
      onClick={onClose}
    >
      <motion.div
        initial={{ scale: 0.9, opacity: 0 }}
        animate={{ scale: 1, opacity: 1 }}
        exit={{ scale: 0.9, opacity: 0 }}
        className="bg-stone-900 border border-stone-700 rounded-xl max-w-2xl w-full max-h-[80vh] overflow-y-auto"
        onClick={e => e.stopPropagation()}
      >
        <div className="p-4 border-b border-stone-700 flex items-center justify-between">
          <div>
            <h3 className="text-lg font-semibold text-amber-200">Зачаровать оружие</h3>
            <p className="text-sm text-stone-500">{weapon.name}</p>
          </div>
          <Button variant="ghost" size="sm" onClick={onClose}>
            <X className="w-4 h-4" />
          </Button>
        </div>
        
        <div className="p-4 space-y-6">
          {/* Текущие зачарования */}
          {weapon.enchantments && weapon.enchantments.length > 0 && (
            <div>
              <h4 className="text-sm font-medium text-stone-400 mb-2">Текущие зачарования</h4>
              <div className="flex flex-wrap gap-2">
                {weapon.enchantments.map((e: any, idx: number) => {
                  const ench = getEnchantment(e.enchantmentId)
                  const school = ench ? enchantmentSchoolInfo[ench.school] : null
                  return (
                    <Badge key={e.enchantmentId || `ench-current-${idx}`} className={school?.color || 'text-stone-400'}>
                      {school?.icon} {ench?.name}
                    </Badge>
                  )
                })}
              </div>
            </div>
          )}
          
          {/* Доступные зачарования по школам */}
          {enchantmentSchools.map(school => {
            const schoolEnchantments = groupedBySchool[school.id]
            if (!schoolEnchantments || schoolEnchantments.length === 0) return null
            
            return (
              <div key={school.id}>
                <div className="flex items-center gap-2 mb-3">
                  <span className="text-xl">{school.icon}</span>
                  <h4 className={cn('font-semibold', school.color)}>{school.name}</h4>
                </div>
                
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                  {schoolEnchantments.map(ench => {
                    const isAlreadyApplied = existingEnchantmentIds.includes(ench.id)
                    const schoolAlreadyApplied = existingEnchantmentIds.some((id: string) => {
                      const existing = getEnchantment(id)
                      return existing?.school === ench.school
                    })
                    
                    // Проверяем, можно ли применить
                    const canApply = !isAlreadyApplied && !schoolAlreadyApplied
                    
                    return (
                      <div
                        key={ench.id}
                        className={cn(
                          'p-3 rounded-lg border transition-all',
                          isAlreadyApplied && 'border-green-600/30 bg-green-900/20',
                          canApply && 'border-stone-700 hover:border-amber-600/50 cursor-pointer',
                          !canApply && !isAlreadyApplied && 'border-stone-700/50 opacity-50'
                        )}
                        onClick={() => canApply && onEnchant(ench.id)}
                      >
                        <div className="flex items-center justify-between mb-1">
                          <span className={cn('font-medium', school.color)}>{ench.name}</span>
                          {isAlreadyApplied && (
                            <CheckCircle className="w-4 h-4 text-green-400" />
                          )}
                        </div>
                        <p className="text-xs text-stone-500">{ench.description}</p>
                        {schoolAlreadyApplied && !isAlreadyApplied && (
                          <p className="text-xs text-red-400 mt-1">
                            Уже есть зачарование этой школы
                          </p>
                        )}
                      </div>
                    )
                  })}
                </div>
              </div>
            )
          })}
          
          {availableEnchantments.length === 0 && (
            <div className="text-center py-8">
              <Lock className="w-12 h-12 mx-auto text-stone-600 mb-3" />
              <p className="text-stone-500">Нет разблокированных зачарований</p>
              <p className="text-stone-600 text-sm mt-1">
                Купите зачарования в магазине выше
              </p>
            </div>
          )}
        </div>
      </motion.div>
    </motion.div>
  )
}

/**
 * Enchanted Weapons Section
 * Секция зачарованного оружия
 */

'use client'

import { AnimatePresence } from 'framer-motion'
import { Sword, Plus } from 'lucide-react'
import { Card, CardHeader, CardTitle, CardDescription, CardContent } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { cn } from '@/lib/utils'
import { useGameStore } from '@/store'
import { useSound } from '@/lib/sounds'
import { useState } from 'react'
import { getEnchantment, enchantmentSchoolInfo } from '@/data/enchantments'
import { qualityGrades } from '@/data/weapon-recipes'
import { EnchantWeaponModal } from './enchant-weapon-modal'

export function EnchantedWeaponsSection() {
  const weaponInventory = useGameStore((state) => state.weaponInventory)
  const enchantWeapon = useGameStore((state) => state.enchantWeapon)
  const unlockedEnchantments = useGameStore((state) => state.unlockedEnchantments)
  const [selectedWeapon, setSelectedWeapon] = useState<any>(null)
  const { play } = useSound()
  
  // Оружие с зачарованиями или разблокированными чарами
  const enchantableWeapons = weaponInventory.weapons.filter(w => {
    const hasEnchantments = w.enchantments && w.enchantments.length > 0
    const hasUnlockedEnchantments = unlockedEnchantments.length > 0
    return hasEnchantments || hasUnlockedEnchantments
  })
  
  const handleEnchant = (enchantmentId: string) => {
    if (selectedWeapon) {
      if (enchantWeapon(selectedWeapon.id, enchantmentId)) {
        play('craft_complete')
      }
      setSelectedWeapon(null)
    }
  }
  
  return (
    <Card className="card-medieval">
      <CardHeader>
        <CardTitle className="text-amber-200 flex items-center gap-2">
          <Sword className="w-5 h-5" />
          Зачарованное оружие
        </CardTitle>
        <CardDescription>
          Наложите зачарования на своё оружие
        </CardDescription>
      </CardHeader>
      <CardContent>
        {enchantableWeapons.length === 0 ? (
          <div className="text-center py-8">
            <Sword className="w-12 h-12 mx-auto text-stone-600 mb-3" />
            <p className="text-stone-500">Нет оружия для зачарования</p>
            <p className="text-stone-600 text-sm mt-1">
              Создайте оружие и разблокируйте зачарования
            </p>
          </div>
        ) : (
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
            {enchantableWeapons.map(weapon => {
              const qualityInfo = qualityGrades[weapon.qualityGrade as keyof typeof qualityGrades] ?? qualityGrades.normal
              const enchantmentsCount = (weapon.enchantments || []).length
              
              return (
                <Card key={weapon.id} className="bg-stone-800/50 border-stone-700">
                  <CardContent className="p-4">
                    <div className="flex items-center justify-between mb-3">
                      <div>
                        <h4 className="font-semibold text-stone-200">{weapon.fullName}</h4>
                        <Badge className={qualityInfo.color}>{qualityInfo.name}</Badge>
                      </div>
                      <div className="text-right">
                        <p className="text-sm text-stone-500">Атака: {weapon.stats.attack}</p>
                      </div>
                    </div>
                    
                    {/* Зачарования */}
                    <div className="flex flex-wrap gap-1 mb-3">
                      {weapon.enchantments && weapon.enchantments.map((e: any, idx: number) => {
                        const ench = getEnchantment(e.enchantmentId)
                        const school = ench ? enchantmentSchoolInfo[ench.school] : null
                        return (
                          <Badge key={e.enchantmentId || `ench-${idx}`} className={cn('text-xs', school?.color)}>
                            {school?.icon} {ench?.name}
                          </Badge>
                        )
                      })}
                      {(!weapon.enchantments || weapon.enchantments.length < 2) && (
                        <Badge variant="outline" className="text-xs text-stone-500">
                          {enchantmentsCount}/2 зачарований
                        </Badge>
                      )}
                    </div>
                    
                    <Button
                      size="sm"
                      className="w-full bg-gradient-to-r from-purple-800 to-purple-900 hover:from-purple-700 hover:to-purple-800 text-purple-100"
                      onClick={() => setSelectedWeapon(weapon)}
                    >
                      <Plus className="w-4 h-4 mr-2" />
                      Зачаровать
                    </Button>
                  </CardContent>
                </Card>
              )
            })}
          </div>
        )}
      </CardContent>
      
      {/* Модальное окно зачарования */}
      <AnimatePresence>
        {selectedWeapon && (
          <EnchantWeaponModal
            weapon={selectedWeapon}
            onClose={() => setSelectedWeapon(null)}
            onEnchant={handleEnchant}
          />
        )}
      </AnimatePresence>
    </Card>
  )
}

