/**
 * Materials Check Component
 * Проверка наличия материалов для крафта
 */

'use client'

import React from 'react'
import { Package, Info, ShoppingBag } from 'lucide-react'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { Badge } from '@/components/ui/badge'
import { Button } from '@/components/ui/button'
import { cn } from '@/lib/utils'
import type { Resources } from '@/store/slices/resources-slice'
import type { WeaponRecipe } from '@/types/craft-v2'
import { 
  checkInventoryForCraft, 
  type MaterialToBuy,
} from '@/lib/craft/inventory-check'

interface MaterialsCheckProps {
  inventory: Resources
  selectedMaterials: Record<string, string>
  recipe: WeaponRecipe | null
  gold: number
  onBuyMaterials?: (materials: MaterialToBuy[], totalCost: number) => void
  shouldPurchaseMaterials?: boolean // Включена ли галочка закупки
  onTogglePurchaseMaterials?: (checked: boolean) => void // Обработчик изменения галочки
  activeOrderId?: string | null // ID активного заказа
  activeOrder?: {
    goldReward: number
    advanceTaken?: number
  } | null // Данные активного заказа для расчёта аванса
  shouldTakeAdvance?: boolean // Включена ли галочка аванса
  onToggleTakeAdvance?: (checked: boolean) => void // Обработчик изменения галочки аванса
}

export function MaterialsCheck({
  inventory,
  selectedMaterials,
  recipe,
  gold,
  onBuyMaterials,
  shouldPurchaseMaterials = false,
  onTogglePurchaseMaterials,
  activeOrderId = null,
  activeOrder = null,
  shouldTakeAdvance = false,
  onToggleTakeAdvance,
}: MaterialsCheckProps) {
  if (!recipe) return null
  
  // Преобразуем выбранные материалы в формат для проверки
  const materialAssignment: Record<string, { materialId: string; quantity: number }> = {}
  recipe.parts.forEach(part => {
    const materialId = selectedMaterials[part.id]
    if (materialId) {
      materialAssignment[part.id] = {
        materialId,
        quantity: part.minQuantity,
      }
    }
  })
  
  // Используем систему проверки
  const checkResult = checkInventoryForCraft(recipe, materialAssignment, inventory)
  
  if (checkResult.requirements.length === 0) return null
  
  const canAffordPurchase = gold >= checkResult.totalPurchaseCost
  
  return (
    <Card className={cn(
      "bg-stone-900/50 border-stone-700",
      !checkResult.canCraft && "border-red-500/50"
    )}>
      <CardHeader className="pb-2">
        <CardTitle className="text-base flex items-center gap-2">
          <Package className={cn(
            "w-4 h-4",
            checkResult.canCraft ? "text-green-400" : "text-red-400"
          )} />
          Материалы
          {!checkResult.canCraft && (
            <Badge variant="destructive" className="ml-auto">
              Не хватает
            </Badge>
          )}
        </CardTitle>
      </CardHeader>
      <CardContent className="space-y-3">
        {/* Общая потребность в сырье */}
        <div className="space-y-1">
          <p className="text-xs text-stone-500 uppercase tracking-wide">Требуется сырья:</p>
          {checkResult.requirements.map(req => (
            <div key={req.resourceKey} className="flex items-center justify-between text-sm">
              <span className="text-stone-400">{req.resourceName}</span>
              <span className={cn(
                "font-mono",
                req.sufficient ? "text-green-400" : "text-red-400"
              )}>
                {req.available}/{req.quantity}
                {!req.sufficient && ' ❌'}
              </span>
            </div>
          ))}
        </div>
        
        {/* Топливо */}
        {checkResult.fuelRequired && (
          <div className="flex items-center justify-between text-sm pt-2 border-t border-stone-700">
            <span className="text-stone-400">Уголь (топливо)</span>
            <span className={cn(
              "font-mono",
              checkResult.fuelRequired.sufficient ? "text-green-400" : "text-red-400"
            )}>
              {checkResult.fuelRequired.available}/{checkResult.fuelRequired.quantity}
              {!checkResult.fuelRequired.sufficient && ' ❌'}
            </span>
          </div>
        )}
        
        {/* Детализация по частям */}
        <details className="text-sm">
          <summary className="cursor-pointer text-stone-500 hover:text-stone-400 flex items-center gap-1">
            <Info className="w-3 h-3" />
            Детализация по частям
          </summary>
          <div className="mt-2 pl-4 space-y-2 border-l-2 border-stone-700">
            {checkResult.breakdownByPart.map(part => (
              <div key={part.partId}>
                <p className="text-stone-300 font-medium">
                  {part.partName}: <span className="text-amber-400">{part.materialName}</span>
                </p>
                {part.requirements.map((req, i) => (
                  <p key={i} className="text-xs text-stone-500 pl-2">
                    → {req.resourceName}: {req.quantity} ед.
                  </p>
                ))}
              </div>
            ))}
          </div>
        </details>
        
        {/* Галочка и информация о закупке */}
        {!checkResult.canCraft && checkResult.canPurchaseMissing && onTogglePurchaseMaterials && (
          <div className="pt-3 border-t border-stone-700 space-y-2">
            <label className="flex items-center gap-3 cursor-pointer">
              <input
                type="checkbox"
                checked={shouldPurchaseMaterials}
                onChange={(e) => onTogglePurchaseMaterials(e.target.checked)}
                className="w-5 h-5 rounded border-stone-600 bg-stone-800 text-amber-500 focus:ring-amber-500 focus:ring-offset-0"
              />
              <div className="flex-1">
                <p className="text-sm font-medium text-stone-200">
                  Закупить недостающие материалы
                </p>
                <p className="text-xs text-stone-500">
                  {!canAffordPurchase ? (
                    <span className="text-red-400">
                      ⚠️ Недостаточно золота (нужно {checkResult.totalPurchaseCost}, есть {gold})
                    </span>
                  ) : (
                    <span className="text-amber-400">
                      💰 Стоимость: {checkResult.totalPurchaseCost}
                    </span>
                  )}
                </p>
              </div>
            </label>
            {shouldPurchaseMaterials && (
              <div className="bg-amber-900/20 border border-amber-600/30 rounded-lg p-3">
                <p className="text-xs text-stone-400 mb-2">К покупке:</p>
                {checkResult.materialsToBuy.map(mat => (
                  <div key={mat.resourceKey} className="flex justify-between text-sm">
                    <span className="text-stone-300">{mat.resourceName} ×{mat.quantity}</span>
                    <span className="text-amber-400 font-mono">{mat.totalPrice} 💰</span>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}

        {/* Галочка аванса на закупку материалов */}
        {!checkResult.canCraft &&
         checkResult.canPurchaseMissing &&
         activeOrderId &&
         activeOrder &&
         gold < checkResult.totalPurchaseCost &&
         checkResult.materialsToBuy.every(m => m.canBuy) &&
         onToggleTakeAdvance && (
          <div className="pt-3 border-t border-stone-700">
            <label className="flex items-center gap-3 cursor-pointer">
              <input
                type="checkbox"
                checked={shouldTakeAdvance}
                onChange={(e) => onToggleTakeAdvance(e.target.checked)}
                className="w-5 h-5 rounded border-stone-600 bg-stone-800 text-blue-500 focus:ring-blue-500 focus:ring-offset-0"
              />
              <div className="flex-1">
                <p className="text-sm font-medium text-stone-200">
                  💰 Взять аванс на закупку материалов
                </p>
                <p className="text-xs text-stone-500">
                  {(() => {
                    const maxAdvance = Math.min(
                      Math.floor(activeOrder.goldReward * 0.5),
                      checkResult.totalPurchaseCost
                    )
                    const alreadyTaken = activeOrder.advanceTaken || 0
                    const availableAdvance = Math.max(0, maxAdvance - alreadyTaken)

                    if (availableAdvance <= 0) {
                      return <span className="text-red-400">⚠️ Аванс уже взят</span>
                    }

                    return (
                      <span className="text-blue-400">
                        Доступно: {availableAdvance} (50% от награды)
                      </span>
                    )
                  })()}
                </p>
              </div>
            </label>
          </div>
        )}
      </CardContent>
    </Card>
  )
}

/**
 * Part Material Selector Component
 * Селектор материала для части оружия
 * Обновлён: умная сортировка, инвентарь, цены, тултип с дельтой
 */

'use client'

import React, { useState, useMemo } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { ChevronDown, ChevronUp, Coins } from 'lucide-react'
import { Badge } from '@/components/ui/badge'
import { cn } from '@/lib/utils'
import { allMaterials } from '@/data/materials'
import { getMaterialsForPart } from '@/data/materials'
import type { MaterialNode } from '@/types/materials'
import type { WeaponRecipe } from '@/types/craft-v2'
import type { Resources } from '@/store/slices/resources-slice'
import type { MaterialKnowledge } from '@/types/materials/knowledge'
import { 
  filterDiscoveredMaterials, 
  smartSortMaterials,
  isMaterialAvailable,
  getMaterialQuantity,
} from '@/lib/craft/material-sorting'
import { 
  calculateMaterialComparison, 
  type MaterialComparison 
} from '@/lib/craft/material-preview'
import { MaterialPreviewTooltip } from './MaterialPreviewTooltip'
import { 
  getMaterialRarity, 
  RARITY_COLORS,
  RARITY_LABELS,
} from '@/types/materials/material-core'
import { 
  getResourceKeyForMaterial, 
} from '@/lib/craft/inventory-check'
import { getMaterialPrice } from '@/data/material-shop'
import type { ResourceKey } from '@/store/slices/resources-slice'

// ================================
// TIPES
// ================================

interface PartMaterialSelectorProps {
  partId: string
  partName: string
  allowedCategories: string[]
  selectedMaterial: string | null
  onSelect: (materialId: string) => void

  // Новые props:
  inventory: Resources
  playerLevel: number
  recipe: WeaponRecipe
  knowledge: Record<string, MaterialKnowledge>
  materialPrices?: Record<string, number>  // цены покупки
  currentMaterials?: Record<string, string>  // выбранные материалы для других частей
}

const categoryIcons: Record<string, string> = {
  metal: '⚒️',
  mineral: '🪨',
  wood: '🪵',
  leather: '🟤',
}

// Получить название свойства по ключу
const getPropertyLabel = (prop: string | undefined): string => {
  if (!prop) return 'Твёрдость'
  const labels: Record<string, string> = {
    hardness: 'Твёрдость',
    elasticity: 'Гибкость',
    toughness: 'Прочность',
    weight: 'Вес',
    conductivity: 'Магия'
  }
  return labels[prop] || prop
}

// Получить значение свойства материала
const getPropertyValue = (material: MaterialNode, prop: string | undefined): number => {
  if (!prop) return material.physical.hardness
  const paths: Record<string, number> = {
    hardness: material.physical.hardness,
    elasticity: material.physical.elasticity,
    toughness: material.physical.toughness,
    weight: material.physical.density,  // Используем density вместо weight
    conductivity: material.arcane.conductivity
  }
  return paths[prop] ?? 0
}

// ================================
// MAIN COMPONENT
// ================================

export function PartMaterialSelector({
  partId,
  partName,
  allowedCategories,
  selectedMaterial,
  onSelect,
  inventory,
  playerLevel,
  recipe,
  knowledge,
  materialPrices,
  currentMaterials = {},
}: PartMaterialSelectorProps) {
  const [expanded, setExpanded] = useState(false)

  // Получаем свойства для этой части из рецепта
  const recipePart = recipe.parts.find(p => p.id === partId)
  const dominantProperty = recipePart?.dominantProperty
  const secondaryProperty = recipePart?.secondaryProperty

  // Фильтруем и сортируем материалы
  const materials = useMemo(() => {
    const allFiltered = getMaterialsForPart(partId, allowedCategories)

    // Фильтр по открытым в энциклопедии
    const discovered = filterDiscoveredMaterials(allFiltered, knowledge)

    // Умная сортировка
    return smartSortMaterials(discovered, {
      inventory,
      knowledge,
      recipe,
      partId,
      blacksmithLevel: playerLevel,
      dominantProperty,
    })
  }, [partId, allowedCategories, inventory, knowledge, recipe, playerLevel, dominantProperty])

  // Текущий выбранный материал
  const selected = useMemo(() => {
    return selectedMaterial 
      ? allMaterials.find((m: MaterialNode) => m.identity.id === selectedMaterial) 
      : null
  }, [selectedMaterial])

  return (
    <div className="border border-stone-700 rounded-lg overflow-hidden">
      <button
        onClick={() => setExpanded(!expanded)}
        className="w-full p-3 flex items-center justify-between bg-stone-800/50 hover:bg-stone-800 transition-colors"
      >
        <div className="flex items-center gap-3">
          <span className="text-lg">
            {selected ? categoryIcons[selected.identity.class] : '❓'}
          </span>
          <div className="text-left">
            <p className="font-medium text-stone-200">{partName}</p>
            <p className="text-xs text-stone-500">
              {selected ? selected.identity.name : 'Выберите материал'}
            </p>
          </div>
        </div>
        {expanded ? (
          <ChevronUp className="w-4 h-4 text-stone-400" />
        ) : (
          <ChevronDown className="w-4 h-4 text-stone-400" />
        )}
      </button>

      <AnimatePresence>
        {expanded && (
          <motion.div
            initial={{ height: 0, opacity: 0 }}
            animate={{ height: 'auto', opacity: 1 }}
            exit={{ height: 0, opacity: 0 }}
            className="overflow-hidden"
          >
            <div className="p-2 grid grid-cols-2 gap-2 bg-stone-900/50">
              {materials.map((material: MaterialNode) => {
                const isSelected = selectedMaterial === material.identity.id
                const isAvailable = isMaterialAvailable(material, inventory)
                const quantity = getMaterialQuantity(material, inventory)
                const resourceKey = getResourceKeyForMaterial(material.identity.id)
                // Используем переданные цены или вычисляем
                const price = materialPrices?.[material.identity.id] || 
                  (resourceKey ? getMaterialPrice(resourceKey, 1, 1.1) : 0)

                const rarity = getMaterialRarity(material.economy)

                // Получаем количество материала по рецепту для этой части
                const recipePart = recipe.parts.find(p => p.id === partId)
                const requiredQuantity = recipePart?.minQuantity || 1

                // Рассчитываем превью для тултипа
                const comparison = calculateMaterialComparison(
                  material,
                  selectedMaterial,
                  recipe,
                  partId,
                  playerLevel,
                  knowledge[material.identity.id]?.expertise || 0,
                  selectedMaterial != null ? knowledge[selectedMaterial]?.expertise : undefined
                )

                // Получаем экспертизу и знания для материала
                const materialExpertise = knowledge[material.identity.id]?.expertise || 0
                const materialKnowledge = knowledge[material.identity.id]

                return (
                  <MaterialPreviewTooltip
                    key={material.identity.id}
                    material={material}
                    comparison={comparison}
                    requiredQuantity={requiredQuantity}
                    inventoryQuantity={isAvailable ? quantity : undefined}
                    price={!isAvailable && price > 0 ? price : undefined}
                    expertise={materialExpertise}
                    knowledge={materialKnowledge}
                  >
                    <button
                      onClick={() => {
                        onSelect(material.identity.id)
                        // НЕ закрываем шторку - пусть пользователь сам закроет
                      }}
                      className={cn(
                        "p-2 rounded text-left transition-colors relative",
                        isSelected
                          ? "bg-amber-600/30 border border-amber-500"
                          : isAvailable
                            ? "bg-stone-800 border border-stone-700 hover:border-stone-600"
                            : "bg-stone-900/30 border border-stone-800 opacity-50"
                      )}
                    >
                      <div className="flex items-start justify-between gap-2">
                        <div className="flex items-center gap-2 min-w-0 flex-1">
                          <span>{categoryIcons[material.identity.class]}</span>
                          <div className="min-w-0">
                            <p className={cn(
                              "text-sm font-medium truncate",
                              isSelected ? "text-amber-200" : isAvailable ? "text-stone-200" : "text-stone-400"
                            )}>
                              {material.identity.name}
                            </p>
                            <div className="flex items-center gap-2 mt-0.5 flex-wrap">
                              <Badge 
                                variant="outline" 
                                className={cn(
                                  "text-xs px-1 py-0 h-auto",
                                  RARITY_COLORS[rarity]
                                )}
                              >
                                {RARITY_LABELS[rarity]}
                              </Badge>
                              {/* Первая характеристика */}
                              <p className="text-xs text-stone-500">
                                {getPropertyLabel(dominantProperty)}: {getPropertyValue(material, dominantProperty)}
                              </p>
                              {/* Вторая характеристика (если есть) */}
                              {secondaryProperty && (
                                <p className="text-xs text-stone-500">
                                  {getPropertyLabel(secondaryProperty)}: {getPropertyValue(material, secondaryProperty)}
                                </p>
                              )}
                            </div>
                          </div>
                        </div>

                        {/* Badge количества для крафта */}
                        <div className="shrink-0">
                          <Badge variant="outline" className="bg-amber-900/20 border-amber-700 text-amber-400 text-xs px-1.5 py-0.5 cursor-help">
                            {requiredQuantity}
                          </Badge>
                        </div>
                      </div>
                    </button>
                  </MaterialPreviewTooltip>
                )
              })}
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  )
}

export default PartMaterialSelector

