    bgBarColor: 'bg-stone-900/20',
    borderColor: 'border-stone-700/30',
    gradient: 'from-stone-500/60 to-stone-400/40'
  },
  soulCapacity: {
    iconColor: 'text-purple-400',
    barColor: 'bg-purple-500',
    bgBarColor: 'bg-purple-900/20',
    borderColor: 'border-purple-900/30',
    gradient: 'from-purple-500/60 to-purple-400/40'
  }
} as const

const STAT_LABELS = {
  attack: 'Атака',
  durability: 'Прочность',
  weight: 'Вес',
  soulCapacity: 'Душа Войны'
} as const

export function StatRow({ stat, range, icon, label }: StatRowProps) {
  const config = STAT_CONFIG[stat]

  // Вычисляем позицию диапазона на баре (нормализованная 0-100)
  // Используем разумные максимумы для нормализации
  const MAX_VALUES = {
    attack: 150,
    durability: 300,
    weight: 20,
    soulCapacity: 50
  }
  const maxValue = MAX_VALUES[stat] || 100
  const normalizedMin = Math.max(0, Math.min(100, (range.min / maxValue) * 100))
  const normalizedMax = Math.max(0, Math.min(100, (range.max / maxValue) * 100))
  const rangeWidth = normalizedMax - normalizedMin

  const precision = stat === 'weight' ? 1 : 0

  const formatValue = (val: number): string => {
    return precision > 0 ? val.toFixed(precision) : val.toString()
  }

  return (
    <div className="px-3 py-2 rounded-lg border border-stone-700 transition-all duration-200">
      {/* Иконка и название */}
      <div className="flex items-center gap-3 mb-1.5">
        <span className={cn('w-5 h-5', config.iconColor)}>
          {icon}
        </span>
        <span className="text-sm font-medium text-stone-200">
          {label}
        </span>

        {/* Значения */}
        <span className="ml-auto text-sm font-bold text-stone-100">
          {formatValue(range.min)} - {formatValue(range.max)}
        </span>
      </div>

      {/* Визуальный бар */}
      <div className="relative h-2 bg-stone-800 rounded-full overflow-hidden">
        {/* Минимальное значение */}
        <motion.div
          className="absolute top-0 bottom-0 bg-gradient-to-r from-stone-700 to-stone-600 rounded-l-full"
          style={{ width: `${normalizedMin}%` }}
          initial={{ width: 0 }}
          animate={{ width: `${normalizedMin}%` }}
          transition={{ duration: 0.4, ease: 'easeOut' }}
        />

        {/* Диапазон */}
        <motion.div
          className={cn(
            'absolute top-0 bottom-0 rounded-full',
            'bg-gradient-to-r',
            config.gradient
          )}
          style={{
            left: `${normalizedMin}%`,
            width: `${rangeWidth}%`
          }}
          initial={{
            left: `${normalizedMin}%`,
            width: 0
          }}
          animate={{
            left: `${normalizedMin}%`,
            width: `${rangeWidth}%`
          }}
          transition={{ duration: 0.4, ease: 'easeOut' }}
        />

        {/* Пульсирующая граница справа */}
        {rangeWidth > 0 && (
          <motion.div
            className="absolute top-0 bottom-0 right-0 w-0.5 bg-white/30"
            animate={{
              opacity: [0.3, 0.7, 0.3]
            }}
            transition={{
              duration: 2,
              repeat: Infinity,
              ease: 'easeInOut'
            }}
          />
        )}
      </div>

      {/* Индикатор неопределённости */}
      {range.variance > 0.2 && (
        <div className="mt-2 flex items-center gap-1.5">
          <motion.div
            className={cn('w-1.5 h-1.5 rounded-full', config.barColor)}
            animate={{
              scale: [0.8, 1.2, 0.8],
              opacity: [0.5, 1, 0.5]
            }}
            transition={{
              duration: 1.5,
              repeat: Infinity,
              ease: 'easeInOut'
            }}
          />
          <span className="text-xs text-stone-500">
            Низкая точность
          </span>
        </div>
      )}
    </div>
  )
}

/**
 * InventorySection - секция инвентаря оружия
 */

'use client'

import { motion, AnimatePresence } from 'framer-motion'
import { Package, Coins, Star, Sword, Filter, SortAsc } from 'lucide-react'
import { useState, useMemo } from 'react'
import { Card, CardContent } from '@/components/ui/card'
import { Badge } from '@/components/ui/badge'
import { Button } from '@/components/ui/button'
import { useGameStore } from '@/store'
import { cn } from '@/lib/utils'
import { WeaponInventoryCard } from './weapon-inventory-card'

export function InventorySection() {
  const weapons = useGameStore((state) => state.weaponInventory.weapons)
  const [sortBy, setSortBy] = useState<'date' | 'price' | 'quality'>('date')
  const [filterQuality, setFilterQuality] = useState<string>('all')
  
  // Мемоизированная сортировка оружия
  const sortedWeapons = useMemo(() => {
    return [...weapons].sort((a, b) => {
      if (sortBy === 'date') return b.createdAt - a.createdAt
      if (sortBy === 'price') return b.sellPrice - a.sellPrice
      if (sortBy === 'quality') return b.quality - a.quality
      return 0
    })
  }, [weapons, sortBy])
  
  // Мемоизированная фильтрация по качеству
  const filteredWeapons = useMemo(() => {
    return filterQuality === 'all' 
      ? sortedWeapons 
      : sortedWeapons.filter(w => w.qualityGrade === filterQuality)
  }, [sortedWeapons, filterQuality])
  
  // Мемоизированная статистика
  const stats = useMemo(() => {
    const totalValue = weapons.reduce((sum, w) => sum + w.sellPrice, 0)
    const avgAttack = weapons.length > 0
      ? Math.round(weapons.reduce((sum, w) => sum + w.stats.attack, 0) / weapons.length)
      : 0
    const masterpieceCount = weapons.filter(
      w => w.qualityGrade === 'masterpiece' || w.qualityGrade === 'legendary'
    ).length
    
    return { totalValue, avgAttack, masterpieceCount, count: weapons.length }
  }, [weapons])
  
  return (
    <div className="space-y-4">
      {/* Статистика инвентаря */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
        <Card className="card-medieval bg-stone-800/50">
          <CardContent className="p-3 text-center">
            <Package className="w-5 h-5 mx-auto text-stone-500 mb-1" />
            <p className="text-xl font-bold text-stone-200">{stats.count}</p>
            <p className="text-xs text-stone-500">Предметов</p>
          </CardContent>
        </Card>
        <Card className="card-medieval bg-stone-800/50">
          <CardContent className="p-3 text-center">
            <Coins className="w-5 h-5 mx-auto text-amber-500 mb-1" />
            <p className="text-xl font-bold text-amber-400">{stats.totalValue}</p>
            <p className="text-xs text-stone-500">Общая стоимость</p>
          </CardContent>
        </Card>
        <Card className="card-medieval bg-stone-800/50">
          <CardContent className="p-3 text-center">
            <Star className="w-5 h-5 mx-auto text-purple-500 mb-1" />
            <p className="text-xl font-bold text-stone-200">{stats.masterpieceCount}</p>
            <p className="text-xs text-stone-500">Шедевров+</p>
          </CardContent>
        </Card>
        <Card className="card-medieval bg-stone-800/50">
          <CardContent className="p-3 text-center">
            <Sword className="w-5 h-5 mx-auto text-red-500 mb-1" />
            <p className="text-xl font-bold text-stone-200">{stats.avgAttack}</p>
            <p className="text-xs text-stone-500">Сред. атака</p>
          </CardContent>
        </Card>
      </div>
      
      {/* Фильтры и сортировка */}
      <div className="flex flex-wrap items-center gap-2">
        <div className="flex items-center gap-1 text-xs text-stone-500">
          <Filter className="w-3 h-3" />
          <span>Фильтр:</span>
        </div>
        {[
          { id: 'all', label: 'Все' },
          { id: 'legendary', label: 'Легенда', color: 'text-amber-400' },
          { id: 'masterpiece', label: 'Шедевр', color: 'text-purple-400' },
          { id: 'excellent', label: 'Отличное', color: 'text-blue-400' },
          { id: 'good', label: 'Хорошее', color: 'text-green-400' },
        ].map((f) => (
          <Button
            key={f.id}
            variant={filterQuality === f.id ? 'default' : 'outline'}
            size="sm"
            className={cn(
              'h-7 text-xs',
              filterQuality === f.id 
                ? 'bg-amber-800 text-amber-100' 
                : 'border-stone-600 text-stone-400'
            )}
            onClick={() => setFilterQuality(f.id)}
          >
            {f.label}
          </Button>
        ))}
        
        <div className="ml-auto flex items-center gap-1">
          <SortAsc className="w-3 h-3 text-stone-500" />
          <select 
            value={sortBy}
            onChange={(e) => setSortBy(e.target.value as 'date' | 'price' | 'quality')}
            className="bg-stone-800 border border-stone-600 rounded px-2 py-1 text-xs text-stone-300"
          >
            <option value="date">По дате</option>
            <option value="price">По цене</option>
            <option value="quality">По качеству</option>
          </select>
        </div>
      </div>
      
      {/* Список оружия */}
      {filteredWeapons.length === 0 ? (
        <Card className="card-medieval">
          <CardContent className="p-8 text-center">
            <Package className="w-12 h-12 mx-auto text-stone-600 mb-3" />
            <p className="text-stone-500 mb-1">Инвентарь пуст</p>
            <p className="text-stone-600 text-sm">
              {stats.count > 0 
                ? 'Нет предметов с выбранным фильтром' 
                : 'Создайте оружие на вкладке "Крафт"'}
            </p>
          </CardContent>
        </Card>
      ) : (
        <AnimatePresence mode="popLayout">
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-3">
            {filteredWeapons.map((weapon) => (
              <WeaponInventoryCard key={weapon.id} weapon={weapon} />
            ))}
          </div>
        </AnimatePresence>
      )}
    </div>
  )
}

/**
