  // Тир Души Войны
  const warSoulTier = weapon.warSoul > 0 || (weapon.maxWarSoul ?? 0) > 0 
    ? getWarSoulTier(weapon.warSoul, weapon.maxWarSoul ?? 100)
    : null
  
  const warSoulProgress = warSoulTier 
    ? getProgressToNextTier(weapon.warSoul, weapon.maxWarSoul ?? 100)
