// Простой компонент для tooltip с children
function InfoTooltip({
  title,
  content,
  side = 'top',
  children
}: {
  title?: string
  content: React.ReactNode
  side?: 'top' | 'right' | 'bottom' | 'left'
  children: React.ReactNode
}) {
  return (
    <Tooltip delayDuration={200}>
      <TooltipTrigger asChild>
        <div className="cursor-help">
          {children}
        </div>
      </TooltipTrigger>
      <TooltipContent side={side} className="max-w-sm z-50">
        {title && (
          <p className="font-semibold text-amber-400 mb-1">{title}</p>
        )}
        <div className="text-stone-300 text-xs leading-relaxed">
          {content}
        </div>
      </TooltipContent>
    </Tooltip>
  )
}

// Карточка искателя
function AdventurerCardItem({
  adventurer,
  isSelected,
  canSelect,
  onSelect
}: {
  adventurer: Adventurer
  isSelected: boolean
  canSelect: boolean
  onSelect: () => void
}) {
  const fullName = getAdventurerFullName(adventurer)
  const minAttack = adventurer.requirements?.minAttack ?? 0

  return (
    <motion.div
      initial={{ opacity: 0, scale: 0.95 }}
      animate={{ opacity: 1, scale: 1 }}
      exit={{ opacity: 0, scale: 0.95 }}
    >
      <Card
        className={cn(
          "card-medieval cursor-pointer transition-all",
          isSelected && "border-amber-500 bg-amber-900/20",
          !canSelect && "opacity-50"
        )}
        onClick={canSelect ? onSelect : undefined}
      >
        <CardContent className="p-3">
          <div className="flex items-center gap-3">
            <div className="w-12 h-12 rounded-xl bg-gradient-to-br from-stone-700 to-stone-800 flex items-center justify-center text-2xl">
              👤
            </div>
            <div className="flex-1 min-w-0">
              <h4 className="font-semibold text-stone-200 text-sm truncate">{fullName}</h4>
              <div className="flex items-center gap-2 mt-1">
                <Badge className="text-xs bg-purple-900/50 text-purple-300">
                  +{adventurer.skill}% души
                </Badge>
                {adventurer.traits && adventurer.traits.length > 0 && (
                  <Badge className="text-xs bg-amber-900/50 text-amber-300">
                    {adventurer.traits.length} черт
                  </Badge>
                )}
              </div>
              <p className="text-xs text-stone-500 mt-1">
                Требует атаку: {minAttack}+
              </p>
            </div>
            {isSelected && (
              <CheckCircle className="w-5 h-5 text-amber-400" />
            )}
          </div>
        </CardContent>
      </Card>
    </motion.div>
  )
}

// ExpeditionCard теперь импортируется как ExpeditionSelectionCard

// WeaponCard теперь импортируется как WeaponSelectionCard

export function ExpeditionsSection() {
  const guild = useGameStore((state) => state.guild)
  const resources = useGameStore((state) => state.resources)
  const player = useGameStore((state) => state.player)
  const weaponInventory = useGameStore((state) => state.weaponInventory)
  const initializeAdventurers = useGameStore((state) => state.initializeAdventurers)
  const refreshAdventurers = useGameStore((state) => state.refreshAdventurers)
  const startExpeditionFull = useGameStore((state) => state.startExpeditionFull)
  const addResource = useGameStore((state) => state.addResource)

  const [selectedExpedition, setSelectedExpedition] = useState<ExpeditionTemplate | null>(null)
  const [selectedWeapon, setSelectedWeapon] = useState<CraftedWeaponV2 | null>(null)
  const [selectedAdventurer, setSelectedAdventurer] = useState<Adventurer | null>(null)
  const [timeUntilRefresh, setTimeUntilRefresh] = useState<number>(0)

  // Расширенный искатель (из RecruitmentInterface)
  const [selectedExtendedAdventurer, setSelectedExtendedAdventurer] = useState<AdventurerExtended | null>(null)

  // Статус черновика для UI
  const [draftStatus, setDraftStatus] = useState<DraftStatus | null>(null)

  // Случайные экспедиции
  const [currentExpeditions, setCurrentExpeditions] = useState<ExpeditionTemplate[]>([])

  // Контрактные искатели из расширенного состояния гильдии
  const contractedAdventurers = (guild as any).contractedAdventurers || []

  // Подсчёт миссий для каждого искателя из истории
  const getAdventurerStats = (adventurerId: string) => {
    // Ищем в истории по имени (т.к. ID могут отличаться)
    const entries = guild.history.filter(e => 
      e.adventurerData?.id === adventurerId || 
      e.adventurerName === (guild.history.find(h => h.adventurerData?.id === adventurerId)?.adventurerName)
    )
    const missionCount = entries.length
    const successCount = entries.filter(e => e.success).length
    const successRate = missionCount > 0 ? Math.round((successCount / missionCount) * 100) : 0
    return { missionCount, successRate }
  }

  // Проверка, есть ли уже контракт с этим искателем
  const isAlreadyContracted = (adventurerId: string) => {
    return contractedAdventurers.some((c: ContractedAdventurer) => c.adventurerId === adventurerId)
  }

  // Обработка предложения контракта
  const handleOfferContract = (adventurer: Adventurer, tier: ContractTier) => {
    // Эта функция должна вызывать action из store
    // Пока что просто выводим в консоль
    console.log('Offer contract:', { adventurer: adventurer.name, tier })
    // В реальной реализации здесь будет вызов store action
  }

  // Получение случайных экспедиций
  const getRandomExpeditions = (count: number = 3): ExpeditionTemplate[] => {
    const available = expeditionTemplates.filter(e => e.minGuildLevel <= guild.level)
    const shuffled = [...available].sort(() => Math.random() - 0.5)
    return shuffled.slice(0, Math.min(count, shuffled.length))
  }

  // Инициализация случайных экспедиций
  useEffect(() => {
    if (currentExpeditions.length === 0) {
      setCurrentExpeditions(getRandomExpeditions(3))
    }
  }, [guild.level])

  // Восстановление черновика при загрузке
  useEffect(() => {
    const draft = loadDraft()
    if (draft && !draft.isExpired) {
      // Пытаемся найти и восстановить выбор
      if (draft.expeditionId) {
        const expedition = currentExpeditions.find(e => e.id === draft.expeditionId)
        if (expedition) setSelectedExpedition(expedition)
      }
      if (draft.weaponId) {
        const weapon = weaponInventory.weapons.find(w => w.id === draft.weaponId)
        if (weapon) setSelectedWeapon(weapon)
      }
      // Искателя восстанавливаем через RecruitmentInterface
    }
    setDraftStatus(getDraftStatus())
  }, [currentExpeditions, weaponInventory.weapons])

  // Автосохранение при изменении выбора
  useEffect(() => {
    debouncedSaveDraft(selectedExpedition, selectedExtendedAdventurer, selectedWeapon)
    setDraftStatus(getDraftStatus())
  }, [selectedExpedition, selectedWeapon, selectedExtendedAdventurer])

  // Стоимость обновления экспедиций
  const refreshCost = 10 * player.level

  // Обновление списка экспедиций
  const refreshExpeditions = () => {
    if (resources.gold >= refreshCost) {
      addResource('gold', -refreshCost)
      setCurrentExpeditions(getRandomExpeditions(3))
      setSelectedExpedition(null)
      setSelectedWeapon(null)
      setSelectedAdventurer(null)
      setSelectedExtendedAdventurer(null)
      clearDraft()
      setDraftStatus(null)
    }
  }

  // Инициализация искателей
  useEffect(() => {
    initializeAdventurers()
  }, [initializeAdventurers])

  // Таймер до обновления искателей
  useEffect(() => {
    const updateTime = () => {
      const remaining = Math.max(0, guild.adventurerRefreshAt - Date.now())
      setTimeUntilRefresh(remaining)
    }

    updateTime()
    const interval = setInterval(updateTime, 1000)
    return () => clearInterval(interval)
  }, [guild.adventurerRefreshAt])

  const formatTime = (ms: number) => {
    const minutes = Math.floor(ms / 60000)
    const seconds = Math.floor((ms % 60000) / 1000)
    return `${minutes}:${seconds.toString().padStart(2, '0')}`
  }

  const canRefresh = timeUntilRefresh === 0

  // Проверка возможности выбрать экспедицию
  const canSelectExpedition = (expedition: ExpeditionTemplate): { can: boolean; reason: string } => {
    const totalCost = expedition.cost.supplies + expedition.cost.deposit
    if (resources.gold < totalCost) {
      return { can: false, reason: `Нужно ${totalCost} золота` }
    }
    return { can: true, reason: '' }
  }

  // Проверка возможности выбрать оружие (v2 - CraftedWeaponV2)
  const canSelectWeapon = (weapon: CraftedWeaponV2): { can: boolean; reason: string } => {
    if (!selectedExpedition) {
      return { can: false, reason: 'Сначала выберите экспедицию' }
    }
    if (weapon.currentDurability <= 10) {
      return { can: false, reason: 'Оружие слишком повреждено' }
    }
    if (weapon.stats.attack < selectedExpedition.minWeaponAttack) {
      return { can: false, reason: `Требуется атака ${selectedExpedition.minWeaponAttack}+` }
    }
    return { can: true, reason: '' }
  }

  // Проверка возможности выбрать искателя (v2)
  const canSelectAdventurer = (adventurer: Adventurer): { can: boolean; reason: string } => {
    if (!selectedWeapon) {
      return { can: false, reason: 'Сначала выберите оружие' }
    }
    const minAttack = adventurer.requirements?.minAttack ?? 0
    if (selectedWeapon.stats.attack < minAttack) {
      return { can: false, reason: `Искатель требует атаку ${minAttack}+` }
    }
    return { can: true, reason: '' }
  }

  // Проверка возможности начать экспедицию
  const canStartExpedition = (): { can: boolean; reason: string } => {
    if (!selectedExpedition) return { can: false, reason: 'Выберите экспедицию' }
    if (!selectedWeapon) return { can: false, reason: 'Выберите оружие' }
    if (!selectedAdventurer) return { can: false, reason: 'Выберите искателя' }
    return { can: true, reason: '' }
  }

  // Доступное оружие (фильтруем по прочности, использованию в экспедиции и требованиям атаки)
  const availableWeapons = weaponInventory.weapons.filter(w => {
    // Базовые проверки (v2)
    if (w.currentDurability <= 10) return false
    if (guild.activeExpeditions.some(e => e.weaponId === w.id)) return false

    // Если выбрана экспедиция, проверяем требования к атаке
    if (selectedExpedition && w.stats.attack < selectedExpedition.minWeaponAttack) {
      return false
    }

    return true
  })

  // Доступные искатели
  const availableAdventurers = guild.adventurers.filter(a =>
    !guild.activeExpeditions.some(e => e.adventurerId === a.id)
  )

  // Запуск экспедиции (v2 - используем startExpeditionFull)
  const handleStartExpedition = () => {
    if (!selectedExpedition || !selectedWeapon || !selectedAdventurer) return

    const success = startExpeditionFull(
      selectedExpedition,
      selectedAdventurer,
      selectedWeapon,
      selectedExtendedAdventurer || undefined // Передаём Extended данные
    )
    if (success) {
      // Очищаем черновик при успешной отправке
      clearDraft()
      setDraftStatus(null)

      setSelectedExpedition(null)
      setSelectedWeapon(null)
      setSelectedAdventurer(null)
      setSelectedExtendedAdventurer(null)
    }
  }

  // Обработка выбора расширенного искателя
  const handleExtendedAdventurerSelect = (extended: AdventurerExtended) => {
    setSelectedExtendedAdventurer(extended)
    // Конвертируем в старый формат для совместимости
    const legacyAdventurer = convertToLegacy(extended)
    legacyAdventurer.id = `ext-${extended.id}` // Уникальный ID для расширенного
    setSelectedAdventurer(legacyAdventurer)
  }

  // Расчёт модификаторов экспедиции (v2 - CraftedWeaponV2 с новыми полями)
  const expeditionCalculation = useMemo<ExpeditionCalculation | null>(() => {
    if (!selectedExpedition || !selectedWeapon || !selectedAdventurer) return null

    // Получаем расширенные данные искателя
    const extendedAdventurer = selectedExtendedAdventurer || convertToExtended(selectedAdventurer)

    return calculateExpeditionResult(
      extendedAdventurer,
      selectedExpedition,
      guild.level,
      selectedWeapon.stats.attack,
      selectedWeapon.currentDurability,
      selectedWeapon.type as any,
      selectedWeapon.id,
      // Новые параметры для системы модификаторов
      selectedWeapon.qualityRank,
      selectedWeapon.epicMultiplier,
      selectedWeapon.combatMaterialId,
      selectedWeapon.quality
    )
  }, [selectedExpedition, selectedWeapon, selectedAdventurer, selectedExtendedAdventurer, guild.level])

  return (
    <TooltipProvider>
      <div className="space-y-6">
        {/* Активные экспедиции */}
        {guild.activeExpeditions.length > 0 && (
          <Card className="card-medieval">
            <CardHeader>
              <CardTitle className="text-amber-200 flex items-center gap-2">
                <Timer className="w-5 h-5" />
                Активные экспедиции
                <Badge variant="outline" className="ml-2 text-xs">
                  {guild.activeExpeditions.length} / {getMaxActiveExpeditions(guild.level)}
                </Badge>
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <AnimatePresence mode="popLayout">
                  {guild.activeExpeditions.map(expedition => (
                    <ActiveExpeditionCard key={expedition.id} expedition={expedition} />
                  ))}
                </AnimatePresence>
              </div>
            </CardContent>
          </Card>
        )}

        {/* Квесты восстановления */}
        {guild.recoveryQuests.filter(q => q.status !== 'declined').length > 0 && (
          <Card className="card-medieval border-red-600/30">
            <CardHeader>
              <CardTitle className="text-red-400 flex items-center gap-2">
                <Skull className="w-5 h-5" />
                Потерянное оружие
              </CardTitle>
              <CardDescription>Оружие, потерянное в неудачных экспедициях</CardDescription>
            </CardHeader>
            <CardContent>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {guild.recoveryQuests
                  .filter(q => q.status !== 'declined')
                  .map(quest => (
                    <RecoveryQuestCard key={quest.id} quest={quest} />
                  ))}
              </div>
            </CardContent>
          </Card>
        )}

        {/* Выбор экспедиции */}
        <Card className="card-medieval">
          <CardHeader className="flex flex-row items-center justify-between">
            <div>
              <CardTitle className="text-amber-200 flex items-center gap-2">
                <Compass className="w-5 h-5" />
                Доступные экспедиции
              </CardTitle>
              <CardDescription>Выберите миссию для искателей</CardDescription>
            </div>
            <div className="flex items-center gap-2">
              {/* Индикатор черновика */}
              {draftStatus?.hasDraft && (
                <Badge variant="outline" className="text-amber-400 border-amber-600/50">
                  Черновик сохранён
                </Badge>
              )}
              <Button
                size="sm"
                variant="outline"
                onClick={refreshExpeditions}
                disabled={resources.gold < refreshCost}
                className="text-amber-400 border-amber-600 hover:bg-amber-900/30"
              >
                <RefreshCw className="w-4 h-4 mr-1" />
                Обновить ({refreshCost} 💰)
              </Button>
            </div>
          </CardHeader>
          <CardContent>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <AnimatePresence mode="popLayout">
                {currentExpeditions.map(expedition => {
                  const { can, reason } = canSelectExpedition(expedition)
                  return (
                    <ExpeditionSelectionCard
                      key={expedition.id}
                      expedition={expedition}
                      isSelected={selectedExpedition?.id === expedition.id}
                      canSelect={can}
                      reason={reason}
                      onSelect={() => {
                        setSelectedExpedition(expedition)
                        setSelectedWeapon(null)
                        setSelectedAdventurer(null)
                        setSelectedExtendedAdventurer(null)
                      }}
                    />
                  )
                })}
              </AnimatePresence>
            </div>
          </CardContent>
        </Card>

        {/* Выбор оружия */}
        {selectedExpedition && (
          <Card className="card-medieval">
            <CardHeader>
              <CardTitle className="text-amber-200 flex items-center gap-2">
                <Sword className="w-5 h-5" />
                Выберите оружие
              </CardTitle>
              <CardDescription>
                Требуется атака {selectedExpedition.minWeaponAttack}+
              </CardDescription>
            </CardHeader>
            <CardContent>
              {availableWeapons.length === 0 ? (
                <p className="text-stone-500 text-center py-4">
                  Нет подходящего оружия. Создайте оружие в кузнице.
                </p>
              ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
                  <AnimatePresence mode="popLayout">
                    {availableWeapons.map(weapon => {
                      const { can, reason } = canSelectWeapon(weapon)
                      return (
                        <WeaponSelectionCard
                          key={weapon.id}
                          weapon={weapon}
                          isSelected={selectedWeapon?.id === weapon.id}
                          canSelect={can}
                          reason={reason}
                          onSelect={() => {
                            setSelectedWeapon(weapon)
                            setSelectedAdventurer(null)
                          }}
                        />
                      )
                    })}
                  </AnimatePresence>
                </div>
              )}
            </CardContent>
          </Card>
        )}

        {/* Поиск искателей */}
        {selectedWeapon && selectedExpedition && (
          <RecruitmentInterface
            expedition={mapExpeditionForRecruitment({
              id: selectedExpedition.id,
              name: selectedExpedition.name,
              difficulty: selectedExpedition.difficulty,
              reward: selectedExpedition.reward,
              duration: selectedExpedition.duration,
              failureChance: selectedExpedition.failureChance,
              weaponLossChance: selectedExpedition.weaponLossChance,
              minWeaponAttack: selectedExpedition.minWeaponAttack,
            })}
            weapon={mapWeaponForRecruitment({
              id: selectedWeapon.id,
              name: selectedWeapon.fullName,
              attack: selectedWeapon.stats.attack,
              durability: selectedWeapon.currentDurability ?? selectedWeapon.stats.durability,
            })}
            guildLevel={guild.level}
            onSelect={handleExtendedAdventurerSelect}
            onCancel={() => {
              setSelectedExtendedAdventurer(null)
              setSelectedAdventurer(null)
            }}
          />
        )}

        {/* Сравнение сценариев */}
        {selectedExpedition && selectedWeapon && selectedExtendedAdventurer && (
          <ScenarioComparison
            expedition={selectedExpedition}
            adventurer={selectedExtendedAdventurer}
            weapon={selectedWeapon}
          />
        )}

        {/* Кнопка начала экспедиции и модификаторы */}
        {selectedExpedition && selectedWeapon && selectedAdventurer && (
          <Card className="card-medieval border-amber-600/50">
            <CardContent className="p-4">
              <div className="flex items-center justify-between mb-4">
                <div>
                  <h4 className="font-semibold text-stone-200">Готово к отправке</h4>
                  <p className="text-sm text-stone-400">
                    {selectedExpedition.name} • {selectedAdventurer.name} • {selectedWeapon.name}
                  </p>
                </div>
                <Button
                  onClick={handleStartExpedition}
                  className="bg-gradient-to-r from-amber-700 to-amber-800 hover:from-amber-600 hover:to-amber-700 text-white"
                >
                  <Send className="w-4 h-4 mr-2" />
                  Отправить в экспедицию
                </Button>
              </div>

              {/* Детализация модификаторов */}
              {expeditionCalculation && (
                <div className="mt-4 pt-4 border-t border-stone-700/50">
                  <div className="flex items-center gap-2 mb-3">
                    <Zap className="w-4 h-4 text-amber-400" />
                    <h5 className="text-sm font-medium text-stone-300">Модификаторы экспедиции</h5>
                  </div>

                  {/* Сводка результатов */}
                  <div className="grid grid-cols-2 md:grid-cols-4 gap-2 mb-4">
                    <div className="bg-stone-800/50 rounded-lg p-2 text-center">
                      <div className="text-xs text-stone-400">Шанс успеха</div>
                      <div className={`text-lg font-bold ${
                        expeditionCalculation.successChance >= 70 ? 'text-green-400' :
                        expeditionCalculation.successChance >= 50 ? 'text-amber-400' : 'text-red-400'
                      }`}>
                        {expeditionCalculation.successChance}%
                      </div>
                    </div>
                    <div className="bg-stone-800/50 rounded-lg p-2 text-center">
                      <div className="text-xs text-stone-400">Награда</div>
                      <div className="text-lg font-bold text-amber-400">
                        💰 {expeditionCalculation.commission}
                      </div>
                    </div>
                    <div className="bg-stone-800/50 rounded-lg p-2 text-center">
                      <div className="text-xs text-stone-400">Души войны</div>
                      <div className="text-lg font-bold text-purple-400">
                        ⚔️ {expeditionCalculation.warSoul}
                      </div>
                    </div>
                    <div className="bg-stone-800/50 rounded-lg p-2 text-center">
                      <div className="text-xs text-stone-400">Износ оружия</div>
                      <div className="text-lg font-bold text-yellow-400">
                        🔧 -{expeditionCalculation.weaponWear}%
                      </div>
                    </div>
                  </div>

                  {/* Рекомендация */}
                  <div className={`text-sm p-2 rounded-lg mb-3 ${
                    expeditionCalculation.recommendation.rating === 'excellent' ? 'bg-green-900/30 text-green-300' :
                    expeditionCalculation.recommendation.rating === 'good' ? 'bg-blue-900/30 text-blue-300' :
                    expeditionCalculation.recommendation.rating === 'risky' ? 'bg-amber-900/30 text-amber-300' :
                    'bg-red-900/30 text-red-300'
                  }`}>
                    {expeditionCalculation.recommendation.description}
                  </div>

                  {/* Полная детализация модификаторов (сворачиваемая) */}
                  <details className="group">
                    <summary className="cursor-pointer text-sm text-amber-400 hover:text-amber-300 flex items-center gap-1">
                      <span className="group-open:rotate-90 transition-transform inline-block">▶</span>
                      Показать все модификаторы
                    </summary>
                    <div className="mt-3">
                      <FullModifierBreakdown calculation={expeditionCalculation} compact={true} />
                    </div>
                  </details>
                </div>
              )}
            </CardContent>
          </Card>
        )}

        {/* История экспедиций */}
        {guild.history.length > 0 && (
          <Card className="card-medieval">
            <CardHeader>
              <CardTitle className="text-stone-300 flex items-center gap-2">
                <Scroll className="w-5 h-5" />
                История экспедиций
              </CardTitle>
              <CardDescription>
                Нажмите на иконку искателя 👤 для просмотра карточки и предложения контракта
              </CardDescription>
            </CardHeader>
            <CardContent>
              <div className="space-y-2 max-h-80 overflow-y-auto">
                {[...guild.history].reverse().slice(0, 20).map(entry => {
                  const adventurerId = entry.adventurerData?.id || ''
                  const stats = getAdventurerStats(adventurerId)

                  return (
                    <ExpeditionHistoryEntryComponent
                      key={entry.id}
                      entry={entry}
                      guildLevel={guild.level}
                      guildGold={resources.gold}
                      guildGlory={guild.glory}
                      currentContractsCount={contractedAdventurers.length}
                      adventurerMissionCount={stats.missionCount}
                      adventurerSuccessRate={stats.successRate}
                      alreadyContracted={isAlreadyContracted(adventurerId)}
                      onOfferContract={handleOfferContract}
                    />
                  )
                })}
              </div>
            </CardContent>
          </Card>
        )}
      </div>
    </TooltipProvider>
  )
}

/**
 * ExpeditionEventLog - Отображение событий экспедиции
 * Показывает события в хронологическом порядке с анимацией
 */

'use client'

import { useState, useEffect, useMemo } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { ScrollText, Clock, MapPin, Sparkles } from 'lucide-react'
import type { ExpeditionEvent } from '@/types/expedition-events'

interface ExpeditionEventLogProps {
  events: ExpeditionEvent[]
  startedAt: number
  endsAt: number
  isComplete: boolean
}

// Цвета для разных типов событий
const EVENT_TYPE_COLORS: Record<string, { bg: string; border: string; text: string }> = {
  combat: { bg: 'bg-red-900/30', border: 'border-red-700/50', text: 'text-red-300' },
  discovery: { bg: 'bg-blue-900/30', border: 'border-blue-700/50', text: 'text-blue-300' },
  social: { bg: 'bg-green-900/30', border: 'border-green-700/50', text: 'text-green-300' },
  travel: { bg: 'bg-amber-900/30', border: 'border-amber-700/50', text: 'text-amber-300' },
  danger: { bg: 'bg-orange-900/30', border: 'border-orange-700/50', text: 'text-orange-300' },
  rest: { bg: 'bg-slate-800/50', border: 'border-slate-600/50', text: 'text-slate-300' },
  mystery: { bg: 'bg-purple-900/30', border: 'border-purple-700/50', text: 'text-purple-300' },
  weather: { bg: 'bg-cyan-900/30', border: 'border-cyan-700/50', text: 'text-cyan-300' },
  treasure: { bg: 'bg-yellow-900/30', border: 'border-yellow-700/50', text: 'text-yellow-300' },
}

// Названия типов на русском
const EVENT_TYPE_NAMES: Record<string, string> = {
  combat: 'Бой',
  discovery: 'Открытие',
  social: 'Встреча',
  travel: 'Путь',
  danger: 'Угроза',
  rest: 'Отдых',
  mystery: 'Тайна',
  weather: 'Погода',
  treasure: 'Сокровище',
}

export function ExpeditionEventLog({
  events,
  startedAt,
  endsAt,
  isComplete,
}: ExpeditionEventLogProps) {
  const [currentTime, setCurrentTime] = useState(Date.now())
  const [expandedEvent, setExpandedEvent] = useState<string | null>(null)

  // Обновляем текущее время каждую секунду
  useEffect(() => {
    if (isComplete) return

    const interval = setInterval(() => {
      setCurrentTime(Date.now())
    }, 1000)

    return () => clearInterval(interval)
  }, [isComplete])

  // Сортируем события по времени
  const sortedEvents = useMemo(() => {
    return [...events].sort((a, b) => a.triggeredAt - b.triggeredAt)
  }, [events])

  // Определяем, какие события уже произошли
  const visibleEvents = useMemo(() => {
    if (isComplete) return sortedEvents
    return sortedEvents.filter(e => e.triggeredAt <= currentTime)
  }, [sortedEvents, currentTime, isComplete])

  // Прогресс экспедиции
  const progress = useMemo(() => {
    if (isComplete) return 100
    const total = endsAt - startedAt
    const elapsed = currentTime - startedAt
    return Math.min(100, Math.max(0, (elapsed / total) * 100))
  }, [currentTime, startedAt, endsAt, isComplete])

  // Форматирование времени
  const formatTime = (timestamp: number): string => {
    const date = new Date(timestamp)
    return date.toLocaleTimeString('ru-RU', { hour: '2-digit', minute: '2-digit' })
  }

  // Пустое состояние - когда экспедиция идёт но событий ещё не было
  if (events.length === 0) {
    return (
      <div className="rounded-lg border border-slate-700 bg-slate-900/30 p-4">
        <p className="text-slate-500 text-sm text-center">
          События будут появляться по ходу экспедиции
        </p>
      </div>
    )
  }

  // Пустое состояние - когда события есть, но ещё ни одно не произошло
  if (!isComplete && visibleEvents.length === 0) {
    return (
      <div className="rounded-lg border border-slate-700 bg-slate-900/50 overflow-hidden">
        {/* Заголовок */}
        <div className="flex items-center justify-between p-3 border-b border-slate-700 bg-slate-800/50">
          <h4 className="font-semibold text-slate-200 flex items-center gap-2">
            <ScrollText className="w-4 h-4" />
            Журнал событий
          </h4>
          {!isComplete && (
            <div className="flex items-center gap-2 text-xs text-slate-400">
              <Clock className="w-3.5 h-3.5" />
              <span>{Math.round(progress)}%</span>
            </div>
          )}
        </div>

        {/* Прогресс-бар */}
        {!isComplete && (
          <div className="h-1 bg-slate-800">
            <motion.div
              className="h-full bg-blue-500/70"
              initial={{ width: 0 }}
              animate={{ width: `${progress}%` }}
              transition={{ duration: 0.5 }}
            />
          </div>
        )}

        {/* Состояние ожидания */}
        <div className="max-h-64 overflow-y-auto p-2">
          <div className="text-center py-6 text-xs text-slate-500">
            <MapPin className="w-5 h-5 mx-auto mb-2 opacity-40" />
            <p>Экспедиция в пути...</p>
            <p className="text-slate-600 mt-1">События будут появляться по мере продвижения</p>
          </div>
        </div>
      </div>
    )
  }

  return (
    <div className="rounded-lg border border-slate-700 bg-slate-900/50 overflow-hidden">
      {/* Заголовок */}
      <div className="flex items-center justify-between p-3 border-b border-slate-700 bg-slate-800/50">
        <h4 className="font-semibold text-slate-200 flex items-center gap-2">
          <ScrollText className="w-4 h-4" />
          Журнал событий
        </h4>
        {!isComplete && (
          <div className="flex items-center gap-2 text-xs text-slate-400">
            <Clock className="w-3.5 h-3.5" />
            <span>{Math.round(progress)}%</span>
          </div>
        )}
      </div>

      {/* Прогресс-бар */}
      {!isComplete && (
        <div className="h-1 bg-slate-800">
          <motion.div
            className="h-full bg-blue-500/70"
            initial={{ width: 0 }}
            animate={{ width: `${progress}%` }}
            transition={{ duration: 0.5 }}
          />
        </div>
      )}

      {/* Список событий - только произошедшие */}
      <div className="max-h-64 overflow-y-auto p-2 space-y-2">
        <AnimatePresence mode="popLayout">
          {visibleEvents.map((event, index) => {
            const colors = EVENT_TYPE_COLORS[event.type] || EVENT_TYPE_COLORS.travel
            if (!colors) return null
            const { bg, border, text } = colors

            return (
              <motion.div
                key={event.instanceId}
                initial={{ opacity: 0, x: -20 }}
                animate={{ opacity: 1, x: 0 }}
                exit={{ opacity: 0, x: 20 }}
                transition={{ delay: index * 0.05 }}
                onClick={() => setExpandedEvent(
                  expandedEvent === event.instanceId ? null : event.instanceId
                )}
                className={`
                  rounded-lg border p-2.5 cursor-pointer transition-all
                  ${bg} ${border} hover:brightness-110
                `}
              >
                {/* Основная строка */}
                <div className="flex items-start gap-3">
                  {/* Иконка */}
                  <div className={`
                    w-8 h-8 rounded-full flex items-center justify-center
                    bg-slate-900/50 text-lg flex-shrink-0
                  `}>
                    {event.icon}
                  </div>

                  {/* Контент */}
                  <div className="flex-1 min-w-0">
                    <div className="flex items-start justify-between gap-2">
                      <p className={`text-sm font-medium ${text} leading-snug`}>
                        {event.text}
                      </p>
                      <span className="text-xs text-slate-500 flex-shrink-0">
                        #{event.order}
                      </span>
                    </div>

                    {/* Мета-информация */}
                    <div className="flex items-center gap-3 mt-1.5 text-xs">
                      <span className="text-slate-500">
                        {formatTime(event.triggeredAt)}
                      </span>
                      <span className="px-1.5 py-0.5 rounded text-xs bg-slate-900/50 text-slate-400">
                        {EVENT_TYPE_NAMES[event.type]}
                      </span>
                    </div>
                  </div>
                </div>

                {/* Развёрнутое описание (если есть) */}
                <AnimatePresence>
                  {expandedEvent === event.instanceId && (
                    <motion.div
                      initial={{ height: 0, opacity: 0 }}
                      animate={{ height: 'auto', opacity: 1 }}
                      exit={{ height: 0, opacity: 0 }}
                      className="overflow-hidden"
                    >
                      <div className="pt-2 mt-2 border-t border-slate-700/50 text-xs text-slate-400">
                        <p>Событие произошло во время экспедиции.</p>
                        {event.flags?.bossOnly && (
                          <p className="flex items-center gap-1 mt-1 text-yellow-400">
                            <Sparkles className="w-3 h-3" />
                            Особое событие босс-энкаунтера
                          </p>
                        )}
                      </div>
                    </motion.div>
                  )}
                </AnimatePresence>
              </motion.div>
            )
          })}
        </AnimatePresence>
      </div>
    </div>
  )
}

export default ExpeditionEventLog

/**
 * ScenarioComparison - Сравнение сценариев экспедиции
 * Показывает три варианта исхода: успех, критический успех, провал
 */

'use client'

import { motion } from 'framer-motion'
import {
  CheckCircle,
  XCircle,
  Star,
  TrendingUp,
  AlertTriangle,
  Shield,
  Swords,
} from 'lucide-react'
import type { ExpeditionTemplate } from '@/data/expedition-templates'
import { calculateExpeditionResult } from '@/lib/expedition-calculator-v2'
import type { AdventurerExtended } from '@/types/adventurer-extended'
import type { CraftedWeaponV2 } from '@/types/craft-v2'

interface ScenarioComparisonProps {
  expedition: ExpeditionTemplate
  adventurer: AdventurerExtended
  weapon: CraftedWeaponV2
}

interface ScenarioData {
  type: 'success' | 'critical' | 'failure'
  label: string
  description: string
  icon: React.ReactNode
  color: string
  bgColor: string
  borderColor: string
  reward: {
    gold: number
    warSoul: number
    glory: number
  }
  weaponLossChance: number
}

export function ScenarioComparison({
  expedition,
  adventurer,
  weapon,
}: ScenarioComparisonProps) {
  // Рассчитываем результат экспедиции
  const calculation = calculateExpeditionResult(
    adventurer,
    expedition,
    1, // guildLevel placeholder
    weapon.stats.attack,
    weapon.currentDurability,
    weapon.type as any,
    weapon.id,
    weapon.qualityRank,
    weapon.epicMultiplier,
    weapon.combatMaterialId,
    weapon.quality
  )

  // Для критического и провала используем множители
  const successChance = calculation.successChance
  const criticalChance = Math.max(5, (100 - successChance) * 0.15) // ~15% от оставшегося шанса
  const failureChance = 100 - successChance - criticalChance

  const scenarios: ScenarioData[] = [
    {
      type: 'critical',
      label: 'Критический успех',
      description: 'Искатель превзошёл ожидания! Дополнительные награды и слава.',
      icon: <Star className="w-6 h-6" />,
      color: 'text-yellow-400',
      bgColor: 'bg-yellow-900/20',
      borderColor: 'border-yellow-600/50',
      reward: {
        gold: Math.round(expedition.reward.baseGold * 1.5), // +50% к награде
        warSoul: Math.round(expedition.reward.baseWarSoul * 1.5),
        glory: 5,
      },
      weaponLossChance: 0,
    },
    {
      type: 'success',
      label: 'Успех',
      description: 'Миссия выполнена. Стандартная награда.',
      icon: <CheckCircle className="w-6 h-6" />,
      color: 'text-green-400',
      bgColor: 'bg-green-900/20',
      borderColor: 'border-green-600/50',
      reward: {
        gold: expedition.reward.baseGold,
        warSoul: expedition.reward.baseWarSoul,
        glory: 2,
      },
      weaponLossChance: 0,
    },
    {
      type: 'failure',
      label: 'Провал',
      description: 'Миссия не удалась. Угроза потери оружия.',
      icon: <XCircle className="w-6 h-6" />,
      color: 'text-red-400',
      bgColor: 'bg-red-900/20',
      borderColor: 'border-red-600/50',
      reward: {
        gold: Math.round(expedition.reward.baseGold * 0.1), // 10% компенсация
        warSoul: 0,
        glory: 0,
      },
      weaponLossChance: expedition.weaponLossChance,
    },
  ]

  const successRate = Math.round(successChance)

  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      className="rounded-lg border border-slate-700 bg-slate-900/50 p-4"
    >
      {/* Заголовок с шансом успеха */}
      <div className="flex items-center justify-between mb-4">
        <h3 className="text-lg font-semibold text-slate-200 flex items-center gap-2">
          <TrendingUp className="w-5 h-5" />
          Вероятности исхода
        </h3>
        <div className="flex items-center gap-2">
          <span className="text-sm text-slate-400">Шанс успеха:</span>
          <span
            className={`font-bold ${
              successRate >= 70
                ? 'text-green-400'
                : successRate >= 40
                  ? 'text-yellow-400'
                  : 'text-red-400'
            }`}
          >
            {successRate}%
          </span>
        </div>
      </div>

      {/* График вероятностей */}
      <div className="mb-4">
        <div className="flex h-3 rounded-full overflow-hidden bg-slate-800">
          {/* Критический успех */}
          <motion.div
            initial={{ width: 0 }}
            animate={{ width: `${Math.round(criticalChance)}%` }}
            className="bg-yellow-500/70"
            title={`Критический успех ~${Math.round(criticalChance)}%`}
          />
          {/* Обычный успех */}
          <motion.div
            initial={{ width: 0 }}
            animate={{ width: `${Math.max(0, successRate - Math.round(criticalChance))}%` }}
            className="bg-green-500/70"
            title={`Успех ~${Math.max(0, successRate - Math.round(criticalChance))}%`}
          />
          {/* Провал */}
          <motion.div
            initial={{ width: 0 }}
            animate={{ width: `${Math.round(failureChance)}%` }}
            className="bg-red-500/70"
            title={`Провал ~${Math.round(failureChance)}%`}
          />
        </div>
        <div className="flex justify-between text-xs text-slate-500 mt-1">
          <span>Крит (~{Math.round(criticalChance)}%)</span>
          <span>Успех (~{Math.max(0, successRate - Math.round(criticalChance))}%)</span>
          <span>Провал (~{Math.round(failureChance)}%)</span>
        </div>
      </div>

      {/* Карточки сценариев */}
      <div className="grid grid-cols-3 gap-3">
        {scenarios.map((scenario, index) => (
          <motion.div
            key={scenario.type}
            initial={{ opacity: 0, scale: 0.95 }}
            animate={{ opacity: 1, scale: 1 }}
            transition={{ delay: index * 0.1 }}
            className={`rounded-lg border ${scenario.borderColor} ${scenario.bgColor} p-3`}
          >
            {/* Иконка и название */}
            <div className={`flex items-center gap-2 mb-2 ${scenario.color}`}>
              {scenario.icon}
              <span className="font-semibold text-sm">{scenario.label}</span>
            </div>

            {/* Описание */}
            <p className="text-xs text-slate-400 mb-3 leading-relaxed">
              {scenario.description}
            </p>

            {/* Награды */}
            <div className="space-y-1">
              <div className="flex items-center justify-between text-sm">
                <span className="text-slate-500">Золото:</span>
                <span className="text-amber-400 font-medium">
                  {scenario.reward.gold}
                </span>
              </div>
              <div className="flex items-center justify-between text-sm">
                <span className="text-slate-500">War Soul:</span>
                <span className="text-blue-400 font-medium">
                  {scenario.reward.warSoul}
                </span>
              </div>
              {scenario.reward.glory > 0 && (
                <div className="flex items-center justify-between text-sm">
                  <span className="text-slate-500">Слава:</span>
                  <span className="text-purple-400 font-medium">
                    +{scenario.reward.glory}
                  </span>
                </div>
              )}
            </div>

            {/* Предупреждение о потере оружия */}
            {scenario.weaponLossChance > 0 && (
              <div className="mt-3 flex items-center gap-1.5 text-xs text-red-400">
                <AlertTriangle className="w-3.5 h-3.5" />
                <span>Шанс потери оружия: {scenario.weaponLossChance}%</span>
              </div>
            )}

            {/* Безопасность */}
            {scenario.weaponLossChance === 0 && scenario.type !== 'failure' && (
              <div className="mt-3 flex items-center gap-1.5 text-xs text-green-400">
                <Shield className="w-3.5 h-3.5" />
                <span>Оружие в безопасности</span>
              </div>
            )}
          </motion.div>
        ))}
      </div>

      {/* Подсказка */}
      <div className="mt-4 p-3 rounded bg-slate-800/50 text-xs text-slate-400">
        <p className="flex items-start gap-2">
          <Swords className="w-4 h-4 mt-0.5 flex-shrink-0" />
          <span>
            Итоговый результат зависит от множителей снаряжения, навыков искателя
            и немного от удачи. Используйте подходящее оружие и качественное снаряжение
            для повышения шансов.
          </span>
        </p>
      </div>
    </motion.div>
  )
}

export default ScenarioComparison

/**
 * Weapon Selection Card
 * Карточка выбора оружия для экспедиции (v2 - CraftedWeaponV2)
 */

'use client'

import React from 'react'
import { motion } from 'framer-motion'
import { CheckCircle, Star } from 'lucide-react'
import { Card, CardContent } from '@/components/ui/card'
import { cn } from '@/lib/utils'
import type { CraftedWeaponV2 } from '@/types/craft-v2'

// ================================
// ТИПЫ
// ================================

interface WeaponSelectionCardProps {
  weapon: CraftedWeaponV2
  isSelected: boolean
  canSelect: boolean
  onSelect: () => void
  reason?: string
}

// Цвета для рангов качества
const rankColors: Record<string, string> = {
  F: 'text-gray-400',
  D: 'text-stone-400',
  C: 'text-green-400',
  B: 'text-blue-400',
  A: 'text-purple-400',
  S: 'text-amber-400',
}

// ================================
// КОМПОНЕНТ
// ================================

export const WeaponSelectionCard: React.FC<WeaponSelectionCardProps> = ({
  weapon,
  isSelected,
  canSelect,
  onSelect,
  reason
}) => {
  // Вычисляем процент прочности
