        {navItems.map((item) => {
          const Icon = item.icon
          const isActive = currentScreen === item.id

          return (
            <motion.div
              key={item.id}
              whileHover={{ x: 5 }}
              whileTap={{ scale: 0.98 }}
            >
              <Button
                data-tutorial={item.id === 'workers' ? 'nav-workers' : item.id === 'resources' ? 'nav-resources' : item.id === 'guild' ? 'nav-guild' : undefined}
