                <TooltipContent side="top" className="max-w-xs">
                  <p className="font-semibold text-amber-400">Эпичность: ×{(weapon.epicMultiplier ?? 1).toFixed(2)}</p>
                  <p className="text-xs text-stone-400 mt-1">
