                  <span className="text-stone-300">{bestBlacksmith.name}</span>
                  {mastery && (
                    <Badge variant="outline" className="text-xs text-amber-400 border-amber-600/50">
                      {mastery.name}
                    </Badge>
                  )}
                </div>
                {mastery && (
                  <span className="text-green-400">+{mastery.successBonus}% к успеху</span>
                )}
              </div>
