// ================================
// ФУНКЦИИ
// ================================

export function getExpeditionById(id: string): ExpeditionTemplate | undefined {
  return expeditionTemplates.find(e => e.id === id)
}

export function getExpeditionsByType(type: ExpeditionType): ExpeditionTemplate[] {
  return expeditionTemplates.filter(e => e.type === type)
}

export function getExpeditionsByDifficulty(difficulty: ExpeditionDifficulty): ExpeditionTemplate[] {
  return expeditionTemplates.filter(e => e.difficulty === difficulty)
}

export function getAvailableExpeditions(guildLevel: number): ExpeditionTemplate[] {
  return expeditionTemplates.filter(e => e.minGuildLevel <= guildLevel)
}

// Расчёт полной стоимости экспедиции
export function calculateTotalCost(template: ExpeditionTemplate): number {
  return template.cost.supplies + template.cost.deposit
}

// Расчёт комиссии игрока
export function calculateCommission(
  template: ExpeditionTemplate,
  guildLevel: number,
  glory: number
): number {
  // Базовая комиссия: 15% + 2% за каждый уровень гильдии
  const baseCommission = 15 + (guildLevel - 1) * 2

  // Бонус от славы: +1% за каждые 100 очков
  const gloryBonus = Math.floor(glory / 100)

  const totalCommission = Math.min(30, baseCommission + gloryBonus)

  return Math.floor(template.reward.baseGold * totalCommission / 100)
}

// Расчёт Души Войны для оружия
export function calculateWarSoul(
  template: ExpeditionTemplate,
  adventurerSkill: number,
  weaponQuality: number
): number {
  const typeMultiplier = typeInfo[template.type].warSoulMultiplier
  const skillBonus = 1 + adventurerSkill / 100
  const qualityBonus = 0.8 + (weaponQuality / 100) * 0.4 // 0.8-1.2

  const base = template.reward.baseWarSoul
  const result = base * typeMultiplier * skillBonus * qualityBonus

  // Добавляем случайность ±20%
  const variance = 0.8 + Math.random() * 0.4

  return Math.floor(result * variance)
}

// Расчёт шанса успеха
export function calculateSuccessChance(
  template: ExpeditionTemplate,
  weaponAttack: number,
  adventurerBonuses: number = 0
): number {
  // Базовый шанс успеха = 100% - шанс провала
  let baseSuccess = 100 - template.failureChance

  // Бонус от атаки оружия
  const attackBonus = Math.min(20, (weaponAttack - template.minWeaponAttack) / 2)
  baseSuccess += Math.max(0, attackBonus)

  // Бонус от искателя
  baseSuccess += adventurerBonuses

  // Ограничение: 10% - 95%
  return Math.max(10, Math.min(95, baseSuccess))
}

// Расчёт шанса потери оружия
export function calculateWeaponLossChance(
  template: ExpeditionTemplate,
  weaponQuality: number,
  adventurerBonuses: number = 0
): number {
  // Базовый шанс потери
  let lossChance = template.weaponLossChance

  // Каждые +20 качества = -2% к шансу потери
  const qualityReduction = Math.floor(weaponQuality / 20) * 2
  lossChance -= qualityReduction

  // Бонус от искателя
  lossChance += adventurerBonuses // Обычно отрицательный

  // Ограничение: 0% - 50%
  return Math.max(0, Math.min(50, lossChance))
}

// Расчёт случайных бонусов
export function rollBonusRewards(
  template: ExpeditionTemplate
): { type: string; amount: number }[] {
  const bonuses: { type: string; amount: number }[] = []

  // Guild Bonus (20% шанс)
  if (Math.random() < 0.2) {
    bonuses.push({
      type: 'guild_bonus',
      amount: Math.floor(10 + Math.random() * 40), // 10-50 золота
    })
  }

  // Lucky Find (10% шанс)
  if (Math.random() < 0.1) {
    bonuses.push({
      type: 'lucky_find',
      amount: Math.floor(25 + Math.random() * 75), // 25-100 золота
    })
  }

  // Special Event (5% шанс)
  if (Math.random() < 0.05) {
    bonuses.push({
      type: 'special_event',
      amount: Math.floor(50 + Math.random() * 150), // 50-200 золота
    })
  }

  return bonuses
}

/**
 * Адаптер для обратной совместимости
 * Преобразует MaterialNode в Material для существующего кода крафта
 */

import type { MaterialNode } from '@/types/materials/material-core'
import type { Material } from '@/types/craft-v2'

/**
 * Преобразует MaterialNode в Material для обратной совместимости
 */
export function adaptMaterialNodeToMaterial(node: MaterialNode): Material {
  // Маппинг MaterialClass в старые категории
  const classToCategory: Record<string, string> = {
    metal: 'metal',
    mineral: 'stone',
    wood: 'wood',
    leather: 'leather',
    other: 'other',
  }

  // Определяем rarity
  let rarity: 'common' | 'uncommon' | 'rare' | 'epic' | 'legendary' = 'common'
  if (node.economy.rarity >= 150) rarity = 'legendary'
  else if (node.economy.rarity >= 100) rarity = 'epic'
  else if (node.economy.rarity >= 60) rarity = 'rare'
  else if (node.economy.rarity >= 30) rarity = 'uncommon'

  // Определяем доминантное свойство
  let dominantPropertyType: 'durability' | 'sharpness' | 'balance' | 'conductivity' = 'durability'
  if (node.physical.hardness >= 70) dominantPropertyType = 'sharpness'
  else if (node.physical.elasticity >= 60) dominantPropertyType = 'balance'
  else if (node.arcane.conductivity >= 40) dominantPropertyType = 'conductivity'

  // Определяем dominantPropertyValue
  let dominantPropertyValue = 50
  switch (dominantPropertyType) {
    case 'sharpness':
      dominantPropertyValue = node.physical.hardness
      break
    case 'balance':
      dominantPropertyValue = Math.round((node.physical.elasticity + node.physical.toughness) / 2)
      break
    case 'conductivity':
      dominantPropertyValue = node.arcane.conductivity
      break
    case 'durability':
    default:
      dominantPropertyValue = Math.round((node.physical.toughness + node.physical.hardness) / 2)
  }

  // Адаптируем MaterialNode к Material
  const material: Material = {
    id: node.identity.id,
    name: node.identity.name,
    adjective: '', // Не хранится в MaterialNode
    category: classToCategory[node.identity.class] || 'other',
    description: node.summary.basic,
    
    properties: {
      hardness: node.physical.hardness,
      flexibility: node.physical.elasticity,
      weight: node.physical.density,
      conductivity: node.arcane.conductivity,
    },
    
    crafting: {
      workability: node.processing.workability,
      meltingPoint: node.physical.meltingPoint || 0,
      requiredHeat: Math.ceil(node.economy.tier / 2),
    },
    
    weaponEffects: {
      attackBonus: Math.round((node.physical.hardness - 50) / 3),
      durabilityBonus: Math.round((node.physical.toughness - 50) / 5),
      soulCapacity: Math.round(node.arcane.affinity * 2),
      repairPotential: node.processing.repairability / 100,
      enchantPower: node.arcane.conductivity / 100,
      enchantSlots: Math.floor(node.arcane.resonance / 30),
    },
    
    craftTimeModifier: 1 + (100 - node.processing.workability) / 200,
    craftRisk: node.processing.defectRisk,
    
    dominantProperty: {
      type: dominantPropertyType,
      value: dominantPropertyValue,
    },
    
    source: {
      rarity,
      unlockCondition: node.discovery.unlockedBy?.[0]?.requiredExpertise 
        ? `Уровень кузнеца ${Math.ceil(node.discovery.unlockedBy[0].requiredExpertise / 10)}`
        : undefined,
    },
    
    icon: node.icon,
  }

  // Добавляем рецепт если есть
  if (node.recipe) {
    material.recipe = {
      inputs: node.recipe.inputs.map(input => ({
        resourceId: input.materialId,
        quantity: input.quantity,
        name: input.materialId, // Имя не хранится в MaterialRecipeInput
      })),
      requiredLevel: Math.ceil(node.economy.tier * 2),
    }
    
    if (node.recipe.processModifiers) {
      material.recipe.fuel = {
        resourceId: 'coal',
        quantity: Math.ceil(node.recipe.inputs.length * 1.5),
      }
    }
  }

  return material
}

/**
 * Получает Material из MaterialNode по ID
 */
export function getMaterialAsLegacy(id: string): Material | undefined {
  const { materialById } = require('./library')
  const node = materialById[id]
  if (!node) return undefined
  return adaptMaterialNodeToMaterial(node)
}

/**
 * Получает все материалы в формате Material[]
 */
export function getAllMaterialsAsLegacy(): Material[] {
  const { allMaterials } = require('./library')
  return allMaterials.map(adaptMaterialNodeToMaterial)
}

