// Количество бонусов и их редкость
export const bonusCountChances = {
  one: 0.91,    // 91% - 1 бонус
  two: 0.07,    // 7% - 2 бонуса
  three: 0.02   // 2% - 3 бонуса
}

// Редкость бонусов при генерации
export const bonusRarityChances = {
  common: 0.60,
  uncommon: 0.30,
  rare: 0.10
}

// ================================
// ФУНКЦИИ
// ================================

/**
 * Получить бонус по ID
 */
export function getBonusById(id: UniqueBonusType): UniqueBonus | undefined {
  return uniqueBonuses.find(b => b.id === id)
}

/**
 * Получить бонусы по редкости
 */
export function getBonusesByRarity(rarity: 'common' | 'uncommon' | 'rare'): UniqueBonus[] {
  return uniqueBonuses.filter(b => b.rarity === rarity)
}

/**
 * Случайный выбор бонуса по редкости
 */
export function getRandomBonus(guildLevel: number = 1): UniqueBonus {
  const roll = Math.random()

  // Уровень гильдии увеличивает шанс редких бонусов
  const rareBonus = 0.02 * guildLevel
  const uncommonBonus = 0.03 * guildLevel

  const rareChance = bonusRarityChances.rare + rareBonus
  const uncommonChance = bonusRarityChances.uncommon + uncommonBonus

  if (roll < rareChance) {
    const rareBonuses = getBonusesByRarity('rare')
    return rareBonuses[Math.floor(Math.random() * rareBonuses.length)]
  } else if (roll < rareChance + uncommonChance) {
    const uncommonBonuses = getBonusesByRarity('uncommon')
    return uncommonBonuses[Math.floor(Math.random() * uncommonBonuses.length)]
  } else {
    const commonBonuses = getBonusesByRarity('common')
    return commonBonuses[Math.floor(Math.random() * commonBonuses.length)]
  }
}

/**
 * Генерация списка уникальных бонусов для искателя
 */
export function generateUniqueBonuses(guildLevel: number = 1): UniqueBonus[] {
  const roll = Math.random()

  let count: number
  if (roll < bonusCountChances.three) {
    count = 3
  } else if (roll < bonusCountChances.three + bonusCountChances.two) {
    count = 2
  } else {
    count = 1
  }

  const bonuses: UniqueBonus[] = []
  const usedIds = new Set<UniqueBonusType>()

  for (let i = 0; i < count; i++) {
    let bonus = getRandomBonus(guildLevel)
    let attempts = 0

    // Избегаем дубликатов
    while (usedIds.has(bonus.id) && attempts < 20) {
      bonus = getRandomBonus(guildLevel)
      attempts++
    }

    if (!usedIds.has(bonus.id)) {
      bonuses.push(bonus)
      usedIds.add(bonus.id)
    }
  }

  return bonuses
}

/**
 * Расчёт общих эффектов от всех бонусов
 */
export function calculateBonusEffects(bonuses: UniqueBonus[]) {
  const effects = {
    resourceChance: 0,
    resourceTypes: [] as string[],
    durationReduction: 0,
    wearReduction: 0,
    lossChanceReduction: 0,
    goldBonus: 0,
    soulBonus: 0,
    critChance: 0,
    critMultiplier: 1,
    successBonus: 0,
    essenceGuaranteed: 0,
    essenceChance: 0
  }

  for (const bonus of bonuses) {
    const e = bonus.effect

    if (e.resourceChance) {
      effects.resourceChance = Math.max(effects.resourceChance, e.resourceChance)
      effects.resourceTypes = [...new Set([...effects.resourceTypes, ...(e.resourceTypes || [])])]
    }
    if (e.durationReduction) {
      effects.durationReduction += e.durationReduction
    }
    if (e.wearReduction) {
      effects.wearReduction = Math.max(effects.wearReduction, e.wearReduction)
    }
    if (e.lossChanceReduction) {
      effects.lossChanceReduction = Math.max(effects.lossChanceReduction, e.lossChanceReduction)
    }
    if (e.goldBonus) {
      effects.goldBonus += e.goldBonus
    }
    if (e.soulBonus) {
      effects.soulBonus += e.soulBonus
    }
    if (e.critChance) {
      effects.critChance = Math.max(effects.critChance, e.critChance)
      effects.critMultiplier = e.critMultiplier || 2
    }
    if (e.successBonus) {
      effects.successBonus += e.successBonus
    }
    if (e.essenceGuaranteed) {
      effects.essenceGuaranteed += e.essenceGuaranteed
    }
    if (e.essenceChance) {
      effects.essenceChance = Math.max(effects.essenceChance, e.essenceChance)
    }
  }

  // Ограничения
  effects.durationReduction = Math.min(effects.durationReduction, 50) // Максимум -50% времени
  effects.successBonus = Math.min(effects.successBonus, 40) // Максимум +40% успеха

  return effects
}

/**
 * Получить текстовое описание редкости бонусов
 */
export function getBonusRarityText(bonuses: UniqueBonus[]): { text: string; color: string } {
  if (bonuses.length === 3) {
    return { text: 'Легенда', color: 'text-amber-400' }
  }
  if (bonuses.length === 2) {
    const hasRare = bonuses.some(b => b.rarity === 'rare')
    if (hasRare) {
      return { text: 'Избранный', color: 'text-purple-400' }
    }
    return { text: 'Талант', color: 'text-blue-400' }
  }

  const bonus = bonuses[0]
  if (!bonus) return { text: 'Обычный', color: 'text-stone-400' }

  switch (bonus.rarity) {
    case 'rare':
      return { text: 'Редкий дар', color: 'text-purple-400' }
    case 'uncommon':
      return { text: 'Особый дар', color: 'text-blue-400' }
    default:
      return { text: 'Дар', color: 'text-green-400' }
  }
}

/**
 * Получить цвет фона для бонуса по редкости
 */
export function getBonusBgColor(bonus: UniqueBonus): string {
  switch (bonus.rarity) {
    case 'rare':
      return 'bg-purple-900/40 border-purple-600/50'
    case 'uncommon':
      return 'bg-blue-900/40 border-blue-600/50'
    default:
      return 'bg-green-900/40 border-green-600/50'
  }
}

/**
 * Применить бонусы к результату экспедиции
 */
export function applyBonusesToResult(
  baseResult: {
    gold: number
    warSoul: number
    success: boolean
    weaponWear: number
    weaponLossChance: number
    duration: number
    successChance: number
  },
  bonuses: UniqueBonus[],
  skill: number
): {
  gold: number
  warSoul: number
  success: boolean
  weaponWear: number
  weaponLost: boolean
  duration: number
  successChance: number
  bonusResources: { resource: string; amount: number }[]
  bonusEssence: number
  isCrit: boolean
} {
  const effects = calculateBonusEffects(bonuses)

  // Применяем модификаторы
  let gold = Math.floor(baseResult.gold * (1 + effects.goldBonus / 100))
  let warSoul = Math.floor(baseResult.warSoul * (1 + (effects.soulBonus + skill) / 100))
  const duration = Math.floor(baseResult.duration * (1 - effects.durationReduction / 100))
  let successChance = Math.min(95, baseResult.successChance + effects.successBonus)
  const weaponWear = Math.floor(baseResult.weaponWear * (1 - effects.wearReduction / 100))
  const weaponLossChance = Math.floor(baseResult.weaponLossChance * (1 - effects.lossChanceReduction / 100))

  // Определяем успех
  const roll = Math.random() * 100
  const success = roll < successChance

  // Проверяем критический успех
  const isCrit = Math.random() * 100 < effects.critChance
  if (isCrit) {
    gold = Math.floor(gold * effects.critMultiplier)
    warSoul = Math.floor(warSoul * effects.critMultiplier)
  }

  // Проверяем потерю оружия
  const weaponLost = !success && Math.random() * 100 < weaponLossChance

  // Генерируем бонусные ресурсы
  const bonusResources: { resource: string; amount: number }[] = []
  if (effects.resourceChance > 0 && Math.random() * 100 < effects.resourceChance && success) {
    const types = effects.resourceTypes
    if (types.length > 0) {
      const resource = types[Math.floor(Math.random() * types.length)]
      const amount = 1 + Math.floor(Math.random() * 3) // 1-3 единицы
      bonusResources.push({ resource, amount })
    }
  }

  // Генерируем бонусную эссенцию
  let bonusEssence = effects.essenceGuaranteed
  if (effects.essenceChance > 0 && Math.random() * 100 < effects.essenceChance && success) {
    bonusEssence += 1
  }

  return {
    gold,
    warSoul,
    success,
    weaponWear,
    weaponLost,
    duration,
    successChance,
    bonusResources,
    bonusEssence,
    isCrit
  }
}

/**
 * Хук для синхронизации игры с сервером
 * Автоматическое сохранение и загрузка с поддержкой офлайн-режима
 */

import { useEffect, useCallback, useRef, useState } from 'react'
import { useGameStore } from '@/store'

interface UseCloudSaveOptions {
  autoSaveInterval?: number
  enableAutoSave?: boolean
  playerId?: string
}

interface CloudSaveResult {
  isLoading: boolean
  isSaving: boolean
  lastSavedAt: Date | null
  error: string | null
  isOnline: boolean
  save: () => Promise<boolean>
  load: () => Promise<boolean>
  reset: () => Promise<boolean>
}

// Хелпер для получения титула по уровню
function getTitleByLevel(level: number): string {
  const titles = [
    { min: 1, max: 4, title: 'Новичок' },
    { min: 5, max: 9, title: 'Ученик' },
    { min: 10, max: 14, title: 'Подмастерье' },
    { min: 15, max: 19, title: 'Опытный кузнец' },
    { min: 20, max: 29, title: 'Мастер-кузнец' },
    { min: 30, max: 39, title: 'Великий мастер' },
    { min: 40, max: 49, title: 'Легендарный мастер' },
    { min: 50, max: 999, title: 'Легенда' },
  ]

  for (const t of titles) {
    if (level >= t.min && level <= t.max) {
      return t.title
    }
  }
  return 'Новичок'
}

const OFFLINE_BACKUP_KEY = 'swordcraft-offline-backup'
const TIMESTAMP_KEY = 'swordcraft-last-save-timestamp'

export function useCloudSave(options: UseCloudSaveOptions = {}): CloudSaveResult {
  const { autoSaveInterval = 60000, enableAutoSave = true, playerId = 'demo-player' } = options

  const [isLoading, setIsLoading] = useState(true)
  const [isSaving, setIsSaving] = useState(false)
  const [lastSavedAt, setLastSavedAt] = useState<Date | null>(null)
  const [error, setError] = useState<string | null>(null)
  const [isOnline, setIsOnline] = useState(navigator.onLine)

  const isLoadingRef = useRef(false)

  // Отслеживаем состояние сети
  useEffect(() => {
    const handleOnline = () => setIsOnline(navigator.onLine)
    window.addEventListener('online', handleOnline)
    window.addEventListener('offline', handleOnline)
    return () => {
      window.removeEventListener('online', handleOnline)
      window.removeEventListener('offline', handleOnline)
    }
  }, [])

  // Сбор данных для сохранения
  const collectSaveData = useCallback(() => {
    const state = useGameStore.getState()

    return {
      timestamp: Date.now(),
      player: {
        level: state.player?.level || 1,
        experience: state.player?.experience || 0,
        fame: state.player?.fame || 1,
      },
      resources: state.resources || {},
      statistics: state.statistics || {},
      workers: state.workers || [],
      buildings: state.buildings || [],
      maxWorkers: state.maxWorkers || 3,
      activeCraft: state.activeCraft || {},
      activeRefining: state.activeRefining || {},
      weaponInventory: state.weaponInventory || { weapons: [] },
      unlockedRecipes: state.unlockedRecipes || { weaponRecipes: [], refiningRecipes: [] },
      recipeSources: state.recipeSources || [],
      unlockedEnchantments: state.unlockedEnchantments || [],
      guild: state.guild || {},
      knownAdventurers: state.knownAdventurers || [],
      orders: state.orders || [],
      tutorial: state.tutorial || { isActive: true, currentStep: 0 },
      playTime: state.statistics?.playTime || 0,
      craftV2Persisted: state.craftV2Persisted || null,
      saveVersion: 3,
    }
  }, [])

  // Сохранение в localStorage (офлайн-бэкап)
  const saveToLocalStorage = useCallback((data: any) => {
    try {
      localStorage.setItem(OFFLINE_BACKUP_KEY, JSON.stringify(data))
      localStorage.setItem(TIMESTAMP_KEY, data.timestamp.toString())
    } catch (e) {
      console.error('[CloudSave] Failed to save to localStorage:', e)
    }
  }, [])

  // Загрузка из localStorage
  const loadFromLocalStorage = useCallback(() => {
    try {
      const backup = localStorage.getItem(OFFLINE_BACKUP_KEY)
      if (backup) {
        return JSON.parse(backup)
      }
    } catch (e) {
      console.error('[CloudSave] Failed to load from localStorage:', e)
    }
    return null
  }, [])

  // Применение загруженных данных
  const applyLoadedData = useCallback((data: any) => {
    const level = data.level || 1

    useGameStore.setState({
      player: {
        name: 'Кузнец',
        level: level,
        experience: data.experience || 0,
        experienceToNextLevel: Math.floor(100 * Math.pow(1.5, level - 1)),
        fame: data.fame || 0,
        title: getTitleByLevel(level),
      },
      resources: data.resources || {},
      statistics: data.statistics || {},
      workers: data.workers || [],
      buildings: data.buildings || [],
      maxWorkers: data.maxWorkers || 3,
      activeCraft: data.activeCraft || {},
      activeRefining: data.activeRefining || {},
      weaponInventory: data.weaponInventory || { weapons: [] },
      unlockedRecipes: data.unlockedRecipes || { weaponRecipes: [], refiningRecipes: [] },
      recipeSources: data.recipeSources || [],
      unlockedEnchantments: data.unlockedEnchantments || [],
      guild: data.guild || {},
      knownAdventurers: data.knownAdventurers || [],
      orders: data.orders || [],
      tutorial: data.tutorial || { isActive: true, currentStep: 0 },
      craftV2Persisted: data.craftV2Persisted || null,
    })
  }, [])

  // Сохранение
  const save = useCallback(async (): Promise<boolean> => {
    if (isSaving) return false

    setIsSaving(true)
    setError(null)

    const saveData = collectSaveData()

    // Всегда сохраняем в localStorage как бэкап
    saveToLocalStorage(saveData)

    // Если онлайн - сохраняем на сервер
    if (isOnline) {
      try {
        const response = await fetch('/api/save', {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            'x-player-id': playerId,
          },
          body: JSON.stringify(saveData),
        })

        const result = await response.json()

        if (result.success) {
          setLastSavedAt(new Date())
          console.log('[CloudSave] Saved to server successfully')
          return true
        } else {
          setError(result.error || 'Save failed')
          return false
        }
      } catch (err) {
        setError(err instanceof Error ? err.message : 'Network error')
        console.error('[CloudSave] Server save error:', err)
        return false
      } finally {
        setIsSaving(false)
      }
    } else {
      // Офлайн - сохранено только в localStorage
      console.log('[CloudSave] Offline - saved to localStorage')
      setLastSavedAt(new Date())
      setIsSaving(false)
      return true
    }
  }, [collectSaveData, isOnline, isSaving, playerId, saveToLocalStorage])

  // Загрузка
  const load = useCallback(async (): Promise<boolean> => {
    if (isLoadingRef.current) return false

    isLoadingRef.current = true
    setIsLoading(true)
    setError(null)

    let loadedData: any = null
    let source = 'none'

    try {
      // Сначала пробуем загрузить с сервера
      if (isOnline) {
        const response = await fetch('/api/save', {
          method: 'GET',
          headers: {
            'x-player-id': playerId,
          },
        })

        const result = await response.json()

        if (result.success && result.data) {
          loadedData = result.data
          source = 'server'
        }
      }

      // Проверяем localStorage на наличие более свежего офлайн-сохранения
      const localBackup = loadFromLocalStorage()
      if (localBackup && localBackup.timestamp) {
        if (!loadedData || localBackup.timestamp > (loadedData.timestamp || 0)) {
          loadedData = localBackup
          source = 'local'
          console.log('[CloudSave] Using newer local backup')
        }
      }

      // Применяем данные
      if (loadedData) {
        applyLoadedData(loadedData)
        console.log(`[CloudSave] Loaded from ${source}, timestamp:`, new Date(loadedData.timestamp))
        return true
      }

      return false
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Load error')
      console.error('[CloudSave] Load error:', err)

      // Пробуем загрузить из localStorage как fallback
      const localBackup = loadFromLocalStorage()
      if (localBackup) {
        applyLoadedData(localBackup)
        console.log('[CloudSave] Loaded from local backup as fallback')
        return true
      }

      return false
    } finally {
      setIsLoading(false)
      isLoadingRef.current = false
    }
  }, [applyLoadedData, isOnline, loadFromLocalStorage, playerId])

  // Сброс
  const reset = useCallback(async (): Promise<boolean> => {
    try {
      const response = await fetch('/api/save', {
        method: 'DELETE',
        headers: {
          'x-player-id': playerId,
        },
      })

      const result = await response.json()

      if (result.success) {
        localStorage.removeItem(OFFLINE_BACKUP_KEY)
        localStorage.removeItem(TIMESTAMP_KEY)
        window.location.reload()
        return true
      }
      return false
    } catch (err) {
      console.error('[CloudSave] Reset error:', err)
      return false
    }
  }, [playerId])

  // Загрузка при монтировании (только один раз)
  const loadRef = useRef(load)
  loadRef.current = load
  useEffect(() => {
    loadRef.current()
  }, [])

  // Автосохранение
  useEffect(() => {
    if (!enableAutoSave) return

    const interval = setInterval(() => {
      save()
    }, autoSaveInterval)

    return () => clearInterval(interval)
  }, [enableAutoSave, autoSaveInterval, save])

  // Сохранение при закрытии страницы
  useEffect(() => {
    const handleBeforeUnload = () => {
      const saveData = collectSaveData()
      saveToLocalStorage(saveData)

      if (isOnline) {
        const blob = new Blob([JSON.stringify(saveData)], { type: 'application/json' })
        navigator.sendBeacon('/api/save', blob)
      }
    }

    window.addEventListener('beforeunload', handleBeforeUnload)
    return () => window.removeEventListener('beforeunload', handleBeforeUnload)
  }, [collectSaveData, isOnline, saveToLocalStorage])

  return {
    isLoading,
    isSaving,
    lastSavedAt,
    error,
    isOnline,
    save,
    load,
    reset,
  }
}

export type { CloudSaveResult, UseCloudSaveOptions }

/**
 * Хук для системы крафта v2
 * Управление состоянием крафта с этапами
 * Состояние синхронизируется с Zustand store для персистентности
 * 
 * @see docs/CRAFT_SYSTEM_CONCEPT.md
 */

import { useState, useCallback, useRef, useEffect } from 'react'
import type { 
  ActiveCraftV2, 
  CraftPlan, 
  CraftStageInstance, 
  CraftedWeaponV2,
  MaterialAssignment 
} from '@/types/craft-v2'
import { 
  generateCraftStages, 
  createCraftPlan 
} from '@/lib/craft/process-generator'
import { 
  calculateWeapon, 
  type WeaponCalculationResult 
} from '@/lib/craft/calculator'
import { 
  generateWeaponName, 
  type WeaponNameResult 
} from '@/lib/craft/name-generator'
import { getRecipeById } from '@/data/recipes'
import { getMaterialAsLegacy } from '@/data/materials'
import { getTechniqueById } from '@/data/techniques'
import { useGameStore } from '@/store/game-store-composed'
import { getQualityRank } from '@/types/craft-v2'

// ================================
// ТИПЫ
// ================================

export interface CraftV2State {
  /** Текущий план крафта */
  plan: CraftPlan | null

  /** Активный процесс */
  activeCraft: ActiveCraftV2 | null

  /** Готовое оружие */
  completedWeapon: CraftedWeaponV2 | null

  /** Предварительный расчёт */
  preview: WeaponCalculationResult | null

  /** Имя оружия */
  weaponName: WeaponNameResult | null

  /** Стадия UI */
  stage: 'planning' | 'crafting' | 'completed'

  /** Нужно ли закупать материалы */
  shouldPurchaseMaterials: boolean
}

export interface UseCraftV2Return {
  // State
  state: CraftV2State

  // Planning actions
  setRecipe: (recipeId: string) => void
  setMaterial: (partId: string, materialId: string, quantity: number) => void
  setTechniques: (techniqueIds: string[]) => void
  calculatePreview: () => void

  // Craft actions
  startCraft: () => void
  setShouldPurchaseMaterials: (should: boolean) => void  // Добавил для галочки закупки
  cancelCraft: () => void
  instantComplete: () => void  // Тестовая функция мгновенного завершения

  // Result actions
  collectWeapon: () => CraftedWeaponV2 | null
  reset: () => void
}

// ================================
// НАЧАЛЬНОЕ СОСТОЯНИЕ
// ================================

const initialState: CraftV2State = {
  plan: null,
  activeCraft: null,
  completedWeapon: null,
  preview: null,
  weaponName: null,
  stage: 'planning',
  shouldPurchaseMaterials: false,
}

function getRestoredState(): CraftV2State {
  const persisted = useGameStore.getState().craftV2Persisted
  if (!persisted || (!persisted.activeCraft && !persisted.completedWeapon)) {
    return initialState
  }
  return {
    plan: persisted.plan || null,
    activeCraft: persisted.activeCraft || null,
    completedWeapon: persisted.completedWeapon || null,
    preview: persisted.preview || null,
    weaponName: persisted.weaponName || null,
    stage: persisted.stage || 'planning',
  }
}

// ================================
// ХУК
// ================================

export function useCraftV2(
  blacksmithLevel: number = 1,
  forgeLevel: number = 1
): UseCraftV2Return {
  const [state, setStateRaw] = useState<CraftV2State>(() => getRestoredState())
  const setCraftV2Persisted = useGameStore(s => s.setCraftV2Persisted)

  const setState = useCallback((updater: CraftV2State | ((prev: CraftV2State) => CraftV2State)) => {
    setStateRaw(prev => {
      const next = typeof updater === 'function' ? updater(prev) : updater
      return next
    })
  }, [])

  // Принудительная синхронизация перед закрытием страницы
  const stateRef = useRef(state)
  stateRef.current = state
  useEffect(() => {
    const handleBeforeUnload = () => {
      const s = stateRef.current
      useGameStore.getState().setCraftV2Persisted({
        activeCraft: s.activeCraft,
        plan: s.plan,
        completedWeapon: s.completedWeapon,
        stage: s.stage,
        preview: s.preview,
        weaponName: s.weaponName,
      })
    }
    window.addEventListener('beforeunload', handleBeforeUnload)
    return () => window.removeEventListener('beforeunload', handleBeforeUnload)
  }, [])

  // Синхронизация состояния в Zustand при изменении stage или completedWeapon
  // НЕ синхронизируем activeCraft каждые 100мс (это вызвало бы лишние ре-рендеры)
  // Вместо этого синхронизируем только при смене стадии
  const prevStageRef = useRef(state.stage)
  useEffect(() => {
    const stageChanged = prevStageRef.current !== state.stage
    prevStageRef.current = state.stage

    if (stageChanged || !state.activeCraft) {
      setCraftV2Persisted({
        activeCraft: state.activeCraft,
        plan: state.plan,
        completedWeapon: state.completedWeapon,
        stage: state.stage,
        preview: state.preview,
        weaponName: state.weaponName,
      })
    }
  }, [state.stage, state.completedWeapon, state.activeCraft, state.plan, state.preview, state.weaponName, setCraftV2Persisted])

  // Refs для отложенных обновлений
  const materialsRef = useRef<MaterialAssignment>(
    state.plan?.materials || {}
  )
  const techniquesRef = useRef<string[]>(
    state.plan?.techniques || []
  )
  const recipeIdRef = useRef<string | null>(
    state.plan?.recipeId || null
  )

  // ================================
  // PLANNING ACTIONS
  // ================================

  const setRecipe = useCallback((recipeId: string) => {
    recipeIdRef.current = recipeId
    materialsRef.current = {}
    techniquesRef.current = []

    const recipe = getRecipeById(recipeId)
    if (!recipe) {
      setState(prev => ({ ...prev, plan: null, preview: null, weaponName: null }))
      return
    }

    const emptyPlan: CraftPlan = {
      recipeId,
      materials: {},
      techniques: [],
      estimatedTime: 0,
      estimatedStats: {
        attack: 0,
        durability: 0,
        maxDurability: 0,
        weight: 0,
        balance: 0,
        soulCapacity: 0,
        repairPotential: 1,
        enchantSlots: 0,
        enchantPower: 1,
      },
      estimatedQuality: 'common',
    }

    setState(prev => ({
      ...prev,
      plan: emptyPlan,
      preview: null,
      weaponName: null,
      stage: 'planning',
    }))
  }, [setState])

  const setMaterial = useCallback((partId: string, materialId: string, quantity: number) => {
    materialsRef.current = {
      ...materialsRef.current,
      [partId]: { materialId, quantity },
    }

    setState(prev => {
      if (!prev.plan) return prev

      const updatedPlan = {
        ...prev.plan,
        materials: materialsRef.current,
      }

      return { ...prev, plan: updatedPlan }
    })
  }, [setState])

  const setTechniques = useCallback((techniqueIds: string[]) => {
    techniquesRef.current = techniqueIds

    setState(prev => {
      if (!prev.plan) return prev

      const updatedPlan = {
        ...prev.plan,
        techniques: techniqueIds,
      }

      return { ...prev, plan: updatedPlan }
    })
  }, [setState])

  const calculatePreview = useCallback(() => {
    const recipeId = recipeIdRef.current
    const materials = materialsRef.current
    const techniqueIds = techniquesRef.current

    if (!recipeId || Object.keys(materials).length === 0) {
      setState(prev => ({ ...prev, preview: null, weaponName: null }))
      return
    }

    const recipe = getRecipeById(recipeId)
    if (!recipe) return

    const techniques = techniqueIds
      .map(id => getTechniqueById(id))
      .filter((t): t is NonNullable<typeof t> => t !== undefined)

    const combatPart = recipe.combatPart
    const combatMaterialId = materials[combatPart]?.materialId
    const combatMaterial = combatMaterialId ? getMaterialAsLegacy(combatMaterialId) : null

    const preview = calculateWeapon(recipe, materials, techniques, blacksmithLevel)
    const weaponName = generateWeaponName(recipe, combatMaterial || null, preview.quality)

    const stages = generateCraftStages(recipe, materials, techniques, blacksmithLevel, forgeLevel)
    const estimatedTime = stages.reduce((sum, s) => sum + s.calculatedDuration, 0)

    setState(prev => ({
      ...prev,
      preview,
      weaponName,
      plan: prev.plan ? {
        ...prev.plan,
        materials,
        techniques: techniqueIds,
        estimatedTime,
        estimatedStats: preview.stats,
        estimatedQuality: preview.qualityGrade,
      } : null,
    }))
  }, [blacksmithLevel, forgeLevel, setState])

  // ================================
  // CRAFT ACTIONS
  // ================================

  const startCraft = useCallback(() => {
    const recipeId = recipeIdRef.current
    const materials = materialsRef.current
    const techniqueIds = techniquesRef.current
    const shouldPurchase = state.shouldPurchaseMaterials

    if (!recipeId || Object.keys(materials).length === 0) {
      console.warn('Cannot start craft: missing recipe or materials')
      return
    }

    const recipe = getRecipeById(recipeId)
    if (!recipe) return

    const techniques = techniqueIds
      .map(id => getTechniqueById(id))
      .filter((t): t is NonNullable<typeof t> => t !== undefined)

    const stages = generateCraftStages(recipe, materials, techniques, blacksmithLevel, forgeLevel, undefined, shouldPurchase)
    const plan = createCraftPlan(recipeId, materials, techniqueIds, blacksmithLevel, forgeLevel, shouldPurchase)

    const activeCraft: ActiveCraftV2 = {
      id: `craft_${Date.now()}`,
      plan,
      stages,
      currentStageIndex: 0,
      startTime: Date.now(),
      totalDuration: stages.reduce((sum, s) => sum + s.calculatedDuration, 0),
      elapsedTime: 0,
      status: 'running',
      log: [{
        timestamp: Date.now(),
        stageId: 'start',
        stageName: 'Начало крафта',
        message: `Начинаю создание ${recipe.name}`,
        type: 'start',
      }],
    }

    if (stages.length > 0) {
      stages[0].status = 'in_progress'
      stages[0].startTime = Date.now()
    }

    setState(prev => ({
      ...prev,
      activeCraft,
      stage: 'crafting',
    }))
  }, [blacksmithLevel, forgeLevel, setState])

  const setShouldPurchaseMaterials = useCallback((should: boolean) => {
    setState(prev => ({ ...prev, shouldPurchaseMaterials: should }))
  }, [setState])

  const cancelCraft = useCallback(() => {
    setState(prev => ({
      ...prev,
      activeCraft: null,
      stage: 'planning',
    }))
  }, [setState])

  // ================================
  // INSTANT COMPLETE (для тестирования)
  // ================================

  const instantComplete = useCallback(() => {
    if (state.stage !== 'crafting' || !state.activeCraft) return

    // Устанавливаем elapsedTime больше totalDuration для мгновенного завершения
    const totalDurationMs = state.activeCraft.totalDuration * 1000

    setState(prev => {
      if (!prev.activeCraft || prev.stage !== 'crafting') return prev

      const craft = { ...prev.activeCraft }
      craft.elapsedTime = totalDurationMs + 1000 // +1 секунда для гарантии
      craft.status = 'completed'

      // Помечаем все этапы как завершенные
      craft.stages = craft.stages.map(stage => ({
        ...stage,
        status: 'completed' as const,
        progress: 100,
      }))
      craft.currentStageIndex = craft.stages.length - 1

      // Создаем оружие если есть данные
      if (prev.preview && prev.weaponName && prev.plan) {
        const recipe = getRecipeById(prev.plan.recipeId)

        // Генерируем уникальный ID: w_timestamp_random
        const uniqueId = `w_${Date.now()}_${Math.random().toString(36).substring(2, 8)}`

        // Получаем combatMaterialId для hiddenTags
        const recipeData = getRecipeById(prev.plan.recipeId)
        const combatPart = recipeData?.combatPart || 'blade'
        const combatMatId = prev.plan.materials[combatPart]?.materialId || 'unknown'

        // Генерируем hiddenTags
        const hiddenTags = [
          recipe?.type || 'sword',
          combatMatId,
          `q:${Math.floor(prev.preview.quality)}`,
          `rank:${prev.weaponName.qualityRank || 'F'}`,
        ]

        const completedWeapon: CraftedWeaponV2 = {
          id: uniqueId,
          recipeId: prev.plan.recipeId,
          prefix: prev.weaponName.prefix,
          baseName: prev.weaponName.baseName,
          suffix: prev.weaponName.suffix,
          fullName: prev.weaponName.fullName,
          type: recipe?.type || 'sword',
          tier: recipe?.baseStats ? Math.ceil(prev.preview.stats.attack / 20) : 1,
          materials: prev.preview.materials,
          stats: prev.preview.stats,
          quality: prev.preview.quality,
          qualityGrade: prev.preview.qualityGrade,
          qualityRank: prev.weaponName.qualityRank || getQualityRank(prev.preview.quality),
          warSoul: 0,
          maxWarSoul: prev.preview.stats.soulCapacity,
          createdAt: Date.now(),
          adventureCount: 0,
          sellPrice: prev.preview.sellPrice,
          hiddenTags,
          combatMaterialId: combatMatId,
          currentDurability: prev.preview.stats.durability,
          epicMultiplier: 1.0,
          techniquesUsed: prev.plan.techniques,
        }

        return {
          ...prev,
          activeCraft: null,
          completedWeapon,
          stage: 'completed' as const,
        }
      }

      return prev
    })
  }, [state.stage, state.activeCraft, setState])

  // ================================
  // RESULT ACTIONS
  // ================================

  const collectWeapon = useCallback(() => {
    const { completedWeapon, preview, weaponName, plan } = state

    if (!completedWeapon || !preview || !weaponName || !plan) return null

    setState(prev => ({
      ...prev,
      completedWeapon: null,
      stage: 'planning',
    }))

    return completedWeapon
  }, [state, setState])

  const reset = useCallback(() => {
    materialsRef.current = {}
    techniquesRef.current = []
    recipeIdRef.current = null
    setState(initialState)
  }, [setState])

  // ================================
  // GAME LOOP (для прогресса крафта)
  // ================================

  useEffect(() => {
    if (state.stage !== 'crafting' || !state.activeCraft) return

    const interval = setInterval(() => {
      setState(prev => {
        if (!prev.activeCraft || prev.stage !== 'crafting') return prev

        const craft = { ...prev.activeCraft }
        const elapsed = Date.now() - craft.startTime
        craft.elapsedTime = elapsed

        let accumulatedTime = 0
        let currentStageFound = false

        for (let i = 0; i < craft.stages.length; i++) {
          const stage = craft.stages[i]
          const stageDuration = stage.calculatedDuration * 1000

          if (accumulatedTime + stageDuration > elapsed) {
            craft.currentStageIndex = i

            const elapsedInStage = elapsed - accumulatedTime
            craft.stages = [...craft.stages]
            craft.stages[i] = {
              ...stage,
              progress: Math.min(100, (elapsedInStage / stageDuration) * 100),
            }
            currentStageFound = true
            break
          }

          if (stage.status !== 'completed') {
            craft.stages = [...craft.stages]
            craft.stages[i] = {
              ...stage,
              status: 'completed',
              progress: 100,
            }
          }

          accumulatedTime += stageDuration
        }

        if (!currentStageFound && craft.stages.length > 0) {
          craft.status = 'completed'

          if (prev.preview && prev.weaponName && prev.plan) {
            const recipe = getRecipeById(prev.plan.recipeId)

            // Генерируем уникальный ID: w_timestamp_random
            const uniqueId = `w_${Date.now()}_${Math.random().toString(36).substring(2, 8)}`

            // Получаем combatMaterialId для hiddenTags
            const recipeData = getRecipeById(prev.plan.recipeId)
            const combatPart = recipeData?.combatPart || 'blade'
            const combatMatId = prev.plan.materials[combatPart]?.materialId || 'unknown'

            // Генерируем hiddenTags
            const hiddenTags = [
              recipe?.type || 'sword',                              // тип оружия
              combatMatId,                                          // материал combatPart
              `q:${Math.floor(prev.preview.quality)}`,              // качество числом
              `rank:${prev.weaponName.qualityRank || 'F'}`,         // ранг качества
            ]

            const completedWeapon: CraftedWeaponV2 = {
              id: uniqueId,
              recipeId: prev.plan.recipeId,
              prefix: prev.weaponName.prefix,
              baseName: prev.weaponName.baseName,
              suffix: prev.weaponName.suffix,
              fullName: prev.weaponName.fullName,
              type: recipe?.type || 'sword',
              tier: recipe?.baseStats ? Math.ceil(prev.preview.stats.attack / 20) : 1,
              materials: prev.preview.materials,
              stats: prev.preview.stats,
              quality: prev.preview.quality,
              qualityGrade: prev.preview.qualityGrade,
              qualityRank: prev.weaponName.qualityRank || getQualityRank(prev.preview.quality),
              warSoul: 0,
              maxWarSoul: prev.preview.stats.soulCapacity,
              createdAt: Date.now(),
              adventureCount: 0,
              sellPrice: prev.preview.sellPrice,
              // Скрытые теги для системы заказов
              hiddenTags,
              combatMaterialId: combatMatId,
              // Runtime-поля
              currentDurability: prev.preview.stats.durability,
              epicMultiplier: 1.0,
              techniquesUsed: prev.plan.techniques,
            }

            return {
              ...prev,
              activeCraft: null,
              completedWeapon,
              stage: 'completed' as const,
            }
          }
        }

        return { ...prev, activeCraft: craft }
      })
    }, 100)

    return () => clearInterval(interval)
  }, [state.stage, state.activeCraft, setState])

  // ================================
  // RETURN
  // ================================

  return {
    state,
    setRecipe,
    setMaterial,
    setTechniques,
    calculatePreview,
    startCraft,
    setShouldPurchaseMaterials,
    cancelCraft,
    instantComplete,  // Тестовая функция мгновенного завершения
    collectWeapon,
    reset,
  }
}

export default useCraftV2

'use client'

import { useEffect, useRef, useCallback, useMemo } from 'react'
import { useGameStore, Worker, ProductionBuilding, workerClassData, WorkerClass } from '@/store'
import { refiningRecipes } from '@/data/refining-recipes'

// Частота обновления игры (в мс)
const TICK_RATE = 100 // 10 тиков в секунду для плавности

// Балансовые константы
const BALANCE = {
  // Базовый расход стамины в секунду (было 0.5)
  BASE_STAMINA_DRAIN: 0.15,

  // Множитель расхода от сложности здания
  STAMINA_COST_MULTIPLIER: 0.05,

  // Базовое восстановление стамины в секунду при отдыхе (было 2)
  BASE_STAMINA_RECOVERY: 0.5,

  // Порог автоперехода на отдых
  AUTO_REST_THRESHOLD: 5,

  // Порог предупреждения о низкой выносливости (в процентах)
  LOW_STAMINA_WARNING_PERCENT: 25,
}

// Коэффициенты расхода стамины для разных классов на разных работах
// Классы лучше работают на своих специальностях
const CLASS_STAMINA_MODIFIERS: Partial<Record<WorkerClass, Partial<Record<string, number>>>> = {
  loggers: { sawmill: 0.6 },      // Дровосеки медленнее тратят стамину на лесопилке
  mason: { quarry: 0.6 },          // Каменщики на каменоломне
  miner: {                         // Шахтёры на шахтах
    iron_mine: 0.6, 
    coal_mine: 0.6,
    copper_mine: 0.6,
    tin_mine: 0.6,
    silver_mine: 0.6,
    gold_mine: 0.6,
  },
  smelter: {                       // Плавильщики
    iron_mine: 0.7,
    coal_mine: 0.7,
  },
}

export function useGameLoop() {
  const lastTickRef = useRef<number>(Date.now())
  const offlineProgressCalculatedRef = useRef<boolean>(false)

  // Используем индивидуальные селекторы (Zustand оптимизирован для этого)
  const addResource = useGameStore((state) => state.addResource)
  const workers = useGameStore((state) => state.workers)
  const buildings = useGameStore((state) => state.buildings)
  const updateWorkerStamina = useGameStore((state) => state.updateWorkerStamina)
  const addWorkerExperience = useGameStore((state) => state.addWorkerExperience)
  const updateBuildingProgress = useGameStore((state) => state.updateBuildingProgress)
  const assignWorker = useGameStore((state) => state.assignWorker)
  const addExperience = useGameStore((state) => state.addExperience)

  // Переработка и крафт
  const activeRefining = useGameStore((state) => state.activeRefining)
  const updateRefiningProgress = useGameStore((state) => state.updateRefiningProgress)
  const completeRefining = useGameStore((state) => state.completeRefiningWithResources)

  // Расчёт расхода стамины для рабочего на конкретном здании
  const getStaminaDrain = useCallback((worker: Worker, building: ProductionBuilding): number => {
    const baseDrain = BALANCE.BASE_STAMINA_DRAIN
    const buildingModifier = building.staminaCost * BALANCE.STAMINA_COST_MULTIPLIER

    // Классовый бонус/штраф
    const classModifier = CLASS_STAMINA_MODIFIERS[worker.class]?.[building.id] ?? 1.0

    // Выносливость рабочего влияет на расход (более выносливые тратят меньше)
    const staminaEfficiency = 1 - (worker.stats.stamina_max - 80) / 200 // -20% для 120 стамины

    return (baseDrain + buildingModifier) * classModifier * Math.max(0.7, staminaEfficiency)
  }, [])

  // Расчёт производительности здания
  const calculateBuildingProduction = useCallback((building: ProductionBuilding) => {
    // Находим рабочих, назначенных на это здание
    const assignedWorkers = workers.filter(w => w.assignment === building.id && w.stamina > 0)

    if (assignedWorkers.length === 0) return { rate: 0, efficiency: 0, workersWithStamina: 0 }

    // Базовая производительность здания
    const baseRate = building.baseProduction

    // Модификатор от рабочих
    const workerModifier = assignedWorkers.reduce((sum, worker) => {
      // Скорость влияет на производительность
      const speedBonus = worker.stats.speed / 100

      // Выносливость влияет на эффективность (линейно от 100% до 20% стамины)
      const staminaFactor = Math.max(0.2, worker.stamina / 100)

      // Уровень даёт небольшой бонус
      const levelBonus = 1 + (worker.level - 1) * 0.05

      // Классовый бонус на специфических работах
      const classBonus = getClassProductionBonus(worker.class, building.id)

      return sum + speedBonus * staminaFactor * levelBonus * classBonus
    }, 0)

    // Эффективность (отношение реальных рабочих к требуемым)
    const efficiency = Math.min(1, assignedWorkers.length / building.requiredWorkers)

    // Итоговая скорость
    const rate = baseRate * workerModifier * efficiency

    return { rate, efficiency, workersWithStamina: assignedWorkers.length }
  }, [workers])

  // Основной игровой цикл
  const gameTick = useCallback((deltaMs: number) => {
    const deltaSeconds = deltaMs / 1000

    // Обработка каждого здания
    buildings.forEach(building => {
      const { rate, efficiency, workersWithStamina } = calculateBuildingProduction(building)

      if (rate > 0 && workersWithStamina > 0) {
        // Добавляем ресурсы
        const amount = rate * deltaSeconds
        addResource(building.produces, amount)

        // Обновляем прогресс здания
        updateBuildingProgress(building.id, efficiency)

        // Снижаем выносливость рабочих и даём опыт
        const assignedWorkers = workers.filter(w => w.assignment === building.id)
        assignedWorkers.forEach(worker => {
          if (worker.stamina > 0) {
            const drain = getStaminaDrain(worker, building) * deltaSeconds
            const newStamina = worker.stamina - drain

            // Даём опыт за работу (медленно, растянуто)
            // 0.01-0.03 опыта за тик в зависимости от сложности работы
            const expGain = 0.01 + (building.staminaCost * 0.005)
            addWorkerExperience(worker.id, expGain * deltaSeconds)

            // Автопереход на отдых при низкой выносливости
            if (newStamina < BALANCE.AUTO_REST_THRESHOLD) {
              assignWorker(worker.id, 'rest')
            } else {
              updateWorkerStamina(worker.id, -drain)
            }
          }
        })

        // Добавляем опыт игроку (медленнее)
        if (Math.random() < 0.05) { // 5% шанс за тик
          addExperience(0.05)
        }
      }
    })

    // Восстановление выносливости для отдыхающих рабочих
    workers
      .filter(w => w.assignment === 'rest' && w.stamina < w.stats.stamina_max)
      .forEach(worker => {
        // Восстановление зависит от максимальной стамины (больше стамины = дольше восстановление)
        const recoveryRate = BALANCE.BASE_STAMINA_RECOVERY * (80 / worker.stats.stamina_max)
        const recovery = recoveryRate * deltaSeconds
        updateWorkerStamina(worker.id, recovery)
      })

    // Обработка прогресса переработки
    if (activeRefining.recipeId && activeRefining.endTime) {
      const now = Date.now()
      const totalTime = activeRefining.endTime - (activeRefining.startTime || now)
      const elapsed = now - (activeRefining.startTime || now)
      const progress = Math.min(100, (elapsed / totalTime) * 100)

      updateRefiningProgress(progress)

      if (progress >= 100) {
        completeRefining()
      }
    }

  }, [buildings, workers, calculateBuildingProduction, addResource, updateWorkerStamina, addWorkerExperience, updateBuildingProgress, addExperience, assignWorker, getStaminaDrain, activeRefining, updateRefiningProgress, completeRefining])

  // Запуск игрового цикла
  useEffect(() => {
    const intervalId = setInterval(() => {
      const now = Date.now()
      const delta = now - lastTickRef.current
      lastTickRef.current = now

      // Ограничиваем delta для предотвращения больших скачков
      const clampedDelta = Math.min(delta, 1000)

      gameTick(clampedDelta)
    }, TICK_RATE)

    return () => clearInterval(intervalId)
  }, [gameTick])

  // Обработка офлайн-прогресса при загрузке (только один раз)
  useEffect(() => {
    // Пропускаем, если уже рассчитали
    if (offlineProgressCalculatedRef.current) return
    offlineProgressCalculatedRef.current = true

    const lastSession = localStorage.getItem('swordcraft-last-session')
    if (lastSession) {
      const lastTime = parseInt(lastSession, 10)
      const now = Date.now()
      const offlineMs = now - lastTime

      // Ограничиваем офлайн-прогресс до 8 часов
      const maxOfflineMs = 8 * 60 * 60 * 1000
      const clampedOfflineMs = Math.min(offlineMs, maxOfflineMs)

      if (clampedOfflineMs > 60000) { // Больше минуты
        console.log(`Calculating offline progress: ${Math.round(clampedOfflineMs / 60000)} minutes`)
        gameTick(clampedOfflineMs)
      }
    }

    // Сохраняем время сессии при закрытии
    const handleBeforeUnload = () => {
      localStorage.setItem('swordcraft-last-session', Date.now().toString())
    }

    window.addEventListener('beforeunload', handleBeforeUnload)
    return () => window.removeEventListener('beforeunload', handleBeforeUnload)
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []) // Пустой массив - запускается только один раз при монтировании

  return {
    calculateBuildingProduction,
    getStaminaDrain,
  }
}

// Классовые бонусы к производительности на специфических работах
function getClassProductionBonus(workerClass: WorkerClass, buildingId: string): number {
  const bonuses: Partial<Record<WorkerClass, Partial<Record<string, number>>>> = {
    loggers: { sawmill: 1.3 },      // Дровосеки +30% на лесопилке
    mason: { quarry: 1.3 },          // Каменщики +30% на каменоломне
    miner: {                         // Шахтёры +25% на шахтах
      iron_mine: 1.25, 
      coal_mine: 1.25,
      copper_mine: 1.25,
      tin_mine: 1.25,
      silver_mine: 1.25,
      gold_mine: 1.25,
    },
    smelter: {                       // Плавильщики +20% на рудниках
      iron_mine: 1.2,
      coal_mine: 1.2,
    },
    blacksmith: { forge: 1.4 },      // Кузнецы +40% в кузнице
    apprentice: {                    // Ученики везде по чуть-чуть
      sawmill: 1.1,
      quarry: 1.1,
      iron_mine: 1.05,
      coal_mine: 1.05,
    },
  }

  return bonuses[workerClass]?.[buildingId] ?? 1.0
}

// Хук для получения текущих скоростей производства
export function useProductionRates() {
  // Используем индивидуальные селекторы
  const workers = useGameStore((state) => state.workers)
  const buildings = useGameStore((state) => state.buildings)

  return useMemo(() => {
    const rates: Record<string, number> = {}

    buildings.forEach(building => {
      const assignedWorkers = workers.filter(w => w.assignment === building.id && w.stamina > 0)

      if (assignedWorkers.length === 0) {
        rates[building.produces] = rates[building.produces] || 0
        return
      }

      const baseRate = building.baseProduction
      const workerModifier = assignedWorkers.reduce((sum, worker) => {
        const speedBonus = worker.stats.speed / 100
        const staminaFactor = Math.max(0.2, worker.stamina / 100)
        const levelBonus = 1 + (worker.level - 1) * 0.05
        const classBonus = getClassProductionBonus(worker.class, building.id)
        return sum + speedBonus * staminaFactor * levelBonus * classBonus
      }, 0)

      const efficiency = Math.min(1, assignedWorkers.length / building.requiredWorkers)
      const rate = baseRate * workerModifier * efficiency

      rates[building.produces] = (rates[building.produces] || 0) + rate
    })

    return rates
  }, [workers, buildings])
}

// Хук для расчёта времени до истощения рабочего
export function useWorkerStaminaTime(workerId: string): { workTime: number; restTime: number } {
  // Используем индивидуальные селекторы
  const worker = useGameStore((state) => state.workers.find(w => w.id === workerId))
  const buildings = useGameStore((state) => state.buildings)

  return useMemo(() => {
    if (!worker || worker.assignment === 'rest') {
      if (!worker) return { workTime: 0, restTime: 0 }

      // Время до полного восстановления
      const missingStamina = worker.stats.stamina_max - worker.stamina
      const recoveryRate = BALANCE.BASE_STAMINA_RECOVERY * (80 / worker.stats.stamina_max)
      return { workTime: 0, restTime: missingStamina / recoveryRate }
    }

    const building = buildings.find(b => b.id === worker.assignment)
    if (!building) return { workTime: 0, restTime: 0 }

    // Время до истощения
    const drainRate = (BALANCE.BASE_STAMINA_DRAIN + building.staminaCost * BALANCE.STAMINA_COST_MULTIPLIER) * 
      (CLASS_STAMINA_MODIFIERS[worker.class]?.[building.id] ?? 1.0) *
      Math.max(0.7, 1 - (worker.stats.stamina_max - 80) / 200)

    const workTime = (worker.stamina - BALANCE.AUTO_REST_THRESHOLD) / drainRate
    const restTime = worker.stats.stamina_max / (BALANCE.BASE_STAMINA_RECOVERY * (80 / worker.stats.stamina_max))

    return { workTime: Math.max(0, workTime), restTime }
  }, [worker, buildings])
}

