/**
 * Обновить статистику после миссии
 */
export function updateMissionStats(
  contractedAdventurer: ContractedAdventurer,
  success: boolean,
  goldEarned: number,
  warSoulEarned: number
): ContractedAdventurer {
  return {
    ...contractedAdventurer,
