    missionsSucceeded: contractedAdventurer.missionsSucceeded + (success ? 1 : 0),
    missionsFailed: contractedAdventurer.missionsFailed + (success ? 0 : 1),
    totalGoldEarned: contractedAdventurer.totalGoldEarned + goldEarned,
