/**
 * Рассчитать шанс отказа контрактника от миссии
 */
export function calculateContractRefusalChance(
  contractedAdventurer: ContractedAdventurer,
  missionDifficulty: string
): number {
  // Базовый шанс отказа
  let baseRefusal = 5
  
  // Влияние лояльности
  const { bonuses } = getLoyaltyStatus(contractedAdventurer.loyalty)
  baseRefusal += bonuses.refusalModifier || 0
  
  // Снижение от контракта
  baseRefusal *= (1 - contractedAdventurer.contract.refusalReduction / 100)
  
  // Высокий уровень не хочет лёгкие миссии
  const adventurerLevel = contractedAdventurer.adventurer?.combat?.level || 1
  const difficultyTiers: Record<string, number> = {
    easy: 5, normal: 15, hard: 25, extreme: 35, legendary: 45
  }
  const diffTier = difficultyTiers[missionDifficulty] || 15
  
  if (adventurerLevel > diffTier + 10) {
    baseRefusal += 20 // Скучно
  }
  
  return Math.max(0, Math.min(50, Math.round(baseRefusal)))
}

/**
 * Проверить, хочет ли искатель расторгнуть контракт
 */
export function wantsToTerminate(contractedAdventurer: ContractedAdventurer): boolean {
  // Если лояльность ниже порога недовольства
  if (contractedAdventurer.loyalty < LOYALTY_THRESHOLDS.disgruntled) {
    // Шанс расторжения пропорционален низкой лояльности
    const terminateChance = (LOYALTY_THRESHOLDS.disgruntled - contractedAdventurer.loyalty) * 2
    return Math.random() * 100 < terminateChance
  }
  return false
}

/**
 * Рассчитать штраф за расторжение контракта
 */
export function calculateTerminationPenalty(contractedAdventurer: ContractedAdventurer): {
  gold: number
  glory: number
} {
  const tier = contractedAdventurer.contract.tier
  const requirements = CONTRACT_REQUIREMENTS[tier]
  
  return {
    gold: Math.floor(requirements.requiredResources.gold * 0.5),
    glory: requirements.requiredResources.glory 
      ? Math.floor(requirements.requiredResources.glory * 0.5) 
      : 0,
  }
}

/**
 * Проверить и применить потерю лояльности за простой
 */
export function checkIdleLoyaltyLoss(contractedAdventurer: ContractedAdventurer): {
  contracted: ContractedAdventurer
  loyaltyLost: number
} {
  if (!contractedAdventurer.lastMissionAt) {
    return { contracted: contractedAdventurer, loyaltyLost: 0 }
  }
  
  const daysSinceLastMission = (Date.now() - contractedAdventurer.lastMissionAt) / (1000 * 60 * 60 * 24)
  
  if (daysSinceLastMission < 7) {
    return { contracted: contractedAdventurer, loyaltyLost: 0 }
  }
  
  const weeksIdle = Math.floor(daysSinceLastMission / 7)
  const loyaltyLost = Math.abs(LOYALTY_CHANGES.idleWeek) * weeksIdle
  
  const updated = updateLoyaltyForIdle(contractedAdventurer, daysSinceLastMission)
  
  return {
    contracted: updated,
    loyaltyLost,
  }
}

// Все функции экспортируются через export function выше

/**
 * Калькулятор характеристик оружия
 * Рассчитывает итоговые характеристики на основе материалов и техник
 * 
 * @see docs/CRAFT_SYSTEM_CONCEPT.md - секция 7 Характеристики оружия
 */

import type { 
  WeaponRecipe, 
  Material, 
  MaterialAssignment, 
  Technique, 
  WeaponStats,
  QualityGrade 
} from '@/types/craft-v2'
import { getMaterialAsLegacy } from '@/data/materials'
import { 
  getQualityGrade, 
  getQualityMultiplier, 
  getQualityColor,
  getQualityNameRu,
  QUALITY_GRADES_CONFIG 
} from '@/types/craft-v2'
import type {
  WeaponForecast,
  StatRange,
  QualityScore,
  QualityRank
} from '@/types/forecast'

/**
 * Полный результат расчёта оружия
 */
export interface WeaponCalculationResult {
  stats: WeaponStats
  quality: number
  qualityGrade: QualityGrade
  qualityMultiplier: number
  qualityColor: string
  qualityNameRu: string
  sellPrice: number
  materials: {
    partId: string
    materialId: string
    materialName: string
    quantity: number
  }[]
}

/**
 * Рассчитать характеристики оружия
 */
export function calculateWeapon(
  recipe: WeaponRecipe,
  materials: MaterialAssignment,
  techniques: Technique[],
  blacksmithLevel: number
): WeaponCalculationResult {
  // 1. Базовые значения из рецепта
  const base = recipe.baseStats
  
  // 2. Собираем материалы
  const materialData: { partId: string; material: Material; quantity: number }[] = []
  
  for (const [partId, { materialId, quantity }] of Object.entries(materials)) {
    const material = getMaterialAsLegacy(materialId)
    if (material) {
      materialData.push({ partId, material, quantity })
    }
  }
  
  // 3. Рассчитываем характеристики
  let attack = base.attackBase
  let durability = base.durabilityBase
  let maxDurability = base.durabilityBase
  let weight = base.weightBase
  let soulCapacity = base.soulCapacityBase
  let balance = 75
  let repairPotential = 1.0
  let enchantSlots = 0
  let enchantPower = 1.0
  
  // Применяем материалы
  for (const { material, quantity } of materialData) {
    const effects = material.weaponEffects
    const props = material.properties
    
    // Атака: база + бонус от материала * вклад части (упрощённо)
    attack += attack * (effects.attackBonus / 100) * (quantity / 2)
    
    // Прочность
    durability += durability * (effects.durabilityBonus / 100) * (quantity / 2)
    
    // Вместимость души
    soulCapacity += effects.soulCapacity * quantity * 0.5
    
    // Вес
    weight += props.weight * quantity * 0.1
    
    // Ремонт
    repairPotential = Math.min(repairPotential, effects.repairPotential)
    
    // Зачарования
    enchantSlots += effects.enchantSlots
    enchantPower *= effects.enchantPower
    
    // Баланс (среднее по гибкости и твёрдости)
    balance += ((props.flexibility + props.hardness) / 2 - 50) * 0.2
  }
  
  // Применяем техники
  for (const technique of techniques) {
    const effects = technique.effects
    
    if (effects.qualityBonus) {
      attack *= 1 + (effects.qualityBonus / 100)
      durability *= 1 + (effects.qualityBonus / 100)
    }
    
    if (effects.durabilityBonus) {
      durability *= 1 + (effects.durabilityBonus / 100)
    }
    
    if (effects.conductivityBonus) {
      enchantPower *= 1 + (effects.conductivityBonus / 100)
    }
  }
  
  // Округляем
  attack = Math.round(attack)
  durability = Math.round(durability)
  maxDurability = Math.round(durability)
  weight = Math.round(weight * 10) / 10
  soulCapacity = Math.round(soulCapacity)
  balance = Math.round(Math.max(50, Math.min(100, balance)))
  enchantPower = Math.round(enchantPower * 100) / 100
  
  // 4. Рассчитываем качество
  const quality = calculateQuality(blacksmithLevel, materialData, techniques)
  const qualityGrade = getQualityGrade(quality)
  const qualityMultiplier = getQualityMultiplier(quality)
  const qualityColor = getQualityColor(quality)
  const qualityNameRu = getQualityNameRu(quality)
  
  // 5. Применяем множитель качества к характеристикам
  attack = Math.round(attack * qualityMultiplier)
  durability = Math.round(durability * qualityMultiplier)
  maxDurability = durability
  soulCapacity = Math.round(soulCapacity * qualityMultiplier)
  
  // 6. Рассчитываем цену
  const sellPrice = calculateSellPrice(
    attack,
    durability,
    quality,
    materialData,
    enchantSlots
  )
  
  return {
    stats: {
      attack,
      durability,
      maxDurability,
      weight,
      balance,
      soulCapacity,
      repairPotential,
      enchantSlots,
      enchantPower,
    },
    quality,
    qualityGrade,
    qualityMultiplier,
    qualityColor,
    qualityNameRu,
    sellPrice,
    materials: materialData.map(({ partId, material, quantity }) => ({
      partId,
      materialId: material.id,
      materialName: material.name,
      quantity,
    })),
  }
}

/**
 * Рассчитать качество оружия
 */
function calculateQuality(
  blacksmithLevel: number,
  materialData: { material: Material; quantity: number }[],
  techniques: Technique[]
): number {
  // Базовое качество от уровня кузнеца
  let quality = 30 + blacksmithLevel * 2
  
  // Бонус от качества материалов
  const avgMaterialQuality = materialData.reduce((sum, { material }) => {
    const matQuality = (material.properties.hardness + material.properties.flexibility) / 2
    return sum + matQuality
  }, 0) / materialData.length || 50
  
  quality += (avgMaterialQuality - 50) * 0.2
  
  // Бонус от техник
  for (const technique of techniques) {
    if (technique.effects.qualityBonus) {
      quality += technique.effects.qualityBonus * 0.5
    }
  }
  
  // Ограничение
  return Math.min(100, Math.max(0, Math.round(quality)))
}

/**
 * Рассчитать цену продажи
 */
function calculateSellPrice(
  attack: number,
  durability: number,
  quality: number,
  materialData: { material: Material; quantity: number }[],
  enchantSlots: number
): number {
  // Базовая цена от характеристик
  let price = attack * 2 + durability * 0.5
  
  // Бонус от качества
  price *= (quality / 50)  // 100 качество = ×2 цены
  
  // Бонус от редкости материалов
  const rarityMultiplier = materialData.reduce((mult, { material }) => {
    switch (material.source.rarity) {
      case 'common': return mult * 1.0
      case 'uncommon': return mult * 1.2
      case 'rare': return mult * 1.5
      case 'epic': return mult * 2.0
      case 'legendary': return mult * 3.0
      default: return mult
    }
  }, 1.0)
  
  price *= rarityMultiplier
  
  // Бонус от слотов зачарований
  price += enchantSlots * 20
  
  return Math.round(price)
}

/**
 * Получить информацию о градации качества
 */
export function getQualityInfo(quality: number): {
  grade: QualityGrade
  multiplier: number
  color: string
  nameRu: string
  nextThreshold: number | null
  prevThreshold: number | null
} {
  const grade = getQualityGrade(quality)
  const config = QUALITY_GRADES_CONFIG.find(g => g.grade === grade)
  const nextConfig = QUALITY_GRADES_CONFIG.find(g => g.min > quality)

  return {
    grade,
    multiplier: config?.multiplier ?? 1.0,
    color: config?.color ?? 'text-gray-400',
    nameRu: config?.nameRu ?? 'Обычное',
    nextThreshold: nextConfig?.min ?? null,
    prevThreshold: config?.min ?? 0,
  }
}

// ================================
// ПРОГНОЗ РЕЗУЛЬТАТА
// ================================

/**
 * Рассчитать прогноз результата оружия
 * Использует те же формулы, что и calculateWeapon, но добавляет разброс на основе экспертизы
 */
export function calculateForecast(
  recipe: WeaponRecipe,
  materials: MaterialAssignment,
  techniques: Technique[],
  blacksmithLevel: number,
  materialExpertise: Record<string, number>
): WeaponForecast {
  // Рассчитываем базовые характеристики используя те же формулы, что и при крафте
  const baseResult = calculateWeapon(recipe, materials, techniques, blacksmithLevel)

  // Рассчитываем среднюю экспертизу для определения разброса
  const avgExpertise = calculateAverageExpertise(materials, materialExpertise)
  const varianceMultiplier = (100 - avgExpertise) / 100 * 0.3

  // Рассчитываем диапазоны характеристик
  const attack: StatRange = {
    min: Math.max(0, Math.round(baseResult.stats.attack * (1 - varianceMultiplier))),
    max: Math.round(baseResult.stats.attack * (1 + varianceMultiplier * 0.5)),
    variance: varianceMultiplier
  }

  const durability: StatRange = {
    min: Math.max(0, Math.round(baseResult.stats.durability * (1 - varianceMultiplier))),
    max: Math.round(baseResult.stats.maxDurability * (1 + varianceMultiplier * 0.5)),
    variance: varianceMultiplier
  }

  const weight: StatRange = {
    min: Math.max(0, Math.round(baseResult.stats.weight * (1 - varianceMultiplier * 0.5))),
    max: Math.round(baseResult.stats.weight * (1 + varianceMultiplier * 0.3)),
    variance: varianceMultiplier
  }

  const soulCapacity: StatRange = {
    min: Math.max(0, Math.round(baseResult.stats.soulCapacity * (1 - varianceMultiplier))),
    max: Math.round(baseResult.stats.soulCapacity * (1 + varianceMultiplier * 0.5)),
    variance: varianceMultiplier
  }

  // Диапазон качества
  const quality: QualityScore = {
    value: baseResult.quality,
    min: Math.max(0, Math.round(baseResult.quality * (1 - varianceMultiplier))),
    max: Math.min(100, Math.round(baseResult.quality * (1 + varianceMultiplier * 0.5))),
    rank: getQualityRankFromQuality(baseResult.quality),
    progress: 0.5
  }

  const predictionAccuracy = 50 + avgExpertise * 0.5

  return {
    attack,
    durability,
    weight,
    soulCapacity,
    quality,
    predictionAccuracy
  }
}

/**
 * Рассчитать среднюю экспертизу по материалам
 */
function calculateAverageExpertise(
  materials: MaterialAssignment,
  materialExpertise: Record<string, number>
): number {
  const values = Object.values(materials).map(m => materialExpertise[m.materialId] || 0)
  return values.length > 0 ? values.reduce((a, b) => a + b, 0) / values.length : 0
}

/**
 * Получить ранг качества по числовому значению
 */
function getQualityRankFromQuality(quality: number): QualityRank {
  if (quality >= 95) return 'S'
  if (quality >= 85) return 'A'
  if (quality >= 70) return 'B'
  if (quality >= 55) return 'C'
  if (quality >= 40) return 'D'
  return 'F'
}

export default {
  calculateWeapon,
  getQualityInfo,
  calculateForecast,
}

// ================================
// КАЛЬКУЛЯТОР ПРОГНОЗА РЕЗУЛЬТАТА ОРУЖИЯ
// ================================

import type {
  ForecastInput,
  WeaponForecast,
  QualityScore,
  QualityRank,
  StatRange,
  StatBreakdown,
  ContributionBreakdown,
  ContributionDetail,
  ForecastStats
} from '@/types/forecast'

// ================================
// РАСЧЁТ ПРОГНОЗА
// ================================

export function calculateWeaponForecast(input: ForecastInput): WeaponForecast {
  const { recipe, materials, techniques, blacksmithLevel, materialExpertise } = input

  // 1. Расчёт средней экспертизы
  const avgExpertise = calculateAverageExpertise(materials, materialExpertise)
  const predictionAccuracy = 50 + (avgExpertise * 0.5) // 50-100%

  // 2. Расчёт качества
  const quality = calculateQuality(input, avgExpertise)

  // 3. Расчёт характеристик
  const attack = calculateAttack(input, avgExpertise, predictionAccuracy)
  const durability = calculateDurability(input, avgExpertise, predictionAccuracy)
  const weight = calculateWeight(input, avgExpertise, predictionAccuracy)
  const soulCapacity = calculateSoulCapacity(input, avgExpertise, predictionAccuracy)

  return {
    attack,
    durability,
    weight,
    soulCapacity,
    quality,
    predictionAccuracy
  }
}

// ================================
// РАСЧЁТ КАЧЕСТВА
// ================================

function calculateQuality(input: ForecastInput, avgExpertise: number): QualityScore {
  const { blacksmithLevel, materials, techniques } = input

  // A. BaseScore (30-130)
  const baseScore = 30 + blacksmithLevel * 2

  // B. MaterialFactor (0.5-1.5)
  const avgMaterialQuality = calculateAverageMaterialQuality(materials)
  const materialFactor = 0.5 + (avgMaterialQuality / 200)

  // C. ExpertiseFactor (0.85-1.15)
  const expertiseFactor = 0.85 + (avgExpertise / 100) * 0.3

  // D. TechniqueFactor (1.0-1.5)
  const techniqueBonus = techniques.reduce((sum, t) => sum + (t.effects.qualityBonus || 0), 0)
  const incompatibilityPenalty = checkMaterialCompatibility(techniques, materials) ? 0 : 0.1
  const techniqueFactor = 1.0 + (techniqueBonus / 100) - incompatibilityPenalty

  // E. RiskFactor (0.7-1.0)
  const totalRisk = techniques.reduce((sum, t) => sum + (t.penalties?.riskOfFailure || 0), 0) / 100
  const riskFactor = 1.0 - Math.min(totalRisk * 0.3, 0.3)

  // Итоговое качество
  let finalQuality = (baseScore + materialFactor * 20) * expertiseFactor * techniqueFactor * riskFactor
  finalQuality = Math.max(0, Math.min(100, finalQuality))

  // Диапазон
  const varianceMultiplier = (100 - avgExpertise) / 100 * 0.4
  const min = finalQuality * (1 - varianceMultiplier)
  const max = finalQuality * (1 + varianceMultiplier * 0.5)

  // Ранг
  const rank = getQualityRank(finalQuality)
  const progress = calculateRankProgress(finalQuality, rank)

  return {
    value: Math.round(finalQuality),
    min: Math.round(min),
    max: Math.round(max),
    rank,
    progress
  }
}

// ================================
// РАСЧЁТ АТАКИ
// ================================

function calculateAttack(
  input: ForecastInput,
  avgExpertise: number,
  predictionAccuracy: number
): StatRange {
  const { recipe, materials, techniques } = input

  let attack = recipe.baseStats.attackBase
  const totalWeight = materials.reduce((sum, m) => sum + m.partWeight, 0)

  // Вклад материалов
  for (const part of materials) {
    const material = part.material
    const contribution = material.physical.hardness * 0.5 + material.physical.toughness * 0.3
    attack += contribution * part.partWeight / totalWeight
  }

  // Вклад техник
  const techniqueBonus = techniques.reduce((sum, t) => sum + (t.effects.qualityBonus || 0), 0)
  attack *= 1 + (techniqueBonus / 100)

  // Диапазон
  const varianceMultiplier = (100 - avgExpertise) / 100 * 0.3
  const min = Math.max(0, attack * (1 - varianceMultiplier))
  const max = attack * (1 + varianceMultiplier * 0.5)

  return {
    min: Math.round(min),
    max: Math.round(max),
    variance: varianceMultiplier
  }
}

// ================================
// РАСЧЁТ ПРОЧНОСТИ
// ================================

function calculateDurability(
  input: ForecastInput,
  avgExpertise: number,
  predictionAccuracy: number
): StatRange {
  const { recipe, materials, techniques } = input

  let durability = recipe.baseStats.durabilityBase

  // Вклад материалов
  for (const part of materials) {
    const material = part.material
    durability += material.physical.toughness * 0.6 * part.quantity
    durability += material.physical.compressiveStrength * 0.2 * part.quantity
  }

  // Вклад техник
  const techniqueBonus = techniques.reduce((sum, t) => sum + (t.effects.durabilityBonus || 0), 0)
  durability *= 1 + (techniqueBonus / 100)

  // Диапазон
  const varianceMultiplier = (100 - avgExpertise) / 100 * 0.25
  const min = Math.max(0, durability * (1 - varianceMultiplier))
  const max = durability * (1 + varianceMultiplier * 0.5)

  return {
    min: Math.round(min),
    max: Math.round(max),
    variance: varianceMultiplier
  }
}

// ================================
// РАСЧЁТ ВЕСА
// ================================

function calculateWeight(
  input: ForecastInput,
  avgExpertise: number,
  predictionAccuracy: number
): StatRange {
  const { recipe, materials, techniques } = input

  let weight = recipe.baseStats.weightBase

  // Вклад материалов
  for (const part of materials) {
    const material = part.material
    weight += material.physical.density * part.quantity * 0.1
  }

  // Вклад техник (balanced_design может снижать вес)
  const weightReduction = techniques.reduce((sum, t) => {
    // Проверяем специальные техники по ID
    if (t.id === 'balanced_design') return sum + 10 // -10% веса
    if (t.id === 'master_balance') return sum + 5 // -5% веса
    return sum
  }, 0)

  weight *= 1 - (weightReduction / 100)

  // Диапазон (меньшая неопределённость для веса)
  const varianceMultiplier = (100 - avgExpertise) / 100 * 0.15
  const min = Math.max(0, weight * (1 - varianceMultiplier))
  const max = weight * (1 + varianceMultiplier * 0.3)

  return {
    min: Math.round(Math.min(min, max) * 10) / 10,
    max: Math.round(max * 10) / 10,
    variance: varianceMultiplier
  }
}

// ================================
// РАСЧЁТ ВМЕСТИМОСТИ ДУШИ
// ================================

function calculateSoulCapacity(
  input: ForecastInput,
  avgExpertise: number,
  predictionAccuracy: number
): StatRange {
  const { recipe, materials, techniques } = input

  let soulCapacity = recipe.baseStats.soulCapacityBase

  // Вклад материалов
  for (const part of materials) {
    const material = part.material
    soulCapacity += material.arcane.conductivity * 0.3 * part.quantity
    soulCapacity += material.arcane.affinity * 0.2 * part.quantity
  }

  // Вклад техник
  const techniqueBonus = techniques.reduce((sum, t) => sum + (t.effects.conductivityBonus || 0), 0)
  soulCapacity *= 1 + (techniqueBonus / 100)

  // Диапазон
  const varianceMultiplier = (100 - avgExpertise) / 100 * 0.35
  const min = Math.max(0, soulCapacity * (1 - varianceMultiplier))
  const max = soulCapacity * (1 + varianceMultiplier * 0.5)

  return {
    min: Math.round(min),
    max: Math.round(max),
    variance: varianceMultiplier
  }
}

// ================================
// ВСПОМОГАТЕЛЬНЫЕ ФУНКЦИИ
// ================================

function calculateAverageExpertise(
  materials: ForecastInput['materials'],
  materialExpertise: Record<string, number>
): number {
  if (materials.length === 0) return 0

  const total = materials.reduce((sum, m) => {
    const expertise = materialExpertise[m.material.identity.id] || 0
    return sum + expertise
  }, 0)

  return total / materials.length
}

function calculateAverageMaterialQuality(
  materials: ForecastInput['materials']
): number {
  if (materials.length === 0) return 50

  const totalWeight = materials.reduce((sum, m) => sum + m.partWeight, 0)

  const weightedSum = materials.reduce((sum, m) => {
    const material = m.material
    const quality = (material.physical.hardness + material.physical.toughness) / 2
    return sum + quality * m.partWeight
  }, 0)

  return weightedSum / totalWeight
}

function checkMaterialCompatibility(
  techniques: ForecastInput['techniques'],
  materials: ForecastInput['materials']
): boolean {
  // Проверяем совместимость техник с материалами
  // Например: dragon_hardening требует мифрил
  const incompatibleCombinations: Record<string, string[]> = {
    'dragon_hardening': ['mythril', 'mithril'],
    'elven_forging': ['iron', 'steel']
  }

  const materialIds = materials.map(m => m.material.identity.id)

  for (const technique of techniques) {
    const requiredMaterials = incompatibleCombinations[technique.id]
    if (!requiredMaterials) continue

    // Если техника требует определённый материал, а его нет - несовместимость
    const hasRequiredMaterial = requiredMaterials.some(id =>
      materialIds.some(mid => mid.includes(id))
    )

    if (hasRequiredMaterial) return false
  }

  return true
}

function getQualityRank(value: number): QualityRank {
  if (value >= 95) return 'S'
  if (value >= 85) return 'A'
  if (value >= 70) return 'B'
  if (value >= 55) return 'C'
  if (value >= 40) return 'D'
  return 'F'
}

function calculateRankProgress(value: number, rank: QualityRank): number {
  const ranges: Record<QualityRank, [number, number]> = {
    S: [95, 100],
    A: [85, 94],
    B: [70, 84],
    C: [55, 69],
    D: [40, 54],
    F: [0, 39]
  }

  const [min, max] = ranges[rank]
  const range = max - min
  const progress = (value - min) / range

  return Math.max(0, Math.min(1, progress))
}

// ================================
// ДЕТАЛИЗАЦИЯ ВКЛАДОВ
// ================================

export function calculateStatBreakdown(
  input: ForecastInput,
  stat: 'attack' | 'durability' | 'weight' | 'soulCapacity'
): StatBreakdown {
  const { recipe, materials, techniques, blacksmithLevel, materialExpertise } = input

  const avgExpertise = calculateAverageExpertise(materials, materialExpertise)
  const predictionAccuracy = 50 + (avgExpertise * 0.5)

  const breakdown: ContributionBreakdown[] = []

  // Вклад материалов
  const materialContribution = calculateMaterialContribution(input, stat)
  if (materialContribution.value !== 0) {
    breakdown.push(materialContribution)
  }

  // Вклад техник
  const techniqueContribution = calculateTechniqueContribution(input, stat)
  if (techniqueContribution.value !== 0) {
    breakdown.push(techniqueContribution)
  }

  // Вклад мастерства
  const masteryContribution = calculateMasteryContribution(input, stat, blacksmithLevel)
  if (masteryContribution.value !== 0) {
    breakdown.push(masteryContribution)
  }

  // Вклад экспертизы
  const expertiseContribution = calculateExpertiseContribution(input, stat, avgExpertise)
  if (expertiseContribution.value !== 0) {
    breakdown.push(expertiseContribution)
  }

  const totalValue = breakdown.reduce((sum, b) => sum + b.value, 0)

  return {
    stat,
    breakdown: breakdown.map(b => ({
      ...b,
      percentage: totalValue > 0 ? (b.value / totalValue) * 100 : 0
    })),
    accuracy: Math.round(predictionAccuracy)
  }
}

function calculateMaterialContribution(
  input: ForecastInput,
  stat: 'attack' | 'durability' | 'weight' | 'soulCapacity'
): ContributionBreakdown {
  const { materials } = input
  const details: ContributionDetail[] = []

  for (const part of materials) {
    const material = part.material
    let value = 0

    switch (stat) {
      case 'attack':
        value = (material.physical.hardness * 0.5 + material.physical.toughness * 0.3) * part.partWeight
        break
      case 'durability':
        value = (material.physical.toughness * 0.6 + material.physical.compressiveStrength * 0.2) * part.quantity
        break
      case 'weight':
        value = material.physical.density * part.quantity * 0.1
        break
      case 'soulCapacity':
        value = (material.arcane.conductivity * 0.3 + material.arcane.affinity * 0.2) * part.quantity
        break
    }

    details.push({
      name: material.identity.name,
      value: Math.round(value)
    })
  }

  const totalValue = details.reduce((sum, d) => sum + d.value, 0)

  return {
    source: 'materials',
    value: totalValue,
    percentage: 0, // будет рассчитано позже
    details
  }
}

function calculateTechniqueContribution(
  input: ForecastInput,
  stat: 'attack' | 'durability' | 'weight' | 'soulCapacity'
): ContributionBreakdown {
  const { techniques } = input
  const details: ContributionDetail[] = []

  for (const technique of techniques) {
    let value = 0

    switch (stat) {
      case 'attack':
        value = technique.effects.qualityBonus || 0
        break
      case 'durability':
        value = technique.effects.durabilityBonus || 0
        break
      case 'weight':
        if (technique.id === 'balanced_design') value = -10
        if (technique.id === 'master_balance') value = -5
        break
      case 'soulCapacity':
        value = technique.effects.conductivityBonus || 0
        break
    }

    if (value !== 0) {
      details.push({
        name: technique.name,
        value
      })
    }
  }

  const totalValue = details.reduce((sum, d) => sum + d.value, 0)

  return {
    source: 'techniques',
    value: totalValue,
    percentage: 0,
    details
  }
}

function calculateMasteryContribution(
  input: ForecastInput,
  stat: 'attack' | 'durability' | 'weight' | 'soulCapacity',
  blacksmithLevel: number
): ContributionBreakdown {
  // Бонус мастерства кузнеца (2% за уровень)
  const value = blacksmithLevel * 2

  return {
    source: 'mastery',
    value: value > 0 ? value : 0,
    percentage: 0,
    details: [
      {
        name: 'Мастерство кузнеца',
        value: value > 0 ? value : 0
      }
    ]
  }
}

function calculateExpertiseContribution(
  input: ForecastInput,
  stat: 'attack' | 'durability' | 'weight' | 'soulCapacity',
  avgExpertise: number
): ContributionBreakdown {
  // Бонус экспертизы (0.5% за единицу экспертизы)
  const value = avgExpertise * 0.5

  return {
    source: 'expertise',
    value: value > 0 ? value : 0,
    percentage: 0,
    details: [
      {
        name: 'Экспертиза материалов',
        value: value > 0 ? Math.round(value) : 0
      }
    ]
  }
}

/**
 * Проверка инвентаря для крафта
 * Расчёт требований и проверка наличия материалов
 * 
 * Поддерживает:
 * - Расчёт сырья для сплавов
 * - Покупку недостающих материалов
 * - Детализацию по частям оружия
 */

import type { Material, MaterialAssignment, WeaponRecipe } from '@/types/craft-v2'
import type { Resources, ResourceKey } from '@/store/slices/resources-slice'
import { getMaterialAsLegacy } from '@/data/materials'
import { canBuyMaterial, getMaterialPrice, getMaterialShopInfo } from '@/data/material-shop'

// ================================
// МАППИНГ МАТЕРИАЛОВ НА РЕСУРСЫ
// ================================

/**
 * Маппинг ID материалов из крафта на ресурсы инвентаря
 * 
 * Материалы в крафте (craft-v2) → Ресурсы в инвентаре (resources-slice)
 */
const MATERIAL_TO_RESOURCE: Record<string, ResourceKey> = {
  // Металлы (сырьё)
  'iron': 'iron',
  'cold_iron': 'iron',  // Вариант железа
  'copper': 'copper',
  'tin': 'tin',
  'silver': 'silver',
  'gold': 'goldOre',
  'mithril': 'mithril',
  
  // Сплавы (создаются из сырья)
  'steel': 'steelIngot',
  'high_carbon_steel': 'steelIngot',
  'iron_alloy': 'ironIngot',
  'copper_alloy': 'copperIngot',
  'tin_alloy': 'tinIngot',
  'bronze': 'bronzeIngot',
  'silver_alloy': 'silverIngot',
  'gold_alloy': 'goldIngot',
  'mithril_alloy': 'mithrilIngot',
  
  // Дерево
  'birch': 'wood',
  'oak': 'wood',
  'ash': 'wood',
  'ebony': 'wood',
  'ironwood': 'wood',
  'pine': 'wood',
  'maple': 'wood',
  'walnut': 'wood',
  'mahogany': 'wood',
  'processed_wood': 'planks',
  
  // Кожа
  'raw_leather': 'leather',
  'tanned_leather': 'leather',
  'bull_leather': 'leather',
  'dragon_leather': 'leather',
  'hardened_leather': 'leather',
  
  // Камень
  'basic_stone': 'stone',
  'granite': 'stone',
  'obsidian': 'stone',
  'marble': 'stone',
  'processed_stone': 'stoneBlocks',
}

/**
 * Рецепты сплавов — что нужно для создания 1 ед. материала
 * Используется для расчёта сырья, если игрок выбрал сплав
 */
const ALLOY_RECIPES: Record<string, { 
  inputs: { resource: ResourceKey, amount: number, name: string }[]
  fuel?: { resource: ResourceKey, amount: number }
}> = {
  'steel': {
    inputs: [
      { resource: 'iron', amount: 2, name: 'Железо' },
      { resource: 'coal', amount: 1, name: 'Уголь' },
    ],
    fuel: { resource: 'coal', amount: 1 },
  },
  'high_carbon_steel': {
    inputs: [
      { resource: 'iron', amount: 2, name: 'Железо' },
      { resource: 'coal', amount: 2, name: 'Уголь' },
    ],
    fuel: { resource: 'coal', amount: 2 },
  },
  'silver_alloy': {
    inputs: [
      { resource: 'iron', amount: 1, name: 'Железо' },
      { resource: 'silver', amount: 1, name: 'Серебро' },
    ],
    fuel: { resource: 'coal', amount: 1 },
  },
}

// ================================
// ТИПЫ
// ================================

/** Требование одного ресурса */
export interface ResourceRequirement {
  resourceKey: ResourceKey
  resourceId: string          // ID для отображения (iron, coal, wood...)
  resourceName: string        // Имя для отображения
  quantity: number
  available: number
  sufficient: boolean
}

/** Материал для покупки */
export interface MaterialToBuy {
  resourceKey: ResourceKey
  resourceName: string
  quantity: number
  unitPrice: number
  totalPrice: number
  canBuy: boolean  // Доступен ли в магазине
}

/** Результат проверки */
export interface InventoryCheckResult {
  canCraft: boolean
  requirements: ResourceRequirement[]
  missing: ResourceRequirement[]
  
  // Детализация по частям оружия
  breakdownByPart: {
    partId: string
    partName: string
    materialId: string
    materialName: string
    requirements: ResourceRequirement[]
  }[]
  
  // Общее топливо (уголь для горна)
  fuelRequired?: ResourceRequirement
  
  // НОВОЕ: Материалы для покупки
  materialsToBuy: MaterialToBuy[]
  totalPurchaseCost: number
  canPurchaseMissing: boolean  // Все ли недостающие можно купить
}

// ================================
// ФУНКЦИИ
// ================================

/**
 * Получить ключ ресурса для материала
 */
export function getResourceKeyForMaterial(materialId: string): ResourceKey | null {
  return MATERIAL_TO_RESOURCE[materialId] || null
}

/**
 * Получить отображаемое имя ресурса
 */
function getResourceDisplayName(resourceKey: ResourceKey): string {
  const names: Partial<Record<ResourceKey, string>> = {
    iron: 'Железо',
    coal: 'Уголь',
    wood: 'Дерево',
    stone: 'Камень',
    ironIngot: 'Железный слиток',
    steelIngot: 'Стальной слиток',
    silverIngot: 'Серебряный слиток',
    mithrilIngot: 'Мифриловый слиток',
    planks: 'Доски',
    leather: 'Кожа',
    silver: 'Серебро',
  }
  return names[resourceKey] || resourceKey
}

/**
 * Рассчитать сырьё для материала
 * Если это сплав — раскрывает рецепт
 */
function calculateRawResources(
  materialId: string,
  quantity: number
): { resource: ResourceKey; amount: number; name: string }[] {
  // Проверяем, есть ли рецепт для сплава
  const recipe = ALLOY_RECIPES[materialId]
  if (recipe) {
    // Это сплав — раскрываем рецепт
    return recipe.inputs.map(input => ({
      resource: input.resource,
      amount: input.amount * quantity,
      name: input.name,
    }))
  }
  
  // Это сырьё — прямая запись
  const resourceKey = getResourceKeyForMaterial(materialId)
  const material = getMaterialAsLegacy(materialId)
  if (resourceKey) {
    return [{ 
      resource: resourceKey, 
      amount: quantity,
      name: material?.name || resourceKey,
    }]
  }
  
  // Неизвестный материал
  console.warn(`Unknown material: ${materialId}`)
  return []
}

/**
 * Рассчитать требования для крафта
 * Возвращает детальную информацию о требуемых ресурсах
 */
export function calculateCraftRequirements(
  recipe: WeaponRecipe,
  materialSelections: MaterialAssignment
): Map<ResourceKey, { amount: number; sources: string[]; names: string[] }> {
  const requirements = new Map<ResourceKey, { amount: number; sources: string[]; names: string[] }>()
  
  for (const [partId, selection] of Object.entries(materialSelections)) {
    const material = getMaterialAsLegacy(selection.materialId)
    if (!material) continue
    
    // Базовое количество материала для этой части
    const recipePart = recipe.parts.find(p => p.id === partId)
    const baseQuantity = recipePart?.minQuantity || 1
    
    // Получаем список сырья
    const rawResources = calculateRawResources(selection.materialId, baseQuantity)
    
    for (const { resource, amount, name } of rawResources) {
      const existing = requirements.get(resource)
      if (existing) {
        existing.amount += amount
        existing.sources.push(partId)
        existing.names.push(name)
      } else {
        requirements.set(resource, { amount, sources: [partId], names: [name] })
      }
    }
  }
  
  return requirements
}

/**
 * Проверить наличие ресурсов в инвентаре
 */
export function checkInventoryForCraft(
  recipe: WeaponRecipe,
  materialSelections: MaterialAssignment,
  inventory: Resources
): InventoryCheckResult {
  const requirements: ResourceRequirement[] = []
  const missing: ResourceRequirement[] = []
  const breakdownByPart: InventoryCheckResult['breakdownByPart'] = []
  const materialsToBuy: MaterialToBuy[] = []
  
  // Рассчитываем общие требования
  const totalRequirements = calculateCraftRequirements(recipe, materialSelections)
  
  // Формируем список требований
  for (const [resourceKey, { amount, sources }] of totalRequirements) {
    const available = inventory[resourceKey] || 0
    const sufficient = available >= amount
    
    const req: ResourceRequirement = {
      resourceKey,
      resourceId: resourceKey,
      resourceName: getResourceDisplayName(resourceKey),
      quantity: amount,
      available,
      sufficient,
    }
    
    requirements.push(req)
    
    if (!sufficient) {
      missing.push(req)
      
      // Проверяем, можно ли купить
      const buyable = canBuyMaterial(resourceKey)
      const neededQuantity = amount - available
      const shopInfo = getMaterialShopInfo(resourceKey)
      
      if (buyable && shopInfo) {
        materialsToBuy.push({
          resourceKey,
          resourceName: shopInfo.name,
          quantity: neededQuantity,
          unitPrice: shopInfo.basePrice,
          totalPrice: Math.ceil(shopInfo.basePrice * neededQuantity * 1.1), // +10% за покупку из крафта
          canBuy: true,
        })
      }
    }
  }
  
  // Детализация по частям (для UI)
  const partNames: Record<string, string> = {
    blade: 'Лезвие',
    guard: 'Гарда',
    grip: 'Рукоять',
    pommel: 'Навершие',
    wrapping: 'Обмотка',
  }
  
  for (const [partId, selection] of Object.entries(materialSelections)) {
    const material = getMaterialAsLegacy(selection.materialId)
    if (!material) continue
    
    const recipePart = recipe.parts.find(p => p.id === partId)
    const baseQuantity = recipePart?.minQuantity || 1
    
    const partRequirements: ResourceRequirement[] = []
    const rawResources = calculateRawResources(selection.materialId, baseQuantity)
    
    for (const { resource, amount } of rawResources) {
      const available = inventory[resource] || 0
      partRequirements.push({
        resourceKey: resource,
        resourceId: resource,
        resourceName: getResourceDisplayName(resource),
        quantity: amount,
        available,
        sufficient: available >= amount,
      })
    }
    
    breakdownByPart.push({
      partId,
      partName: partNames[partId] || partId,
      materialId: selection.materialId,
      materialName: material.name,
      requirements: partRequirements,
    })
  }
  
  // Топливо для горна (базовое количество угля)
  const fuelRequired: ResourceRequirement = {
    resourceKey: 'coal',
    resourceId: 'coal',
    resourceName: 'Уголь',
    quantity: 3, // Базовый расход на крафт
    available: inventory.coal || 0,
    sufficient: (inventory.coal || 0) >= 3,
  }
  
  // Если не хватает топлива — добавляем в список покупки
  if (!fuelRequired.sufficient) {
    const neededFuel = fuelRequired.quantity - fuelRequired.available
    const fuelShopInfo = getMaterialShopInfo('coal')
    if (fuelShopInfo) {
      materialsToBuy.push({
        resourceKey: 'coal',
        resourceName: 'Уголь',
        quantity: neededFuel,
        unitPrice: fuelShopInfo.basePrice,
        totalPrice: Math.ceil(fuelShopInfo.basePrice * neededFuel * 1.1),
        canBuy: true,
      })
    }
  }
  
  // Рассчитываем общую стоимость покупки
  const totalPurchaseCost = materialsToBuy.reduce((sum, m) => sum + m.totalPrice, 0)
  
  // Проверяем, можно ли купить все недостающие материалы
  const canPurchaseMissing = missing.length > 0 && materialsToBuy.length > 0 && materialsToBuy.every(m => m.canBuy)
  
  return {
    canCraft: missing.length === 0 && fuelRequired.sufficient,
    requirements,
    missing,
    breakdownByPart,
    fuelRequired,
    materialsToBuy,
    totalPurchaseCost,
    canPurchaseMissing,
  }
}

/**
 * Получить стоимость для списания
 * 
 * Если materialSelections пустой (генерация заказа), используем recipe.cost
 */
export function getCraftingCost(
  recipe: WeaponRecipe,
  materialSelections: MaterialAssignment
): Partial<Record<ResourceKey, number>> {
  const cost: Partial<Record<ResourceKey, number>> = {}
  
  // Если есть выбранные материалы (при крафте) — используем их
  if (Object.keys(materialSelections).length > 0) {
    const totalRequirements = calculateCraftRequirements(recipe, materialSelections)
    for (const [resourceKey, { amount }] of totalRequirements) {
      cost[resourceKey] = (cost[resourceKey] || 0) + amount
    }
  } else if (recipe.cost) {
    // Если нет выбранных материалов (генерация заказа) — используем базовую стоимость рецепта
    for (const [resourceKey, amount] of Object.entries(recipe.cost)) {
      if (amount && amount > 0) {
        cost[resourceKey as ResourceKey] = amount
      }
    }
  }
  
  // Добавляем топливо
  cost.coal = (cost.coal || 0) + 3
  
  return cost
}

/**
 * Проверить, есть ли материал в инвентаре
 */
export function hasMaterialInInventory(
  materialId: string,
  quantity: number,
  inventory: Resources
): boolean {
  const resourceKey = getResourceKeyForMaterial(materialId)
  if (!resourceKey) return false
  
  return (inventory[resourceKey] || 0) >= quantity
}

/**
 * Получить количество материала в инвентаре
 */
export function getMaterialAmountInInventory(
  materialId: string,
  inventory: Resources
): number {
  const resourceKey = getResourceKeyForMaterial(materialId)
  if (!resourceKey) return 0
  
  return inventory[resourceKey] || 0
}

/**
 * Расчёт превью характеристик материала для крафта
 * Рассчитывает диапазоны возможных значений с учётом экспертизы
 */

import type { MaterialNode } from '@/types/materials/material-core'
import type { WeaponRecipe } from '@/types/craft-v2'
import type { Material } from '@/types/craft-v2'
import { getMaterialAsLegacy } from '@/data/materials'
import { calculateExpertiseImpact } from '@/types/materials/knowledge'
import { getMaterialById } from '@/data/materials'

// ================================
// ТИПЫ
// ================================

/** Превью характеристик материала */
export interface MaterialPreview {
  attack: { min: number; max: number; base: number }
  durability: { min: number; max: number; base: number }
  weight: number
  soulCapacity: { min: number; max: number; base: number }
  quality: { min: number; max: number }
  predictionAccuracy: number // 50-100%
}

/** Сравнение с текущим выбранным материалом */
export interface MaterialComparison {
  preview: MaterialPreview
  delta: {
    attack: { min: number; max: number } | null
    durability: { min: number; max: number } | null
    quality: { min: number; max: number } | null
  }
}

// ================================
// ФУНКЦИИ РАСЧЁТА
// ================================

/**
 * Рассчитать превью характеристик материала
 */
export function calculateMaterialPreview(
  material: MaterialNode,
  recipe: WeaponRecipe,
  partId: string,
  blacksmithLevel: number,
  expertise: number
): MaterialPreview {
  const legacyMaterial = getMaterialAsLegacy(material?.identity?.id || '')
  if (!legacyMaterial) {
    throw new Error(`Material not found: ${material?.identity?.id}`)
  }

  const impact = calculateExpertiseImpact(material, expertise)
  
  // 1. Базовое качество от уровня кузнеца и экспертизы
  const baseQuality = 30 + blacksmithLevel * 2
  const qualityBonus = expertise * 0.15 // До +15
  const avgMaterialQuality = (material.physical.hardness + material.physical.elasticity) / 2
  const materialQualityBonus = (avgMaterialQuality - 50) * 0.2
  
  const baseQualityValue = Math.min(100, baseQuality + qualityBonus + materialQualityBonus)
  
  // 2. Разброс от экспертизы (varianceMultiplier)
  // Чем выше экспертиза, тем меньше разброс
  // varianceMultiplier: 1.0 при 0% экспертизы, 0.2 при 100% экспертизы
  const variance = impact.varianceMultiplier
  
  // 3. Базовые значения для части из рецепта
  const recipePart = recipe.parts.find(p => p.id === partId)
  const partQuantity = recipePart?.minQuantity || 1
  
  // 4. Рассчитываем базовые характеристики
  const baseAttack = recipe.baseStats.attackBase
  const baseDurability = recipe.baseStats.durabilityBase
  const baseSoul = recipe.baseStats.soulCapacityBase
  const baseWeight = recipe.baseStats.weightBase
  
  // Бонусы от материала
  const attackBonus = baseAttack * (legacyMaterial.weaponEffects.attackBonus / 100) * (partQuantity / 2)
  const durabilityBonus = baseDurability * (legacyMaterial.weaponEffects.durabilityBonus / 100) * (partQuantity / 2)
  const soulBonus = legacyMaterial.weaponEffects.soulCapacity * partQuantity * 0.5
  const weightBonus = legacyMaterial.properties.weight * partQuantity * 0.1
  
  // Базовые значения с бонусами
  const attackBase = Math.round(baseAttack + attackBonus)
  const durabilityBase = Math.round(baseDurability + durabilityBonus)
  const soulBase = Math.round(baseSoul + soulBonus)
  const weightValue = Math.round((baseWeight + weightBonus) * 10) / 10
  
  // 5. Асимметричный разброс от экспертизы
  // При 0% экспертизы: min = base - 75%, max = base + 15%
  // При 100% экспертизы: min = base - 0%, max = base + 0%
  const expertiseFactor = expertise / 100  // 0.0 - 1.0
  
  // Разброс вниз уменьшается с 75% до 0%
  const downVarianceFactor = 0.75 * (1 - expertiseFactor)
  
  // Разброс вверх уменьшается с 15% до 0%
  const upVarianceFactor = 0.15 * (1 - expertiseFactor)
  
  // Применяем к базовым значениям
  const attackDown = Math.round(attackBase * downVarianceFactor)
  const attackUp = Math.round(attackBase * upVarianceFactor)
  const durabilityDown = Math.round(durabilityBase * downVarianceFactor)
  const durabilityUp = Math.round(durabilityBase * upVarianceFactor)
  const soulDown = Math.round(soulBase * downVarianceFactor)
  const soulUp = Math.round(soulBase * upVarianceFactor)
  const qualityVariance = Math.round(10 * (1 - expertiseFactor))
  
  // 6. Точность прогноза - УСИЛЕНА зависимость от экспертизы
  // Базовая формула: 50% + (expertise * 0.5) = 50-100%
  // Это означает: 0% экспертизы = 50% точности, 100% экспертизы = 100% точности
  const baseAccuracy = 50 + (expertise * 0.5)
  
  // Модификаторы от материала
  const materialAccuracyFactor =
    (material.chemical.stability / 100) * 10 +       // Стабильность до +10%
    (material.arcane.stability / 100) * 10 +          // Магическая стабильность до +10%
    (material.economy.discoverability / 100) * 5      // Изученность до +5%
  
  const predictionAccuracy = Math.min(100, Math.max(50, baseAccuracy + materialAccuracyFactor))
  
  return {
    attack: {
      base: attackBase,
      min: Math.max(0, attackBase - attackDown),
      max: attackBase + attackUp,
    },
    durability: {
      base: durabilityBase,
      min: Math.max(0, durabilityBase - durabilityDown),
      max: durabilityBase + durabilityUp,
    },
    weight: weightValue,
    soulCapacity: {
      base: soulBase,
      min: Math.max(0, soulBase - soulDown),
      max: soulBase + soulUp,
    },
    quality: {
      min: Math.max(0, baseQualityValue - qualityVariance),
      max: Math.min(100, baseQualityValue + qualityVariance),
    },
    predictionAccuracy,
  }
}

/**
 * Рассчитать сравнение с текущим выбранным материалом
 */
export function calculateMaterialComparison(
  newMaterial: MaterialNode,
  currentMaterialId: string | null,
  recipe: WeaponRecipe,
  partId: string,
  blacksmithLevel: number,
  newMaterialExpertise: number,
  currentMaterialExpertise?: number
): MaterialComparison {
  const preview = calculateMaterialPreview(newMaterial, recipe, partId, blacksmithLevel, newMaterialExpertise)
  
  // Если нет текущего материала - дельта null
  if (!currentMaterialId) {
    return {
      preview,
      delta: {
        attack: null,
        durability: null,
        quality: null,
      },
    }
  }
  
  // Получаем текущий материал
  const currentMaterial = getMaterialById(currentMaterialId)
  if (!currentMaterial) {
    // Материал не найден - дельта null
    return {
      preview,
      delta: {
        attack: null,
        durability: null,
        quality: null,
      },
    }
  }
  
  // Рассчитываем превью для текущего материала с его экспертизой
  // Если экспертиза текущего материала не указана, используем экспертизу нового материала
  const expertiseForCurrent = currentMaterialExpertise ?? newMaterialExpertise
  const currentPreview = calculateMaterialPreview(
    currentMaterial,
    recipe,
    partId,
    blacksmithLevel,
    expertiseForCurrent
  )
  
  // Рассчитываем дельту
  return {
    preview,
    delta: {
      attack: {
        min: preview.attack.min - currentPreview.attack.min,
        max: preview.attack.max - currentPreview.attack.max,
      },
      durability: {
        min: preview.durability.min - currentPreview.durability.min,
        max: preview.durability.max - currentPreview.durability.max,
      },
      quality: {
        min: preview.quality.min - currentPreview.quality.min,
        max: preview.quality.max - currentPreview.quality.max,
      },
    },
  }
}

export default {
  calculateMaterialPreview,
  calculateMaterialComparison,
}

/**
 * Умная сортировка и фильтрация материалов для селектора
 */

import type { MaterialNode } from '@/types/materials/material-core'
import type { WeaponRecipe } from '@/types/craft-v2'
import type { Resources, ResourceKey } from '@/store/slices/resources-slice'
import type { MaterialKnowledge } from '@/types/materials/knowledge'
import { getResourceKeyForMaterial } from './inventory-check'
import { getMaterialRarity, type MaterialRarity } from '@/types/materials/material-core'

// ================================
// ТИПЫ
// ================================

/** Контекст для сортировки */
export interface SortContext {
  inventory: Resources
  knowledge: Record<string, MaterialKnowledge>
  recipe: WeaponRecipe
  partId: string
  blacksmithLevel: number
  dominantProperty?: string  // Главное свойство из рецепта
}

// ================================
// КОНСТАНТЫ
// ================================

const RARITY_VALUES: Record<MaterialRarity, number> = {
  common: 1,
  uncommon: 2,
  rare: 3,
  epic: 4,
  legendary: 5,
}

// ================================
// ФУНКЦИИ ФИЛЬТРАЦИИ
// ================================

/**
 * Фильтровать материалы по открытым в энциклопедии
 */
export function filterDiscoveredMaterials(
  materials: MaterialNode[],
  knowledge: Record<string, MaterialKnowledge>
): MaterialNode[] {
  return materials.filter(material => {
    const matKnowledge = knowledge[material.identity.id]
    return matKnowledge && matKnowledge.expertise > 0
  })
}

// ================================
// ФУНКЦИИ СОРТИРОВКИ
// ================================

/**
 * Умная сортировка материалов
 * Приоритет: доступность × качество × экспертиза × редкость
 */
export function smartSortMaterials(
  materials: MaterialNode[],
  context: SortContext
): MaterialNode[] {
  // Копируем массив для неизменности
  return [...materials].sort((a, b) => {
    const scoreA = calculateMaterialScore(a, context)
    const scoreB = calculateMaterialScore(b, context)
    
    // Сортировка по убыванию оценки
    return scoreB - scoreA
  })
}

/**
 * Рассчитать оценку материала для сортировки
 * Чем выше оценка, тем выше материал в списке
 */
function calculateMaterialScore(material: MaterialNode, context: SortContext): number {
  const { inventory, knowledge, recipe, partId, blacksmithLevel, dominantProperty } = context
  
  // 1. Доступность (вес 40%) - 40 баллов максимум
  const availabilityScore = calculateAvailabilityScore(material, inventory)
  
  // 2. Качество для данной части (вес 30%) - 30 баллов максимум
  const qualityScore = calculateQualityScore(material, recipe, partId, dominantProperty)
  
  // 3. Экспертиза (вес 20%) - 20 баллов максимум
  const expertiseScore = calculateExpertiseScore(material, knowledge)
  
  // 4. Редкость (вес 10%) - 10 баллов максимум
  const rarityScore = calculateRarityScore(material)
  
  // Общая оценка
  return availabilityScore * 0.4 + 
         qualityScore * 0.3 + 
         expertiseScore * 0.2 + 
         rarityScore * 0.1
}

/**
 * Оценка доступности материала
 * Есть в инвентаре = 100, нет = 0
 */
function calculateAvailabilityScore(
  material: MaterialNode,
  inventory: Resources
): number {
  const resourceKey = getResourceKeyForMaterial(material.identity.id)
  if (!resourceKey) return 0
  
  const quantity = inventory[resourceKey] || 0
  // Нормализуем: 0 = 0, >=1 = 100
  return quantity > 0 ? 100 : 0
}

/**
 * Оценка качества материала для данной части
 */
function calculateQualityScore(
  material: MaterialNode,
  recipe: WeaponRecipe,
  partId: string,
  dominantProperty?: string
): number {
  const rarityValue = RARITY_VALUES[getMaterialRarity(material.economy)] // 1-5
  const normalizedRarity = ((rarityValue - 1) / 4) * 50 // 0-50
  
  // Свойства важные для разных частей
  const physical = material.physical
  const arcane = material.arcane
  const properties = material.properties
  
  let propertyScore = 0
  
  // Если в рецепте указано главное свойство, используем его
  if (dominantProperty) {
    const propValue = getDominantPropertyValue(material, dominantProperty)
    propertyScore = propValue / 100 * 50
  } else {
    // Иначе используем старую логику на основе части
    switch (partId) {
      case 'blade':
        // Для лезвия важны: твёрдость + проводимость
        propertyScore = (physical.hardness * 0.6 + arcane.conductivity * 0.4) / 100 * 50
        break
        
      case 'guard':
      case 'pommel':
        // Для гарды/навершия важны: твёрдость + прочность
        propertyScore = (physical.hardness * 0.7 + physical.toughness * 0.3) / 100 * 50
        break
        
      case 'grip':
        // Для рукояти важны: гибкость + меньше вес (используем density)
        propertyScore = (physical.elasticity * 0.8 + (100 - physical.density) * 0.2) / 100 * 50
        break
        
      default:
        // По умолчанию: среднее значение
        propertyScore = (physical.hardness + physical.toughness + physical.elasticity) / 3
        break
    }
  }
  
  return Math.min(50, normalizedRarity + propertyScore * 0.5)
}

/**
 * Получить значение главного свойства материала
 */
function getDominantPropertyValue(material: MaterialNode | undefined, prop: string | undefined): number {
  if (!material || !prop) return 50
  const physical = material.physical
  const arcane = material.arcane
  
  const propMap: Record<string, number> = {
    hardness: physical?.hardness ?? 50,
    elasticity: physical?.elasticity ?? 50,
    toughness: physical?.toughness ?? 50,
    weight: physical?.density ?? 50,  // Используем density вместо weight
    conductivity: arcane?.conductivity ?? 50
  }
  
  return propMap[prop] ?? 50
}

/**
 * Оценка экспертизы
 */
function calculateExpertiseScore(
  material: MaterialNode,
  knowledge: Record<string, MaterialKnowledge>
): number {
  const matKnowledge = knowledge[material.identity.id]
  if (!matKnowledge) return 0
  
  // Экспертиза 0-100 -> оценка 0-20
  return matKnowledge.expertise * 0.2
}

/**
 * Оценка редкости
 */
function calculateRarityScore(material: MaterialNode): number {
  const rarityValue = RARITY_VALUES[getMaterialRarity(material.economy)] // 1-5
  // Нормализуем в 0-10
  return ((rarityValue - 1) / 4) * 10
}

// ================================
// ВСПОМОГАТЕЛЬНЫЕ ФУНКЦИИ
// ================================

/**
 * Проверить, есть ли материал в инвентаре
 */
export function isMaterialAvailable(
  material: MaterialNode,
  inventory: Resources
): boolean {
  const resourceKey = getResourceKeyForMaterial(material.identity.id)
  if (!resourceKey) return false
  
  return (inventory[resourceKey] || 0) > 0
}

/**
 * Получить количество материала в инвентаре
 */
export function getMaterialQuantity(
  material: MaterialNode,
  inventory: Resources
): number {
  const resourceKey = getResourceKeyForMaterial(material.identity.id)
  if (!resourceKey) return 0
  
  return inventory[resourceKey] || 0
}

export default {
  filterDiscoveredMaterials,
  smartSortMaterials,
  isMaterialAvailable,
  getMaterialQuantity,
}

/**
 * Генератор имён оружия
 * Создаёт имя по формуле: [РанговыйПрефикс] [Материал] [База] [Суффикс]
 * Пример: "Обычный Стальной меч остроты II"
 * 
 * @see docs/CRAFT_SYSTEM_CONCEPT.md - секция 8.1 Система именования
 */

import type { 
  Material, 
  WeaponRecipe, 
  DominantPropertyType,
  QualityGrade,
  QualityRank 
} from '@/types/craft-v2'
import { 
  SUFFIX_RULES, 
  ROMAN_NUMERALS, 
  calculateSuffixLevel,
  getQualityRank,
  getQualityRankPrefix 
} from '@/types/craft-v2'

/**
 * Результат генерации имени
 */
export interface WeaponNameResult {
  prefix: string              // "Стальной" (от материала)
  baseName: string            // "меч"
  suffix: string             // "остроты II"
  fullName: string           // "Обычный Стальной меч остроты II"
  qualityRank: QualityRank   // "C"
  qualityPrefix: string      // "Хороший"
}

/**
 * Сгенерировать имя оружия
 * 
 * @param recipe Рецепт оружия
 * @param combatMaterial Материал боевой части (лезвие для меча)
 * @param quality Качество оружия (0-100) для определения ранга
 */
export function generateWeaponName(
  recipe: WeaponRecipe,
  combatMaterial: Material | null,
  quality: number = 50
): WeaponNameResult {
  // 1. База — всегда из рецепта
  const baseName = recipe.name
  
  // 2. Префикс материала — из материала боевой части
  const materialPrefix = combatMaterial?.adjective || ''
  
  // 3. Суффикс — из доминирующего свойства материала
  const suffix = generateSuffix(combatMaterial)
  
  // 4. Ранговый префикс от качества
  const qualityRank = getQualityRank(quality)
  const qualityPrefix = getQualityRankPrefix(qualityRank)
  
  // 5. Полное имя: [РанговыйПрефикс] [Материал] [База] [Суффикс]
  const parts = [qualityPrefix, materialPrefix, baseName, suffix].filter(Boolean)
  const fullName = parts.join(' ')
  
  return {
    prefix: materialPrefix,
    baseName,
    suffix,
    fullName,
    qualityRank,
    qualityPrefix,
  }
}

/**
 * Сгенерировать суффикс
 */
function generateSuffix(material: Material | null): string {
  if (!material?.dominantProperty) return ''
  
  const { type, value } = material.dominantProperty
  
  // Находим правило для этого свойства
  const rule = SUFFIX_RULES.find(r => r.property === type)
  if (!rule) return ''
  
  // Проверяем порог
  if (value < rule.threshold) return ''
  
  // Рассчитываем уровень
  const level = calculateSuffixLevel(value, rule.threshold, rule.levelStep)
  if (level < 1) return ''
  
  // Формируем суффикс
  const numeral = ROMAN_NUMERALS[level - 1] || ''
  return `${rule.name} ${numeral}`
}

/**
 * Получить уровень суффикса (для отображения в UI)
 */
export function getSuffixLevel(material: Material | null): number {
  if (!material?.dominantProperty) return 0
  
  const { type, value } = material.dominantProperty
  const rule = SUFFIX_RULES.find(r => r.property === type)
  if (!rule) return 0
  
  return calculateSuffixLevel(value, rule.threshold, rule.levelStep)
}

/**
 * Получить описание суффикса
 */
export function getSuffixDescription(type: DominantPropertyType): string {
  const descriptions: Record<DominantPropertyType, string> = {
    sharpness: 'Увеличивает урон оружия',
    durability: 'Увеличивает прочность оружия',
    balance: 'Улучшает баланс и эффективность',
    conductivity: 'Усиливает магические свойства',
    lightness: 'Уменьшает вес оружия',
  }
  return descriptions[type] || ''
}

export default {
