  getSuffixLevel,
  getSuffixDescription,
}

/**
 * Генератор процесса крафта
 * Создаёт последовательность этапов из рецепта с учётом материалов и техник
 */

import type { 
  WeaponRecipe, 
  Material, 
  Technique, 
  CraftStageInstance, 
  MaterialAssignment,
  CraftPlan,
  ActiveCraftV2,
  GameConfig,
  StageTypeDefinition
} from '@/types/craft-v2'
import { DEFAULT_GAME_CONFIG } from '@/types/craft-v2'
import { getStageById, allStages } from '@/data/stages'
import { getMaterialAsLegacy } from '@/data/materials'

/**
 * Контекст для генерации процесса
 */
interface GenerationContext {
  recipe: WeaponRecipe
  materials: MaterialAssignment
  techniques: Technique[]
  blacksmithLevel: number
  forgeLevel: number
  config: GameConfig
}

/**
 * Сгенерировать экземпляры этапов из плана крафта
 */
export function generateCraftStages(
  recipe: WeaponRecipe,
  materials: MaterialAssignment,
  techniques: Technique[] = [],
  blacksmithLevel: number = 1,
  forgeLevel: number = 1,
  config: GameConfig = DEFAULT_GAME_CONFIG,
  shouldPurchaseMaterials: boolean = false
): CraftStageInstance[] {
  const context: GenerationContext = {
    recipe,
    materials,
    techniques,
    blacksmithLevel,
    forgeLevel,
    config,
  }
  
  // 1. Базовая последовательность этапов из рецепта
  let stageConfigs = [...recipe.stages]
  
  // 2. Добавляем этап закупки материалов, если нужно
  if (shouldPurchaseMaterials) {
    stageConfigs.unshift({ stageType: 'proc_purchasing' })
  }
  
  // 3. Применяем модификации от материалов
  stageConfigs = applyMaterialMods(stageConfigs, materials, context)
  
  // 3. Применяем модификации от техник
  stageConfigs = applyTechniqueMods(stageConfigs, techniques, context)
  
  // 4. Создаём экземпляры этапов
  const instances: CraftStageInstance[] = stageConfigs.map((config, index) => {
    const stageType = getStageById(config.stageType)
    if (!stageType) {
      console.warn(`Stage type not found: ${config.stageType}`)
      return null
    }
    
    return createStageInstance(
      stageType,
      config,
      index,
      context
    )
  }).filter(Boolean) as CraftStageInstance[]
  
  return instances
}

/**
 * Применить модификации от материалов
 */
function applyMaterialMods(
  stages: WeaponRecipe['stages'],
  materials: MaterialAssignment,
  context: GenerationContext
): WeaponRecipe['stages'] {
  const result = [...stages]
  
  // Для каждого материала проверяем processingProfile
  for (const [partId, { materialId }] of Object.entries(materials)) {
    const material = getMaterialAsLegacy(materialId)
    if (!material?.processingProfile?.stages) continue
    
    const { replacements, forbidden } = material.processingProfile.stages
    
    // Удаляем запрещённые этапы
    if (forbidden) {
      for (let i = result.length - 1; i >= 0; i--) {
        if (forbidden.includes(result[i].stageType)) {
          result.splice(i, 1)
        }
      }
    }
    
    // Заменяем этапы
    if (replacements) {
      for (let i = 0; i < result.length; i++) {
        const replacement = replacements[result[i].stageType]
        if (replacement) {
          result[i] = { ...result[i], stageType: replacement }
        }
      }
    }
  }
  
  return result
}

/**
 * Применить модификации от техник
 */
function applyTechniqueMods(
  stages: WeaponRecipe['stages'],
  techniques: Technique[],
  context: GenerationContext
): WeaponRecipe['stages'] {
  const result = [...stages]
  
  for (const technique of techniques) {
    if (!technique.processMods) continue
    
    const { replaceStage, addStage } = technique.processMods
    
    // Замена этапов
    if (replaceStage) {
      for (let i = 0; i < result.length; i++) {
        const replacement = replaceStage[result[i].stageType]
        if (replacement) {
          result[i] = { ...result[i], stageType: replacement }
        }
      }
    }
    
    // Добавление этапов
    if (addStage) {
      const insertIndex = addStage.after
        ? result.findIndex(s => s.stageType === addStage.after) + 1
        : addStage.before
        ? result.findIndex(s => s.stageType === addStage.before)
        : result.length
      
      if (insertIndex >= 0) {
        result.splice(insertIndex, 0, { stageType: addStage.stage })
      }
    }
  }
  
  return result
}

/**
 * Создать экземпляр этапа
 */
function createStageInstance(
  stageType: StageTypeDefinition,
  config: { stageType: string; material?: string; target?: string },
  index: number,
  context: GenerationContext
): CraftStageInstance {
  // Получаем материал для расчёта модификаторов
  const material = config.material && context.materials[config.material]
    ? getMaterialAsLegacy(context.materials[config.material].materialId)
    : null
  
  // Рассчитываем длительность
  const baseDuration = stageType.baseDuration
  const calculatedDuration = calculateStageDuration(
    baseDuration,
    stageType,
    material ?? null,
    context
  )
  
  // Выбираем сообщения
  const startMessage = selectMessage(stageType.messages.start)
  const completeMessage = selectMessage(stageType.messages.complete)
  
  return {
    id: `stage_${index}_${Date.now()}`,
    stageTypeId: stageType.id,
    name: stageType.name,
    category: stageType.category,
    materialId: config.material,
    target: config.target,
    baseDuration,
    calculatedDuration,
    status: 'pending',
    progress: 0,
    startMessage,
    completeMessage,
    requirements: stageType.requirements,
    environmentRequired: stageType.environmentRequired,
  }
}

/**
 * Рассчитать длительность этапа с модификаторами
 */
function calculateStageDuration(
  baseDuration: number,
  stageType: StageTypeDefinition,
  material: Material | null,
  context: GenerationContext
): number {
  let duration = baseDuration
  
  // Глобальный множитель
  duration *= context.config.craftSpeedMultiplier
  
  // Модификаторы этапа
  if (stageType.durationModifiers) {
    // Навык кузнеца
    if (stageType.durationModifiers.skill) {
      const reduction = context.blacksmithLevel * 0.03  // -3% за уровень
      duration *= (1 - reduction)
    }
    
    // Уровень кузницы
    if (stageType.durationModifiers.tool) {
      const reduction = context.forgeLevel * 0.05  // -5% за уровень
      duration *= (1 - reduction)
    }
    
    // Материал (обрабатываемость)
    if (stageType.durationModifiers.material && material) {
      const workability = material.crafting.workability
      duration *= (100 / workability)  // Чем ниже workability, тем дольше
    }
  }
  
  // Минимум 5 секунд
  return Math.max(5, Math.round(duration))
}

/**
 * Выбрать случайное сообщение из списка
 */
function selectMessage(messages: string[]): string {
  if (!messages || messages.length === 0) return '...'
  return messages[Math.floor(Math.random() * messages.length)]
}

/**
 * Создать план крафта
 */
export function createCraftPlan(
  recipeId: string,
  materials: MaterialAssignment,
  techniqueIds: string[] = [],
  blacksmithLevel: number = 1,
  forgeLevel: number = 1,
  shouldPurchaseMaterials: boolean = false
): CraftPlan {
  // Загружаем рецепт
  const { getRecipeById } = require('@/data/recipes')
  const recipe = getRecipeById(recipeId)
  if (!recipe) {
    throw new Error(`Recipe not found: ${recipeId}`)
  }
  
  // Загружаем техники
  const { getTechniqueById } = require('@/data/techniques')
  const techniques: Technique[] = techniqueIds
    .map(id => getTechniqueById(id))
    .filter((t): t is Technique => t !== undefined)
  
  // Генерируем этапы
  const stages = generateCraftStages(
    recipe,
    materials,
    techniques,
    blacksmithLevel,
    forgeLevel,
    undefined,
    shouldPurchaseMaterials
  )
  
  // Рассчитываем общее время
  const estimatedTime = stages.reduce((sum, s) => sum + s.calculatedDuration, 0)
  
  // Рассчитываем характеристики
  const estimatedStats = calculateWeaponStats(recipe, materials, techniques, blacksmithLevel)
  
  // Оценка качества
  const estimatedQuality = estimateQuality(blacksmithLevel, materials, techniques)
  
  return {
    recipeId,
    materials,
    techniques: techniqueIds,
    shouldPurchaseMaterials,
    estimatedTime,
    estimatedStats,
    estimatedQuality,
  }
}

/**
 * Рассчитать характеристики оружия
 */
function calculateWeaponStats(
  recipe: WeaponRecipe,
  materials: MaterialAssignment,
  techniques: Technique[],
  blacksmithLevel: number
): CraftPlan['estimatedStats'] {
  const base = recipe.baseStats
  
  // Начальные значения из базы
  let attack = base.attackBase
  let durability = base.durabilityBase
  let weight = base.weightBase
  let soulCapacity = base.soulCapacityBase
  let balance = 75 // базовый баланс
  let repairPotential = 1.0
  let enchantSlots = 0
  let enchantPower = 1.0
  
  // Применяем бонусы от материалов
  for (const [partId, { materialId }] of Object.entries(materials)) {
    const material = getMaterialAsLegacy(materialId)
    if (!material) continue
    
    // Бонусы к атаке
    attack += attack * (material.weaponEffects.attackBonus / 100)
    
    // Бонусы к прочности
    durability += durability * (material.weaponEffects.durabilityBonus / 100)
    
    // Вместимость души
    soulCapacity += material.weaponEffects.soulCapacity
    
    // Вес
    weight += material.properties.weight * 0.1
    
    // Дополнительные свойства
    repairPotential = Math.max(repairPotential, material.weaponEffects.repairPotential)
    enchantSlots += material.weaponEffects.enchantSlots
    enchantPower *= material.weaponEffects.enchantPower
  }
  
  // Применяем бонусы от техник
  for (const technique of techniques) {
    if (technique.effects.qualityBonus) {
      attack *= 1 + (technique.effects.qualityBonus / 100)
    }
  }
  
  return {
    attack: Math.round(attack),
    durability: Math.round(durability),
    maxDurability: Math.round(durability),
    weight: Math.round(weight * 10) / 10,
    balance: Math.round(balance),
    soulCapacity: Math.round(soulCapacity),
    repairPotential,
    enchantSlots,
    enchantPower,
  }
}

/**
 * Оценить качество оружия
 */
function estimateQuality(
  blacksmithLevel: number,
  materials: MaterialAssignment,
  techniques: Technique[]
): CraftPlan['estimatedQuality'] {
  // Базовое качество от уровня кузнеца
  let quality = 30 + blacksmithLevel * 2
  
  // Бонус от техник
  for (const technique of techniques) {
    if (technique.effects.qualityBonus) {
      quality += technique.effects.qualityBonus * 0.5
    }
  }
  
  // Ограничение
  quality = Math.min(100, Math.max(0, quality))
  
  // Определяем градацию
  if (quality >= 96) return 'legendary'
  if (quality >= 86) return 'masterpiece'
  if (quality >= 71) return 'excellent'
  if (quality >= 51) return 'good'
  if (quality >= 31) return 'common'
  return 'poor'
}

/**
 * Создать активный процесс крафта
 */
export function createActiveCraft(
  plan: CraftPlan,
  recipe: WeaponRecipe
): ActiveCraftV2 {
  const stages = generateCraftStages(
    recipe,
    plan.materials,
    [], // техники уже применены в плане
    1,  // уровень кузнеца
    1,  // уровень кузницы
    undefined, // config
    plan.shouldPurchaseMaterials ?? false
  )
  
  const totalDuration = stages.reduce((sum, s) => sum + s.calculatedDuration, 0)
  
  return {
    id: `craft_${Date.now()}`,
    plan,
    stages,
    currentStageIndex: 0,
    startTime: Date.now(),
    totalDuration,
    elapsedTime: 0,
    status: 'planning',
    log: [],
  }
}

export default {
  generateCraftStages,
  createCraftPlan,
  createActiveCraft,
}

/**
 * Turso/libSQL клиент для SwordCraft
 * Прямое подключение без Prisma adapter
 *
 * Схема Turso (этот файл + миграции ниже) — источник правды для облачных сейвов.
 * Prisma (prisma/schema.prisma, file:./dev.db) — локальная SQLite для prisma generate / опциональных утилит;
 * при изменении колонок game_saves синхронизируйте DDL здесь, Prisma-модель и POST/GET в src/app/api/save/route.ts
 */

import { createClient, type Client } from '@libsql/client'

const globalForDb = globalThis as unknown as {
  turso: Client | undefined
  tablesInitialized: boolean
}

// SQL для создания таблиц
const CREATE_TABLES_SQL = `
CREATE TABLE IF NOT EXISTS game_saves (
  id TEXT PRIMARY KEY,
  playerId TEXT UNIQUE,
  level INTEGER DEFAULT 1,
  experience INTEGER DEFAULT 0,
  fame INTEGER DEFAULT 0,
  resources TEXT DEFAULT '{}',
  statistics TEXT DEFAULT '{}',
  workers TEXT DEFAULT '[]',
  buildings TEXT DEFAULT '[]',
  maxWorkers INTEGER DEFAULT 3,
  activeCraft TEXT DEFAULT '{}',
  activeRefining TEXT DEFAULT '{}',
  weaponInventory TEXT DEFAULT '{"weapons":[]}',
  unlockedRecipes TEXT DEFAULT '{"weaponRecipes":["sword_iron","dagger_iron","sword_bronze","dagger_bronze","sword_copper","dagger_copper"],"refiningRecipes":[]}',
  recipeSources TEXT DEFAULT '[]',
  unlockedEnchantments TEXT DEFAULT '[]',
  guild TEXT DEFAULT '{}',
  knownAdventurers TEXT DEFAULT '[]',
  orders TEXT DEFAULT '{}',
  tutorial TEXT DEFAULT '{"isActive":true,"currentStep":0}',
  materialKnowledge TEXT DEFAULT '{}',
  createdAt TEXT DEFAULT (datetime('now')),
  updatedAt TEXT DEFAULT (datetime('now')),
  playTime INTEGER DEFAULT 0,
  saveVersion INTEGER DEFAULT 2
);

CREATE TABLE IF NOT EXISTS save_history (
  id TEXT PRIMARY KEY,
  gameSaveId TEXT,
  snapshot TEXT,
  createdAt TEXT DEFAULT (datetime('now'))
);

CREATE INDEX IF NOT EXISTS save_history_gameSaveId_idx ON save_history(gameSaveId);
`

function createDbClient(): Client | null {
  const url = process.env.TURSO_DATABASE_URL
  const authToken = process.env.TURSO_AUTH_TOKEN

  if (!url) {
    console.warn('[DB] TURSO_DATABASE_URL not found')
    return null
  }

  console.log('[DB] Connecting to Turso:', url.substring(0, 30) + '...')

  return createClient({
    url,
    authToken: authToken || undefined,
  })
}

async function initializeTables(db: Client): Promise<void> {
  if (globalForDb.tablesInitialized) return

  try {
    console.log('[DB] Creating tables if not exist...')

    const statements = CREATE_TABLES_SQL.split(';').filter(s => s.trim())

    for (const statement of statements) {
      const sql = statement.trim()
      if (sql) {
        await db.execute(sql)
      }
    }

    await ensureGameSavesColumns(db)

    globalForDb.tablesInitialized = true
    console.log('[DB] Tables initialized successfully')
  } catch (error) {
    console.error('[DB] Failed to initialize tables:', error)
    throw error
  }
}

/** Добавляет колонки, появившиеся после первого деплоя (SQLite ALTER). */
async function ensureGameSavesColumns(db: Client): Promise<void> {
  const info = await db.execute({ sql: 'PRAGMA table_info(game_saves)' })
  const names = new Set<string>()
  for (const r of info.rows) {
    const row = r as Record<string, unknown>
    const n = row['name']
    if (typeof n === 'string' && n) names.add(n)
  }
  if (!names.has('materialKnowledge')) {
    await db.execute({
      sql: "ALTER TABLE game_saves ADD COLUMN materialKnowledge TEXT DEFAULT '{}'",
    })
  }
}

export function getDb(): Client | null {
  if (!globalForDb.turso) {
    globalForDb.turso = createDbClient()
  }
  return globalForDb.turso
}

// Инициализация таблиц при первом обращении
export async function initDb(): Promise<Client | null> {
  const db = getDb()
  if (db) {
    await initializeTables(db)
  }
  return db
}

export { createDbClient }
export type { Client }

/**
 * Утилиты для расчёта результатов экспедиции
 * Версия 2.0 — Использует унифицированную систему модификаторов
 * 
 * ВАЖНО: Вся логика модификаторов вынесена в провайдеры.
 * Для добавления нового эффекта — создайте нового провайдера.
 * НЕ НУЖНО изменять этот файл для добавления новых модификаторов!
 */

import type { AdventurerExtended } from '@/types/adventurer-extended'
import type { ExpeditionTemplate, ExpeditionDifficulty, ExpeditionType } from '@/data/expedition-templates'
import { difficultyInfo } from '@/data/expedition-templates'
import { 
  calculateModifiers, 
  type ModifierContext,
  type AppliedModifier,
  type ModifierTarget,
} from './modifier-system'

// ================================
// ТИПЫ
// ================================

export interface ModifierDetail {
  source: string
  sourceIcon: string
  value: number
  description: string
  type: 'positive' | 'negative' | 'neutral'
}

export interface ExpeditionCalculation {
  successChance: number
  commission: number
  warSoul: number
  weaponWear: number
  weaponLossChance: number
  critChance: number

  successModifiers: ModifierDetail[]
  goldModifiers: ModifierDetail[]
  warSoulModifiers: ModifierDetail[]
  weaponLossModifiers: ModifierDetail[]
  weaponWearModifiers: ModifierDetail[]
  critModifiers: ModifierDetail[]

  levelMatch: {
    adventurerLevel: number
    missionTier: number
    missionTierName: string
    match: 'optimal' | 'underlevel' | 'overlevel' | 'dangerous'
    matchDescription: string
  }

  recommendation: {
    rating: 'excellent' | 'good' | 'risky' | 'dangerous'
    description: string
  }
}

// ================================
// КОНСТАНТЫ
// ================================

const BASE_COMMISSION_PERCENT = 15
const COMMISSION_PER_GUILD_LEVEL = 2
const MAX_COMMISSION_PERCENT = 30

const BASE_CRIT_CHANCE = 5 // 5% базовый шанс крита

// ================================
// ВСПОМОГАТЕЛЬНЫЕ ФУНКЦИИ
// ================================

function getRarityName(rarity: string): string {
  const names: Record<string, string> = {
    common: 'Обычный',
    uncommon: 'Необычный',
    rare: 'Редкий',
    epic: 'Эпический',
    legendary: 'Легендарный'
  }
  return names[rarity] || 'Обычный'
}

function getMissionTypeName(type: ExpeditionType): string {
  const names: Record<ExpeditionType, string> = {
    hunt: 'охоту',
    scout: 'разведку',
    clear: 'зачистку',
    delivery: 'доставку',
    magic: 'магические миссии'
  }
  return names[type] || 'миссию'
}

/**
 * Преобразовать AppliedModifier в ModifierDetail для UI
 */
function appliedToDetail(applied: AppliedModifier): ModifierDetail {
  return {
    source: applied.source.name,
    sourceIcon: applied.source.icon,
    value: applied.effectiveValue,
    description: applied.source.description || '',
    type: applied.effectiveValue > 0 ? 'positive' : applied.effectiveValue < 0 ? 'negative' : 'neutral'
  }
}

/**
 * Определить соответствие уровня
 */
function calculateLevelMatch(
  adventurerLevel: number,
  difficulty: ExpeditionDifficulty
): ExpeditionCalculation['levelMatch'] {
  const difficultyData = difficultyInfo[difficulty]
  const missionTier = difficultyData.tier
  const [minLevel, maxLevel] = difficultyData.levelRange

  if (adventurerLevel < minLevel - 5) {
    return {
      adventurerLevel,
      missionTier,
      missionTierName: difficultyData.tierName,
      match: 'dangerous',
      matchDescription: `Уровень искателя слишком низкий для этой миссии (рекомендуется ${minLevel}+)`
    }
  } else if (adventurerLevel > maxLevel + 10) {
    return {
      adventurerLevel,
      missionTier,
      missionTierName: difficultyData.tierName,
      match: 'overlevel',
      matchDescription: `Искатель слишком опытный для такой простой миссии`
    }
  } else if (adventurerLevel >= minLevel && adventurerLevel <= maxLevel) {
    return {
      adventurerLevel,
      missionTier,
      missionTierName: difficultyData.tierName,
      match: 'optimal',
      matchDescription: `Отличное соответствие уровню миссии`
    }
  } else {
    return {
      adventurerLevel,
      missionTier,
      missionTierName: difficultyData.tierName,
      match: 'underlevel',
      matchDescription: `Уровень чуть ниже рекомендованного, но допустимо`
    }
  }
}

// ================================
// ОСНОВНАЯ ФУНКЦИЯ РАСЧЁТА
// ================================

export function calculateExpeditionResult(
  adventurer: AdventurerExtended,
  expedition: ExpeditionTemplate,
  guildLevel: number,
  weaponAttack: number,
  weaponDurability: number = 50,
  weaponType: string = 'sword',
  weaponId: string = 'weapon_0',
  // Новые параметры для CraftedWeaponV2 (опциональные для обратной совместимости)
  weaponQualityRank?: string,
  weaponEpicMultiplier?: number,
  weaponCombatMaterialId?: string,
  weaponQuality?: number
): ExpeditionCalculation {
  // ===== 1. ПОДГОТОВКА КОНТЕКСТА (v2 - с новыми полями оружия) =====
  const context: ModifierContext = {
    adventurer,
    expedition: {
      id: expedition.id,
      type: expedition.type,
      difficulty: expedition.difficulty,
      duration: expedition.duration,
      minWeaponAttack: expedition.minWeaponAttack || 5,
      enemyTypes: [], // TODO: добавить в шаблон
    },
    weapon: {
      id: weaponId,
      type: weaponType as any,
      attack: weaponAttack,
      quality: weaponQuality ?? 50,
      qualityRank: weaponQualityRank,
      epicMultiplier: weaponEpicMultiplier,
      combatMaterialId: weaponCombatMaterialId,
      durability: weaponDurability,
      currentDurability: weaponDurability,
    },
    guild: {
      level: guildLevel,
      glory: 0, // TODO: передать из контекста
    },
  }

  // ===== 2. БАЗОВЫЕ ЗНАЧЕНИЯ =====
  const difficultyData = difficultyInfo[expedition.difficulty]
  const baseSuccess = 100 - difficultyData.failureChance
  const baseGold = expedition.reward?.baseGold || 50
  const baseWarSoul = expedition.reward?.baseWarSoul || 3
  const baseWeaponLoss = difficultyData.weaponLossChance || 5
  const baseWeaponWear = 10

  const baseValues: Record<ModifierTarget, number> = {
    successChance: baseSuccess,
    gold: baseGold,
    warSoul: baseWarSoul,
    glory: 0,
    weaponWear: baseWeaponWear,
    weaponLossChance: baseWeaponLoss,
    critChance: BASE_CRIT_CHANCE,
    commission: 0,
  }

  // ===== 3. РАСЧЁТ ЧЕРЕЗ СИСТЕМУ МОДИФИКАТОРОВ =====
  const result = calculateModifiers(context, baseValues)

  // ===== 4. ФОРМИРОВАНИЕ РЕЗУЛЬТАТОВ =====

  // Шанс успеха (ограничен 5-95%)
  const finalSuccess = Math.max(5, Math.min(95, result.totals.successChance))

  // Золото (базовое * множители)
  // Модификаторы золота — это проценты, преобразуем в множитель
  let goldMult = 1
  const goldModifiers = result.byTarget.gold.filter(m => m.applied)
  for (const mod of goldModifiers) {
    goldMult += mod.effectiveValue / 100
  }
  const finalGold = Math.floor(baseGold * goldMult)

  // Комиссия
  const commissionPercent = Math.min(
    MAX_COMMISSION_PERCENT,
    BASE_COMMISSION_PERCENT + (guildLevel - 1) * COMMISSION_PER_GUILD_LEVEL
  )
  const finalCommission = Math.floor(finalGold * commissionPercent / 100)

  // Души войны
  let warSoulMult = 1
  const warSoulModifiers = result.byTarget.warSoul.filter(m => m.applied)
  for (const mod of warSoulModifiers) {
    warSoulMult += mod.effectiveValue / 100
  }
  const finalWarSoul = Math.max(1, Math.floor(baseWarSoul * warSoulMult))

  // Износ оружия
  let weaponWearMod = 0
  const weaponWearModifiers = result.byTarget.weaponWear.filter(m => m.applied)
  for (const mod of weaponWearModifiers) {
    weaponWearMod += mod.effectiveValue
  }
  const finalWeaponWear = Math.max(1, Math.min(50, baseWeaponWear + weaponWearMod))

  // Шанс потери оружия
  let weaponLossMod = 0
  const weaponLossModifiers = result.byTarget.weaponLossChance.filter(m => m.applied)
  for (const mod of weaponLossModifiers) {
    weaponLossMod += mod.effectiveValue
  }
  const finalWeaponLoss = Math.max(0, Math.min(50, baseWeaponLoss + weaponLossMod))

  // Шанс крита
  let critChance = BASE_CRIT_CHANCE
  const critModifiers = result.byTarget.critChance.filter(m => m.applied)
  for (const mod of critModifiers) {
    critChance += mod.effectiveValue
  }
  const finalCritChance = Math.max(0, Math.min(25, critChance))

  // ===== 5. ФОРМИРОВАНИЕ МОДИФИКАТОРОВ ДЛЯ UI =====

  const toModifierDetail = (applied: AppliedModifier): ModifierDetail => ({
    source: applied.source.name,
    sourceIcon: applied.source.icon,
    value: applied.effectiveValue,
    description: applied.source.description || '',
    type: applied.effectiveValue > 0 ? 'positive' : applied.effectiveValue < 0 ? 'negative' : 'neutral'
  })

  // ===== 6. РЕКОМЕНДАЦИЯ =====
  let recommendation: ExpeditionCalculation['recommendation']

  if (finalSuccess >= 80) {
    recommendation = {
      rating: 'excellent',
      description: 'Отличный выбор! Высокий шанс успеха и хорошая награда.'
    }
  } else if (finalSuccess >= 60) {
    recommendation = {
      rating: 'good',
      description: 'Хороший выбор. Шанс успеха приемлемый.'
    }
  } else if (finalSuccess >= 40) {
    recommendation = {
      rating: 'risky',
      description: 'Рискованно. Есть значительный шанс провала.'
    }
  } else {
    recommendation = {
      rating: 'dangerous',
      description: 'Опасно! Высокий риск провала и потери оружия.'
    }
  }

  // ===== 7. ВОЗВРАТ РЕЗУЛЬТАТА =====
  return {
    successChance: Math.round(finalSuccess),
    commission: finalCommission,
    warSoul: finalWarSoul,
    weaponWear: Math.round(finalWeaponWear),
    weaponLossChance: Math.round(finalWeaponLoss),
    critChance: Math.round(finalCritChance),

    successModifiers: result.byTarget.successChance.filter(m => m.applied).map(toModifierDetail),
    goldModifiers: result.byTarget.gold.filter(m => m.applied).map(toModifierDetail),
    warSoulModifiers: result.byTarget.warSoul.filter(m => m.applied).map(toModifierDetail),
    weaponLossModifiers: result.byTarget.weaponLossChance.filter(m => m.applied).map(toModifierDetail),
    weaponWearModifiers: result.byTarget.weaponWear.filter(m => m.applied).map(toModifierDetail),
    critModifiers: result.byTarget.critChance.filter(m => m.applied).map(toModifierDetail),

    levelMatch: calculateLevelMatch(adventurer.combat.level, expedition.difficulty),
    recommendation,
  }
}

// ================================
// ФОРМАТИРОВАНИЕ
// ================================

export function formatModifierValue(value: number): string {
  const roundedValue = Math.round(value)
  return roundedValue > 0 ? `+${roundedValue}%` : `${roundedValue}%`
}

export function getRatingColor(rating: string): string {
  switch (rating) {
    case 'excellent': return 'text-green-400'
    case 'good': return 'text-blue-400'
    case 'risky': return 'text-amber-400'
    case 'dangerous': return 'text-red-400'
    default: return 'text-stone-400'
  }
}

export function getRatingBgColor(rating: string): string {
  switch (rating) {
    case 'excellent': return 'bg-green-900/30 border-green-600/50'
    case 'good': return 'bg-blue-900/30 border-blue-600/50'
    case 'risky': return 'bg-amber-900/30 border-amber-600/50'
    case 'dangerous': return 'bg-red-900/30 border-red-600/50'
    default: return 'bg-stone-900/30 border-stone-600/50'
  }
}

/**
 * Утилиты для расчёта результатов экспедиции
 * Явные формулы с показом влияния каждого фактора
 * 
 * ВАЖНО: Все эффекты берутся из реальных данных тегов
 */

import type { AdventurerExtended, Strength, Weakness } from '@/types/adventurer-extended'
import type { ExpeditionTemplate, ExpeditionDifficulty, ExpeditionType } from '@/data/expedition-templates'
import { difficultyInfo } from '@/data/expedition-templates'
import { getPersonalityTraitById } from '@/data/adventurer-tags/personality-traits'
import { getStrengthById, doesStrengthApply, type StrengthData } from '@/data/adventurer-tags/strengths'
import { getWeaknessById, doesWeaknessApply, type WeaknessData } from '@/data/adventurer-tags/weaknesses'
import { getSocialTagById } from '@/data/adventurer-tags/social-tags'
import { getCombatStyleById, getMissionBonus } from '@/data/adventurer-tags/combat-styles'

// ================================
// ТИПЫ
// ================================

export interface ModifierDetail {
  source: string      // Источник модификатора
  sourceIcon: string  // Иконка источника
  value: number       // Значение (+ или -)
  description: string // Описание влияния
  type: 'positive' | 'negative' | 'neutral'
}

export interface ExpeditionCalculation {
  // Основные результаты
  successChance: number
  commission: number
  warSoul: number
  weaponWear: number
  weaponLossChance: number
  
  // Детализация модификаторов
  successModifiers: ModifierDetail[]
  goldModifiers: ModifierDetail[]
  warSoulModifiers: ModifierDetail[]
  weaponLossModifiers: ModifierDetail[]
  weaponWearModifiers: ModifierDetail[]
  
  // Соответствие уровню миссии
  levelMatch: {
    adventurerLevel: number
    missionTier: number
    missionTierName: string
    match: 'optimal' | 'underlevel' | 'overlevel' | 'dangerous'
    matchDescription: string
  }
  
  // Рекомендация
  recommendation: {
    rating: 'excellent' | 'good' | 'risky' | 'dangerous'
    description: string
  }
}

// ================================
// КОНСТАНТЫ
// ================================

// Базовая комиссия гильдии
const BASE_COMMISSION_PERCENT = 15
const COMMISSION_PER_GUILD_LEVEL = 2
const MAX_COMMISSION_PERCENT = 30

// Множители редкости
const RARITY_MULTIPLIERS = {
  common: { gold: 1.0, warSoul: 1.0 },
  uncommon: { gold: 1.1, warSoul: 1.15 },
  rare: { gold: 1.2, warSoul: 1.3 },
  epic: { gold: 1.35, warSoul: 1.5 },
  legendary: { gold: 1.5, warSoul: 2.0 },
}

// ================================
// ОСНОВНАЯ ФУНКЦИЯ РАСЧЁТА
// ================================

export function calculateExpeditionResult(
  adventurer: AdventurerExtended,
  expedition: ExpeditionTemplate,
  guildLevel: number,
  weaponAttack: number,
  weaponQuality: number = 50
): ExpeditionCalculation {
  const successModifiers: ModifierDetail[] = []
  const goldModifiers: ModifierDetail[] = []
  const warSoulModifiers: ModifierDetail[] = []
  const weaponLossModifiers: ModifierDetail[] = []
  const weaponWearModifiers: ModifierDetail[] = []

  // Получаем информацию о сложности и типе миссии
  const difficulty = expedition.difficulty
  const missionType = expedition.type
  const difficultyData = difficultyInfo[difficulty]
  
  // ===== 1. РАСЧЁТ СООТВЕТСТВИЯ УРОВНЯ =====
  const adventurerLevel = adventurer.combat.level
  const missionTier = difficultyData.tier
  const [minLevel, maxLevel] = difficultyData.levelRange
  
  let baseSuccess = 100 - difficultyData.failureChance
  let levelMatch: ExpeditionCalculation['levelMatch']
  
  if (adventurerLevel < minLevel - 5) {
    // Опасно — уровень слишком низкий
    levelMatch = {
      adventurerLevel,
      missionTier,
      missionTierName: difficultyData.tierName,
      match: 'dangerous',
      matchDescription: `Уровень искателя слишком низкий для этой миссии (рекомендуется ${minLevel}+)`
    }
    const penalty = Math.min(30, (minLevel - adventurerLevel) * 3)
    baseSuccess -= penalty
    successModifiers.push({
      source: 'Уровень',
      sourceIcon: '📉',
      value: -penalty,
      description: `Слишком низкий уровень (${adventurerLevel} против рекомендованного ${minLevel}+)`,
      type: 'negative'
    })
  } else if (adventurerLevel > maxLevel + 10) {
    // Скучно — уровень слишком высокий
    levelMatch = {
      adventurerLevel,
      missionTier,
      missionTierName: difficultyData.tierName,
      match: 'overlevel',
      matchDescription: `Искатель слишком опытный для такой простой миссии`
    }
    const penalty = Math.min(15, (adventurerLevel - maxLevel - 10) * 1.5)
    baseSuccess -= penalty
    successModifiers.push({
      source: 'Скука',
      sourceIcon: '😴',
      value: -penalty,
      description: 'Опытному искателю скучно на лёгких миссиях',
      type: 'negative'
    })
  } else if (adventurerLevel >= minLevel && adventurerLevel <= maxLevel) {
    // Оптимально
    levelMatch = {
      adventurerLevel,
      missionTier,
      missionTierName: difficultyData.tierName,
      match: 'optimal',
      matchDescription: `Отличное соответствие уровню миссии`
    }
    baseSuccess += 5
    successModifiers.push({
      source: 'Уровень',
      sourceIcon: '✓',
      value: 5,
      description: 'Идеальное соответствие уровню миссии',
      type: 'positive'
    })
  } else {
    // Допустимо
    levelMatch = {
      adventurerLevel,
      missionTier,
      missionTierName: difficultyData.tierName,
      match: 'underlevel',
      matchDescription: `Уровень чуть ниже рекомендованного, но допустимо`
    }
  }
  
  // ===== 2. ВЛИЯНИЕ ОРУЖИЯ =====
  const minWeaponAttack = expedition.minWeaponAttack || 5
  const attackDiff = weaponAttack - minWeaponAttack
  if (attackDiff > 0) {
    const bonus = Math.min(15, attackDiff * 0.5)
    baseSuccess += bonus
    successModifiers.push({
      source: 'Оружие',
      sourceIcon: '⚔️',
      value: bonus,
      description: `Атака оружия выше требуемой на ${attackDiff}`,
      type: 'positive'
    })
  } else if (attackDiff < 0) {
    successModifiers.push({
      source: 'Оружие',
      sourceIcon: '⚔️',
      value: 0,
      description: `Атака оружия соответствует требованиям`,
      type: 'neutral'
    })
  }
  
  // ===== 3. ВЛИЯНИЕ РЕДКОСТИ =====
  const rarityMult = RARITY_MULTIPLIERS[adventurer.combat.rarity]
  if (adventurer.combat.rarity !== 'common') {
    warSoulModifiers.push({
      source: 'Редкость',
      sourceIcon: '⭐',
      value: Math.round((rarityMult.warSoul - 1) * 100),
      description: `${getRarityName(adventurer.combat.rarity)} искатель приносит больше душ`,
      type: 'positive'
    })
    goldModifiers.push({
      source: 'Редкость',
      sourceIcon: '⭐',
      value: Math.round((rarityMult.gold - 1) * 100),
      description: `${getRarityName(adventurer.combat.rarity)} искатель находит больше золота`,
      type: 'positive'
    })
  }
  
  // ===== 4. ВЛИЯНИЕ ХАРАКТЕРА =====
  const primaryTrait = getPersonalityTraitById(adventurer.personality.primaryTrait)
  if (primaryTrait) {
    const traitBonus = calculateTraitBonus(adventurer.personality.primaryTrait, difficulty)
    if (traitBonus !== 0) {
      baseSuccess += traitBonus
      successModifiers.push({
        source: primaryTrait.name,
        sourceIcon: primaryTrait.icon,
        value: traitBonus,
        description: primaryTrait.description,
        type: traitBonus > 0 ? 'positive' : 'negative'
      })
    }
  }
  
  // ===== 5. ВЛИЯНИЕ СТИЛЯ БОЯ =====
  const combatStyle = getCombatStyleById(adventurer.combat.combatStyle)
  if (combatStyle) {
    // Бонус от стиля боя к типу миссии
    const missionBonus = getMissionBonus(combatStyle, missionType)
    if (missionBonus !== 0) {
      baseSuccess += missionBonus
      successModifiers.push({
        source: combatStyle.name,
        sourceIcon: combatStyle.icon,
        value: missionBonus,
        description: missionBonus > 0 
          ? `Специализация на ${getMissionTypeName(missionType)}`
          : `Не подходит для ${getMissionTypeName(missionType)}`,
        type: missionBonus > 0 ? 'positive' : 'negative'
      })
    }
  }
  
  // ===== 6. ВЛИЯНИЕ СОЦИАЛЬНЫХ ТЕГОВ =====
  for (const socialTagId of adventurer.personality.socialTags) {
    const socialTag = getSocialTagById(socialTagId)
    if (socialTag) {
      // Модификатор золота
      if (socialTag.effects.goldModifier !== 0) {
        goldModifiers.push({
          source: socialTag.name,
          sourceIcon: socialTag.icon,
          value: socialTag.effects.goldModifier,
          description: socialTag.effects.goldModifier > 0
            ? 'Лучшие контракты благодаря репутации'
            : 'Скромные запросы',
          type: socialTag.effects.goldModifier > 0 ? 'positive' : 'negative'
        })
      }
    }
  }
  
  // ===== 7. ВЛИЯНИЕ СИЛЬНЫХ СТОРОН =====
  for (const strength of adventurer.strengths) {
    const data = getStrengthById(strength.id)
    if (data && doesStrengthApply(data, difficulty, missionType)) {
      // Бонус к успеху
      if (data.effects.successBonus !== 0) {
        baseSuccess += data.effects.successBonus
        successModifiers.push({
          source: data.name,
          sourceIcon: data.icon,
          value: data.effects.successBonus,
          description: data.description,
          type: 'positive'
        })
      }
      // Бонус к золоту
      if (data.effects.goldBonus !== 0) {
        goldModifiers.push({
          source: data.name,
          sourceIcon: data.icon,
          value: data.effects.goldBonus,
          description: data.description,
          type: 'positive'
        })
      }
      // Бонус к душам войны
      if (data.effects.warSoulBonus !== 0) {
        warSoulModifiers.push({
          source: data.name,
          sourceIcon: data.icon,
          value: data.effects.warSoulBonus,
          description: data.description,
          type: 'positive'
        })
      }
      // Снижение шанса потери оружия
      if (data.effects.weaponLossReduction !== 0) {
        weaponLossModifiers.push({
          source: data.name,
          sourceIcon: data.icon,
          value: -data.effects.weaponLossReduction,
          description: 'Защищает оружие',
          type: 'positive'
        })
      }
      // Снижение износа оружия
      if (data.effects.weaponWearReduction !== 0) {
        weaponWearModifiers.push({
          source: data.name,
          sourceIcon: data.icon,
          value: -data.effects.weaponWearReduction,
          description: 'Меньше износа',
          type: 'positive'
        })
      }
    }
  }
  
  // ===== 8. ВЛИЯНИЕ СЛАБОСТЕЙ =====
  for (const weakness of adventurer.weaknesses) {
    const data = getWeaknessById(weakness.id)
    if (data && doesWeaknessApply(data, difficulty, missionType)) {
      // Штраф к успеху
      if (data.effects.successPenalty !== 0) {
        baseSuccess += data.effects.successPenalty // Уже отрицательное число
        successModifiers.push({
          source: data.name,
          sourceIcon: '⚠️',
          value: data.effects.successPenalty,
          description: data.description,
          type: 'negative'
        })
      }
      // Штраф к золоту
      if (data.effects.goldPenalty !== 0) {
        goldModifiers.push({
          source: data.name,
          sourceIcon: '⚠️',
          value: -data.effects.goldPenalty,
          description: data.description,
          type: 'negative'
        })
      }
      // Штраф к душам войны
      if (data.effects.warSoulPenalty !== 0) {
        warSoulModifiers.push({
          source: data.name,
          sourceIcon: '⚠️',
          value: -data.effects.warSoulPenalty,
          description: data.description,
          type: 'negative'
        })
      }
      // Увеличение шанса потери оружия
      if (data.effects.weaponLossIncrease !== 0) {
        weaponLossModifiers.push({
          source: data.name,
          sourceIcon: '⚠️',
          value: data.effects.weaponLossIncrease,
          description: 'Риск для оружия',
          type: 'negative'
        })
      }
      // Увеличение износа оружия
      if (data.effects.weaponWearIncrease !== 0) {
        weaponWearModifiers.push({
          source: data.name,
          sourceIcon: '⚠️',
          value: data.effects.weaponWearIncrease,
          description: 'Больше износа',
          type: 'negative'
        })
      }
    }
  }
  
  // ===== 9. РАСЧЁТ КОМИССИИ =====
  const commissionPercent = Math.min(
    MAX_COMMISSION_PERCENT,
    BASE_COMMISSION_PERCENT + (guildLevel - 1) * COMMISSION_PER_GUILD_LEVEL
  )
  
  // Суммируем модификаторы золота
  let totalGoldMult = rarityMult.gold
  for (const mod of goldModifiers) {
    totalGoldMult += mod.value / 100
  }
  
  const baseGold = expedition.reward?.baseGold || 50
  const totalGold = Math.floor(baseGold * totalGoldMult)
  const commission = Math.floor(totalGold * commissionPercent / 100)
  
  // ===== 10. РАСЧЁТ ДУШ ВОЙНЫ =====
  // Суммируем модификаторы душ
  let totalWarSoulMult = rarityMult.warSoul
  for (const mod of warSoulModifiers) {
    totalWarSoulMult += mod.value / 100
  }
  
  const baseWarSoul = expedition.reward?.baseWarSoul || 3
  const warSoul = Math.max(1, Math.floor(baseWarSoul * totalWarSoulMult))
  
  // ===== 11. ИЗНОС ОРУЖИЯ =====
  let baseWeaponWear = 10 // Базовый износ
  for (const mod of weaponWearModifiers) {
    baseWeaponWear += mod.value
  }
  const weaponWear = Math.max(1, Math.min(50, baseWeaponWear))
  
  // ===== 12. ШАНС ПОТЕРИ ОРУЖИЯ =====
  let baseWeaponLossChance = difficultyData.weaponLossChance || 5
  for (const mod of weaponLossModifiers) {
    baseWeaponLossChance += mod.value
  }
  const weaponLossChance = Math.max(0, Math.min(50, baseWeaponLossChance))
  
  // ===== 13. РЕКОМЕНДАЦИЯ =====
  const finalSuccess = Math.max(5, Math.min(95, baseSuccess))
  let recommendation: ExpeditionCalculation['recommendation']
  
  if (finalSuccess >= 80) {
    recommendation = {
      rating: 'excellent',
      description: 'Отличный выбор! Высокий шанс успеха и хорошая награда.'
    }
  } else if (finalSuccess >= 60) {
    recommendation = {
      rating: 'good',
      description: 'Хороший выбор. Шанс успеха приемлемый.'
    }
  } else if (finalSuccess >= 40) {
    recommendation = {
      rating: 'risky',
      description: 'Рискованно. Есть значительный шанс провала.'
    }
  } else {
    recommendation = {
      rating: 'dangerous',
      description: 'Опасно! Высокий риск провала и потери оружия.'
    }
  }
  
  return {
    successChance: finalSuccess,
    commission,
    warSoul,
    weaponWear,
    weaponLossChance,
    successModifiers,
    goldModifiers,
    warSoulModifiers,
    weaponLossModifiers,
    weaponWearModifiers,
    levelMatch,
    recommendation
  }
}

// ================================
// ВСПОМОГАТЕЛЬНЫЕ ФУНКЦИИ
// ================================

function getRarityName(rarity: string): string {
  const names: Record<string, string> = {
    common: 'Обычный',
    uncommon: 'Необычный',
    rare: 'Редкий',
    epic: 'Эпический',
    legendary: 'Легендарный'
  }
  return names[rarity] || 'Обычный'
}

function getMissionTypeName(type: ExpeditionType): string {
  const names: Record<ExpeditionType, string> = {
    hunt: 'охоту',
    scout: 'разведку',
    clear: 'зачистку',
    delivery: 'доставку',
    magic: 'магические миссии'
  }
  return names[type] || 'миссию'
}

function calculateTraitBonus(traitId: string, difficulty: ExpeditionDifficulty): number {
  // Храбрые лучше на сложных миссиях
  if (traitId === 'brave' && (difficulty === 'hard' || difficulty === 'extreme' || difficulty === 'legendary')) {
    return 10
  }
  // Осторожные лучше на лёгких
  if (traitId === 'cautious' && difficulty === 'easy') {
    return 5
  }
  // Безрассудные всегда в плюсе на успех, но увеличивают риск
  if (traitId === 'reckless') {
    return 8
  }
  // Ветераны стабильны
  if (traitId === 'veteran') {
    return 5
  }
  // Ленивые хуже на долгих миссиях
  if (traitId === 'lazy') {
    return -5
  }
  return 0
