  const range = WARSOUL_RANGES[rarity]
  const amount = Math.floor(Math.random() * (range.max - range.min + 1)) + range.min

  return {
    type: 'warSoul',
    amount,
    rarity,
    name: `Души войны`,
    description: `${amount} душ войны`,
  }
}

/**
