  calculateWeaponLossChance,
} from '@/data/expedition-templates'

// ================================
// ТИПЫ
// ================================

export interface WeaponForExpedition {
  id: string
  name: string
  type: string
  attack: number
  quality: number
  durability: number
  warSoul: number
  epicMultiplier: number
}

export interface ExpeditionCompletionParams {
  expedition: ActiveExpedition
  guildLevel: number
  weapon?: WeaponForExpedition
}

export interface ExpeditionCompletionResult {
  success: boolean
  commission: number
  warSoul: number
  glory: number
  weaponWear: number
  weaponLost: boolean
  isCrit: boolean
  newKnownAdventurers?: KnownAdventurer[]
}

// ================================
// ГЕНЕРАЦИЯ ID
// ================================

const generateId = (): string => Math.random().toString(36).substring(2, 9)

// ================================
// ОСНОВНЫЕ ФУНКЦИИ
// ================================

/**
 * Рассчитать результат экспедиции
 */
export function calculateExpeditionOutcome(
  params: ExpeditionCompletionParams
): ExpeditionCompletionResult {
  const { expedition, guildLevel, weapon } = params
  const template = expeditionTemplates.find(t => t.id === expedition.expeditionId)
  
  if (!template) {
    return {
      success: false,
      commission: 0,
      warSoul: 0,
      glory: 0,
      weaponWear: 0,
      weaponLost: false,
      isCrit: false,
    }
  }

  const extendedAdventurer = expedition.adventurerExtended

  let success: boolean
  let commission: number
  let warSoul: number
  let gloryGained: number
  let weaponLost: boolean
  let weaponWear: number
  let isCrit = false

  if (extendedAdventurer && weapon) {
    // Новая система расчёта через модификаторы
    const calculation = calculateExpeditionResultV2(
      extendedAdventurer,
      template,
      guildLevel,
      weapon.attack,
      weapon.quality,
      weapon.type,
      weapon.id
    )

    const roll = Math.random() * 100
    success = roll < calculation.successChance

    isCrit = success && Math.random() * 100 < calculation.critChance
    const critMultiplier = isCrit ? 2 : 1

    commission = success ? Math.floor(calculation.commission * critMultiplier) : 0
    warSoul = success ? Math.floor(calculation.warSoul * critMultiplier) : 0
    gloryGained = success ? Math.floor((5 + Math.random() * 5) * critMultiplier) : 1

    weaponLost = !success && Math.random() * 100 < calculation.weaponLossChance
    weaponWear = calculation.weaponWear
  } else {
    // Fallback на старую систему
    const weaponAttack = weapon?.attack || 10
    const successChance = calculateSuccessChance(template, weaponAttack, 0)
    const roll = Math.random() * 100
    success = roll < successChance

    const weaponLossChance = calculateWeaponLossChance(template, weapon?.quality || 50, 0)
    weaponLost = !success && Math.random() * 100 < weaponLossChance

    commission = success ? calculateCommission(template, guildLevel, 0) : 0
    warSoul = success ? calculateWarSoul(template, 10, weapon?.quality || 50) : 0
    gloryGained = success ? 5 + Math.floor(Math.random() * 5) : 1
    weaponWear = success ? 5 + Math.floor(Math.random() * 10) : 20
  }

  return {
    success,
    commission,
    warSoul,
    glory: gloryGained,
    weaponWear,
    weaponLost,
    isCrit,
  }
}

/**
 * Обновить базу известных искателей после экспедиции
 */
export function updateKnownAdventurersAfterMission(
  knownAdventurers: KnownAdventurer[],
  extendedAdventurer: AdventurerExtended | undefined,
  result: ExpeditionCompletionResult,
  weaponType?: string
): KnownAdventurer[] {
  if (!extendedAdventurer) return knownAdventurers

  const missionResult: MissionResultForStats = {
    success: result.success,
    gold: result.commission,
    warSoul: result.warSoul,
    weaponType: weaponType as any,
  }

  return updateKnownAdventurer(knownAdventurers, extendedAdventurer, missionResult)
}

/**
 * Создать квест восстановления для потерянного оружия
 */
export function createRecoveryQuest(
  expedition: ActiveExpedition,
  template: ExpeditionTemplate,
  weapon: WeaponForExpedition
): RecoveryQuest {
  return {
    id: generateId(),
    lostWeaponId: weapon.id,
    lostWeaponData: weapon as any,
    originalExpeditionId: expedition.expeditionId,
    originalExpeditionName: expedition.expeditionName,
    cost: Math.floor(template.cost.deposit * 0.5),
    duration: template.duration * 2 * 1000,
    status: 'available',
  }
}

/**
 * Создать запись истории экспедиции
 */
export function createHistoryEntry(
  expedition: ActiveExpedition,
  result: ExpeditionCompletionResult
): GuildState['history'][0] {
  return {
    id: generateId(),
    expeditionName: expedition.expeditionName,
    expeditionIcon: expedition.expeditionIcon,
    adventurerName: expedition.adventurerName,
    adventurerData: expedition.adventurerData,
    adventurerExtended: expedition.adventurerExtended,
    weaponName: expedition.weaponName,
    completedAt: Date.now(),
    success: result.success,
    commission: result.commission,
    warSoul: result.warSoul,
    glory: result.glory,
    weaponLost: result.weaponLost,
  }
}

/**
 * Обновить статистику гильдии после экспедиции
 */
export function updateGuildStats(
  stats: GuildState['stats'],
  result: ExpeditionCompletionResult
): GuildState['stats'] {
  return {
    ...stats,
    totalExpeditions: stats.totalExpeditions + 1,
    successfulExpeditions: result.success
      ? stats.successfulExpeditions + 1
      : stats.successfulExpeditions,
    failedExpeditions: !result.success
      ? stats.failedExpeditions + 1
      : stats.failedExpeditions,
    weaponsLost: result.weaponLost
      ? stats.weaponsLost + 1
      : stats.weaponsLost,
    totalCommission: stats.totalCommission + result.commission,
    totalWarSoul: stats.totalWarSoul + result.warSoul,
    totalGlory: (stats.totalGlory ?? 0) + result.glory,
  }
}

/**
 * Рассчитать экспедицию для предпросмотра
 */
export function calculateExpeditionPreview(
  adventurer: AdventurerExtended,
  expedition: ExpeditionTemplate,
  weapon: WeaponForExpedition,
  guildLevel: number
): ExpeditionCalculation {
  return calculateExpeditionResultV2(
    adventurer,
    expedition,
    guildLevel,
    weapon.attack,
    weapon.quality,
    weapon.type,
    weapon.id
  )
}

/**
 * Order Achievability Utilities
 * Утилиты для проверки достижимости заказов и генерации достижимых заказов
 */

import { generateId, randomInt, randomElement, generateClientName } from './generators'
import { ORDER_MIN_QUALITY, ORDER_MAX_QUALITY, ORDER_BASE_GOLD_REWARD, ORDER_BASE_FAME_REWARD } from './constants'
import { calculateGoldReward, calculateFameReward } from './order-utils'
import { calculateAttack } from './craft-utils'
import { RESOURCE_SELL_PRICES } from './constants'
import { WeaponRecipe, weaponRecipes } from '@/data/weapon-recipes'
import { getCraftingCost } from '@/lib/craft/inventory-check'
import type { NPCOrder } from './order-utils'
import type { UnlockedRecipes } from '@/store/slices/craft-slice'

// ================================
// ТИПЫ
// ================================

export interface MaterialAdvance {
  materials: { resource: string; amount: number }[]
  totalCost: number
}

export interface OrderGenerationContext {
  playerLevel: number
  playerFame: number
  playerResources: Record<string, number>
  unlockedRecipes: UnlockedRecipes
  existingClients: string[]
}

export interface OrderCategory {
  type: 'basic' | 'progressive' | 'ambitious'
  weight: number
}

// ================================
// КОНСТАНТЫ
// ================================

const ORDER_CATEGORIES: OrderCategory[] = [
  { type: 'basic', weight: 60 },
  { type: 'progressive', weight: 30 },
  { type: 'ambitious', weight: 10 },
]

// ================================
// ПРОВЕРКА ДОСТИЖИМОСТИ ЗАКАЗА
// ================================

/**
 * Проверить, может ли игрок выполнить заказ
 */
export function checkOrderAchievability(
  order: NPCOrder,
  context: OrderGenerationContext
): { achievable: boolean; reason?: string } {
  // Проверка уровня и славы
  if (order.requiredLevel > context.playerLevel) {
    return { achievable: false, reason: 'Требуется более высокий уровень' }
  }
  if (order.requiredFame > context.playerFame) {
    return { achievable: false, reason: 'Требуется больше славы' }
  }

  // Найти подходящий рецепт
  const matchingRecipe = weaponRecipes.find(
    r => r.type === order.weaponType && r.material === order.material
  )

  if (!matchingRecipe) {
    return { achievable: false, reason: 'Нет подходящего рецепта' }
  }

  // Проверка, разблокирован ли рецепт
  const isRecipeUnlocked = context.unlockedRecipes.weaponRecipes.includes(matchingRecipe.id)
  if (!isRecipeUnlocked) {
    return { achievable: false, reason: 'Рецепт не разблокирован' }
  }

  // Проверка уровня для рецепта
  if (matchingRecipe.requiredLevel > context.playerLevel) {
    return { achievable: false, reason: 'Требуемый уровень для рецепта' }
  }

  // Проверка, может ли игрок создать такое качество
  const minPossibleQuality = calculateMinAchievableQuality(context.playerLevel)
  if (order.minQuality > minPossibleQuality * 1.3) {
    return { achievable: false, reason: 'Требуемое качество слишком высокое' }
  }

  // Проверка, может ли игрок создать такую атаку
  const maxPossibleAttack = calculateMaxAchievableAttack(
    matchingRecipe,
    context.playerLevel
  )
  if (order.minAttack && order.minAttack > maxPossibleAttack) {
    return { achievable: false, reason: 'Требуемая атака слишком высокая' }
  }

  return { achievable: true }
}

/**
 * Проверить, может ли игрок позволить материалы для рецепта
 */
export function checkCanAffordRecipeMaterials(
  recipe: WeaponRecipe,
  playerResources: Record<string, number>
): boolean {
  if (!recipe.cost) return true

  for (const [resource, amount] of Object.entries(recipe.cost)) {
    if (amount && (playerResources[resource] || 0) < amount) {
      return false
    }
  }

  return true
}

/**
 * Рассчитать стоимость материалов для выполнения заказа
 */
export function calculateMaterialCostForOrder(
  recipe: WeaponRecipe
): { materials: { resource: string; amount: number }[]; totalCost: number } {
  if (!recipe.cost) {
    return { materials: [], totalCost: 0 }
  }

  const materials: { resource: string; amount: number }[] = []
  let totalCost = 0

  for (const [resource, amount] of Object.entries(recipe.cost)) {
    if (amount > 0) {
      materials.push({ resource, amount })
      // Рассчитываем стоимость на основе цен продажи ресурсов
      const resourcePrice = RESOURCE_SELL_PRICES[resource as keyof typeof RESOURCE_SELL_PRICES] || 1
      totalCost += resourcePrice * amount
    }
  }

  return { materials, totalCost }
}

/**
 * Создать аванс материалов для заказа
 */
export function generateMaterialAdvance(
  recipe: WeaponRecipe,
  originalReward: number
): MaterialAdvance | null {
  const { materials, totalCost } = calculateMaterialCostForOrder(recipe)

  if (totalCost === 0) {
    return null
  }

  return {
    materials,
    totalCost: Math.min(totalCost, originalReward * 0.5), // Максимум 50% от награды
  }
}

// ================================
// РАСЧЁТ ВОЗМОЖНОСТЕЙ ИГРОКА
// ================================

/**
 * Рассчитать минимальное качество, которое игрок может создать
 */
export function calculateMinAchievableQuality(playerLevel: number): number {
  // Базовое качество на основе уровня (10-20 на уровне 1, до 60-70 на уровне 20)
  const baseQuality = 10 + playerLevel * 3
  // Добавляем небольшой запас (+20%)
  return Math.floor(baseQuality * 1.2)
}

/**
 * Рассчитать максимальную атаку, которую может создать игрок для рецепта
 */
export function calculateMaxAchievableAttack(
  recipe: WeaponRecipe,
  playerLevel: number
): number {
  // Используем максимальное качество, которое может создать игрок
  const maxQuality = Math.min(ORDER_MAX_QUALITY, 50 + playerLevel * 2)

  // Рассчитываем атаку с этим качеством
  return calculateAttack(
    recipe.type,
    recipe.tier,
    recipe.material,
    maxQuality
  )
}

/**
 * Фильтровать рецепты по прогрессивной сложности
 */
export function filterRecipesByProgression(
  category: 'basic' | 'progressive' | 'ambitious',
  context: OrderGenerationContext
): WeaponRecipe[] {
  return weaponRecipes.filter(recipe => {
    switch (category) {
      case 'basic':
        // Точно может сделать сейчас (рецепт разблокирован и уровень достаточен)
        return (
          context.unlockedRecipes.weaponRecipes.includes(recipe.id) &&
          recipe.requiredLevel <= context.playerLevel
        )

      case 'progressive':
        // Через 1-2 уровня реально (рецепт может быть ещё не разблокирован, но уровень почти достигнут)
        return (
          !context.unlockedRecipes.weaponRecipes.includes(recipe.id) &&
          recipe.requiredLevel <= context.playerLevel + 2 &&
          recipe.requiredLevel >= context.playerLevel
        )

      case 'ambitious':
        // Любые рецепты для мотивации
        return true

      default:
        return false
    }
  })
}

// ================================
// ГЕНЕРАЦИЯ ДОСТИЖИМЫХ ЗАКАЗОВ
// ================================

/**
 * Сгенерировать достижимый заказ
 */
export function generateAchievableOrder(context: OrderGenerationContext): NPCOrder | null {
  // Выбираем категорию заказа
  const category = selectOrderCategory()

  // Фильтруем рецепты по категории
  const availableRecipes = filterRecipesByProgression(category.type, context)

  console.log('[Order Generation] Category:', category.type, 'Available recipes:', availableRecipes.length, 'Unlocked recipes:', context.unlockedRecipes.weaponRecipes)

  if (availableRecipes.length === 0) {
    // Если нет рецептов в выбранной категории, пробуем базовую
    const basicRecipes = filterRecipesByProgression('basic', context)
    console.log('[Order Generation] Trying basic recipes:', basicRecipes.length)
    if (basicRecipes.length === 0) {
      console.warn('[Order Generation] No suitable recipes found')
      return null
    }
    return generateOrderFromRecipe(basicRecipes[Math.floor(Math.random() * basicRecipes.length)], context)
  }

  // Выбираем случайный рецепт
  const recipe = randomElement(availableRecipes)
  console.log('[Order Generation] Selected recipe:', recipe.id)

  return generateOrderFromRecipe(recipe, context)
}

/**
 * Выбрать категорию заказа на основе весов
 */
function selectOrderCategory(): OrderCategory {
  const totalWeight = ORDER_CATEGORIES.reduce((sum, cat) => sum + cat.weight, 0)
  let random = Math.random() * totalWeight

  for (const category of ORDER_CATEGORIES) {
    random -= category.weight
    if (random <= 0) {
      return category
    }
  }

  return ORDER_CATEGORIES[0]
}

/**
 * Сгенерировать заказ из рецепта
 */
function generateOrderFromRecipe(
  recipe: WeaponRecipe,
  context: OrderGenerationContext
): NPCOrder {
  // Генерируем клиента
  const client = generateClientName()

  // Проверка на дубликат клиента
  if (context.existingClients.includes(client.name)) {
    // Если дубликат, добавляем номер
    const existingCount = context.existingClients.filter(n => n.includes(client.name)).length
    client.name = `${client.name} ${existingCount + 1}`
  }

  // Рассчитываем достижимое качество для заказа
  const minQuality = calculateOrderQuality(recipe, context.playerLevel)

  // Рассчитываем возможную атаку для заказа
  const maxPossibleAttack = calculateMaxAchievableAttack(recipe, context.playerLevel)
  const minAttack = minQuality > 70 ? randomInt(10, Math.min(maxPossibleAttack, 20 + context.playerLevel)) : undefined

  // Рассчитываем точную стоимость материалов для хранения в заказе
  const materialCostMap = getCraftingCost(recipe, {})
  const resourcePrices: Record<string, number> = {
    iron: 2, wood: 1, stone: 1, coal: 1,
    ironIngot: 5, steelIngot: 12, bronzeIngot: 8,
    copper: 3, tin: 3, silver: 10, mithril: 25,
    leather: 3, planks: 2
  }
  const materialCost = Object.entries(materialCostMap).reduce((total, [resource, amount]) => {
    const price = resourcePrices[resource] || 1
    return total + (amount || 0) * price
  }, 0)

  // Награды (передаем recipe для точного расчета стоимости материалов)
  let goldReward = calculateGoldReward(minQuality, recipe.type, recipe.material, context.playerLevel, recipe)
  let fameReward = calculateFameReward(minQuality, context.playerFame)

  // Проверяем, может ли игрок позволить материалы
  const canAffordMaterials = checkCanAffordRecipeMaterials(recipe, context.playerResources)

  // Аванс материалов
  let materialAdvance: MaterialAdvance | undefined

  if (!canAffordMaterials) {
    materialAdvance = generateMaterialAdvance(recipe, goldReward)
    // НЕ уменьшаем награду здесь - это будет сделано при выполнении заказа
    // на основе фактического качества оружия
  }

  // Требования для появления
  const requiredLevel = Math.max(1, context.playerLevel - 2)
  const requiredFame = Math.max(0, context.playerFame - 50)

  const order: NPCOrder = {
    id: generateId(),
    clientName: client.name,
    clientTitle: client.title,
    clientIcon: client.icon,
    weaponType: recipe.type,
    material: recipe.material,
    minQuality,
    minAttack,
    goldReward,
    fameReward,
    materialCost, // Точная стоимость материалов для отображения диапазона
    status: 'available',
    requiredLevel,
    requiredFame,
  }

  return order
}

/**
 * Рассчитать качество для заказа
 */
function calculateOrderQuality(recipe: WeaponRecipe, playerLevel: number): number {
  const minPossible = calculateMinAchievableQuality(playerLevel)
  const maxPossible = Math.min(ORDER_MAX_QUALITY, 50 + playerLevel * 2)

  // Для базовых заказов - ближе к минимуму
  // Для прогрессивных - выше
  const variance = Math.random() * 0.4 + 0.1 // 10-50% диапазон

  const quality = Math.floor(
    minPossible + (maxPossible - minPossible) * variance
  )

  return Math.max(ORDER_MIN_QUALITY, Math.min(ORDER_MAX_QUALITY, quality))
}

/**
 * Order Utilities
 * Чистые функции для логики заказов (NPC заказы)
 * 
 * НОВАЯ ФОРМУЛА НАГРАД:
 * Награда = (Стоимость материалов × 2.0 + Крафт-бонус) × (1 + Качество/100) × (1 + Уровень×0.05)
 * Где Крафт-бонус = 20-40 золота в зависимости от сложности
 * 
 * Пример: Железный кинжал (23 золота материалы)
 * = (23 × 2.0 + 25) × 1.4 × 1.05 = 46 + 25 = 71 × 1.47 = 104 → Округляем до 45-55 для баланса
 * 
 * Упрощенная формула для баланса:
 * Награда = Материалы × 2.0 + Базовый бонус (15-30) + Качество × 0.5
 * Минимум 30, максимум 200
 */

import { generateId, generateClientName, randomInt, randomElement } from './generators'
import { ORDER_MIN_QUALITY, ORDER_MAX_QUALITY, ORDER_BASE_GOLD_REWARD, ORDER_BASE_FAME_REWARD } from './constants'
import type { OrderCompletionParams, OrderCompletionResult } from './types'
import type { WeaponRecipe } from '@/data/weapon-recipes'
import { getCraftingCost } from '@/lib/craft/inventory-check'

// ================================
// ТИПЫ
// ================================

export interface MaterialAdvance {
  materials: { resource: string; amount: number }[]
  totalCost: number
}

export interface NPCOrder {
  id: string
  clientName: string
  clientTitle: string
  clientIcon: string
  weaponType: string
  material?: string
  minQuality: number
  minAttack?: number
  goldReward: number
  fameReward: number
  bonusItems?: { resource: string; amount: number }[]
  materialAdvance?: MaterialAdvance
  status: 'available' | 'in_progress' | 'completed' | 'expired'
  acceptedAt?: number
  requiredLevel: number
  requiredFame: number
}

export interface OrderGenerationParams {
  playerLevel: number
  playerFame: number
  existingClients: string[]
}

export interface OrderGenerationResult {
  order: NPCOrder | null
  reason?: string
}

// ================================
// КОНСТАНТЫ
// ================================

const WEAPON_TYPES = ['sword', 'dagger', 'axe', 'mace', 'spear', 'hammer']
const MATERIALS = ['iron', 'bronze', 'steel', 'silver', 'gold', 'mithril']

const BONUS_ITEMS: { resource: string; minAmount: number; maxAmount: number }[] = [
  { resource: 'iron', minAmount: 5, maxAmount: 20 },
  { resource: 'coal', minAmount: 3, maxAmount: 15 },
  { resource: 'wood', minAmount: 10, maxAmount: 30 },
  { resource: 'stone', minAmount: 5, maxAmount: 20 },
]

// ================================
// ГЕНЕРАЦИЯ ЗАКАЗОВ
// ================================

/**
 * Рассчитать награду золотом на основе стоимости материалов
 * 
 * Новая формула:
 * 1. Получаем стоимость материалов для крафта
 * 2. Базовая награда = Стоимость материалов × 2.0 (100% markup за работу)
 * 3. Добавляем бонус за качество (minQuality × 0.3)
 * 4. Добавляем бонус за уровень (playerLevel × 2)
 * 5. Округляем до целого числа
 * 
 * Диапазон: 30-200 золота
 */
export function calculateGoldReward(
  minQuality: number,
  weaponType: string,
  material: string | undefined,
  playerLevel: number,
  recipeOrCost?: WeaponRecipe | number  // Рецепт или готовая стоимость материалов
): number {
  // Определяем стоимость материалов
  let materialCost = 0
  
  if (typeof recipeOrCost === 'number') {
    // Передана готовая стоимость материалов
    materialCost = recipeOrCost
  } else if (recipeOrCost) {
    // Передан рецепт — считаем точную стоимость материалов
    const materialCostMap = getCraftingCost(recipeOrCost, {})
    
    // Переводим ресурсы в золото (примерные цены)
    const resourcePrices: Record<string, number> = {
      iron: 2, wood: 1, stone: 1, coal: 1,
      ironIngot: 5, steelIngot: 12, bronzeIngot: 8,
      copper: 3, tin: 3, silver: 10, mithril: 25,
      leather: 3, planks: 2
    }
    
    materialCost = Object.entries(materialCostMap).reduce((total, [resource, amount]) => {
      const price = resourcePrices[resource] || 1
      return total + (amount || 0) * price
    }, 0)
  } else {
    // Приблизительная стоимость если нет данных
    const materialCosts: Record<string, number> = {
      iron: 15, bronze: 25, steel: 35, silver: 50, gold: 80, mithril: 120
    }
    materialCost = materialCosts[material || 'iron'] || 15
  }
  
  // Базовая награда: материалы × 2.0 (возмещение + оплата работы)
  let reward = materialCost * 2.0
  
  // Бонус за качество (0.3 золота за каждое очко качества)
  const qualityBonus = minQuality * 0.3
  reward += qualityBonus
  
  // Бонус за уровень игрока (2 золота за уровень)
  const levelBonus = playerLevel * 2
  reward += levelBonus
  
  // Бонус за тип оружия (сложность крафта)
  const typeBonus: Record<string, number> = {
    sword: 10, dagger: 5, axe: 8, mace: 8, spear: 8, hammer: 12
  }
  reward += typeBonus[weaponType] || 8
  
  // Округляем до целого
  reward = Math.floor(reward)
  
  // Ограничиваем диапазон
  return Math.max(30, Math.min(200, reward))
}

/**
 * Рассчитать диапазон награды золотом (минимум и максимум)
 * 
 * Минимум: за минимальное требуемое качество
 * Максимум: за качество 100 (или максимально возможное)
 * 
 * Используется для отображения в UI заказов
 */
export function calculateGoldRewardRange(
  minQuality: number,
  weaponType: string,
  material: string | undefined,
  playerLevel: number,
  recipeOrCost?: WeaponRecipe | number // Можно передать рецепт или готовую стоимость материалов
): { min: number; max: number; current: (quality: number) => number } {
  // Рассчитываем награду за минимальное качество
  const minReward = calculateGoldReward(minQuality, weaponType, material, playerLevel, recipeOrCost)
  
  // Рассчитываем награду за максимальное качество (100)
  const maxReward = calculateGoldReward(100, weaponType, material, playerLevel, recipeOrCost)
  
  // Функция для расчета награды за конкретное качество
  const getRewardForQuality = (quality: number): number => {
    // Награда растет линейно от minQuality до 100
    if (quality <= minQuality) return minReward
    if (quality >= 100) return maxReward
    
    // Линейная интерполяция
    const progress = (quality - minQuality) / (100 - minQuality)
    return Math.floor(minReward + (maxReward - minReward) * progress)
  }
  
  return { min: minReward, max: maxReward, current: getRewardForQuality }
}

/**
 * Рассчитать награду славой
 */
export function calculateFameReward(
  minQuality: number,
  playerFame: number
): number {
  const baseFame = ORDER_BASE_FAME_REWARD
  const qualityBonus = Math.floor(minQuality / 20)
  return baseFame + qualityBonus
}

/**
 * Сгенерировать бонусные предметы
 */
export function generateBonusItems(): { resource: string; amount: number }[] | undefined {
  // 30% шанс бонусных предметов
  if (Math.random() > 0.3) return undefined

  const numItems = randomInt(1, 2)
  const items: { resource: string; amount: number }[] = []

  for (let i = 0; i < numItems; i++) {
    const bonus = randomElement(BONUS_ITEMS)
    items.push({
      resource: bonus.resource,
      amount: randomInt(bonus.minAmount, bonus.maxAmount),
    })
  }

  return items.length > 0 ? items : undefined
}

/**
 * Сгенерировать новый заказ
 */
export function generateOrder(params: OrderGenerationParams): OrderGenerationResult {
  const { playerLevel, playerFame, existingClients } = params

  // Минимальный уровень для заказов
  if (playerLevel < 2) {
    return { order: null, reason: 'Требуется уровень 2' }
  }

  // Генерация клиента
  const client = generateClientName()

  // Проверка на дубликат клиента
  if (existingClients.includes(client.name)) {
    return { order: null, reason: 'Клиент уже заказывает' }
  }

  // Определение типа оружия
  const weaponType = randomElement(WEAPON_TYPES)

  // Определение материала (50% шанс указать)
  const material = Math.random() > 0.5 ? randomElement(MATERIALS) : undefined

  // Определение минимального качества
  const minQuality = randomInt(
    Math.max(ORDER_MIN_QUALITY, playerLevel * 2),
    Math.min(ORDER_MAX_QUALITY, 50 + playerLevel * 2)
  )

  // Минимальная атака (только для высоких требований качества)
  const minAttack = minQuality > 70 ? randomInt(10, 20 + playerLevel) : undefined

  // Награды
  const goldReward = calculateGoldReward(minQuality, weaponType, material, playerLevel)
  const fameReward = calculateFameReward(minQuality, playerFame)
  const bonusItems = generateBonusItems()

  const order: NPCOrder = {
    id: generateId(),
    clientName: client.name,
    clientTitle: client.title,
    clientIcon: client.icon,
    weaponType,
    material,
    minQuality,
    minAttack,
    goldReward,
    fameReward,
    bonusItems,
    status: 'available',
    requiredLevel: Math.max(1, playerLevel - 2),
    requiredFame: Math.max(0, playerFame - 50),
  }

  return { order }
}

// ================================
// ПРИНЯТИЕ ЗАКАЗА
// ================================

/**
 * Проверить возможность принятия заказа
 */
export function canAcceptOrder(params: {
  orderStatus: string
  hasActiveOrder: boolean
  playerLevel: number
  playerFame: number
  requiredLevel: number
  requiredFame: number
}): { can: boolean; reason: string } {
  if (params.orderStatus !== 'available') {
    return { can: false, reason: 'Заказ недоступен' }
  }

  if (params.hasActiveOrder) {
    return { can: false, reason: 'У вас уже есть активный заказ' }
  }

  if (params.playerLevel < params.requiredLevel) {
    return { can: false, reason: `Требуется уровень ${params.requiredLevel}` }
  }

  if (params.playerFame < params.requiredFame) {
    return { can: false, reason: `Требуется слава ${params.requiredFame}` }
  }

  return { can: true, reason: '' }
}

// ================================
// ВЫПОЛНЕНИЕ ЗАКАЗА
// ================================

/**
 * Проверить соответствие оружия требованиям заказа
 */
export function checkWeaponMatchesOrder(params: {
  weaponQuality: number
  weaponAttack: number
  weaponType: string
  weaponMaterial: string
  orderMinQuality: number
  orderMinAttack?: number
  orderWeaponType: string
  orderMaterial?: string
}): { matches: boolean; reason: string } {
  if (params.weaponType !== params.orderWeaponType) {
    return { matches: false, reason: 'Неподходящий тип оружия' }
  }

  if (params.weaponQuality < params.orderMinQuality) {
    return { matches: false, reason: `Качество должно быть не менее ${params.orderMinQuality}` }
  }

  if (params.orderMinAttack && params.weaponAttack < params.orderMinAttack) {
    return { matches: false, reason: `Атака должна быть не менее ${params.orderMinAttack}` }
  }

  if (params.orderMaterial && params.weaponMaterial !== params.orderMaterial) {
    return { matches: false, reason: `Требуется материал: ${params.orderMaterial}` }
  }

  return { matches: true, reason: '' }
}

/**
 * Выполнить заказ
 */
export function completeOrder(params: OrderCompletionParams): OrderCompletionResult {
  const check = checkWeaponMatchesOrder({
    weaponQuality: params.weaponQuality,
    weaponAttack: params.weaponAttack,
    weaponType: params.weaponType,
    weaponMaterial: params.weaponRecipeId.split('_')[0] || 'iron',
    orderMinQuality: params.orderMinQuality,
    orderMinAttack: params.orderMinAttack,
    orderWeaponType: params.orderWeaponType,
    orderMaterial: params.orderMaterial,
  })

  if (!check.matches) {
    return {
      success: false,
      goldEarned: 0,
      fameEarned: 0,
      error: check.reason,
    }
  }

  return {
    success: true,
    goldEarned: params.orderGoldReward,
    fameEarned: params.orderFameReward,
    bonusItems: params.orderBonusItems,
  }
}

