export const shouldRefreshAdventurers = (state: GuildSliceState): boolean => {
  return Date.now() >= state.adventurerRefreshAt
}

export const getTimeUntilRefresh = (state: GuildSliceState): number => {
  return Math.max(0, state.adventurerRefreshAt - Date.now())
}

export const getGuildLevelInfo = (state: GuildSliceState) => {
  const currentLevel = state.level
  const currentGlory = state.glory
  const nextLevel = GUILD_LEVELS.find(l => l.level === currentLevel + 1)
  const requiredGlory = nextLevel?.requiredGlory ?? 0

  return {
    level: currentLevel,
    currentGlory,
    nextLevelGlory: requiredGlory,
    progress: nextLevel ? Math.min(100, (currentGlory / requiredGlory) * 100) : 0,
  }
}

export const canStartExpedition = (
  expedition: ExpeditionTemplate,
  adventurer: Adventurer,
  weapon: CraftedWeaponV2,
  gold: number,
  activeExpeditions: ActiveExpedition[]
): { can: boolean; reason: string } => {
  // Проверка затрат
  const totalCost = expedition.cost.supplies + expedition.cost.deposit
  if (gold < totalCost) {
    return { can: false, reason: 'Недостаточно золота' }
  }

  // Проверка оружия
  if (weapon.currentDurability <= 10) {
    return { can: false, reason: 'Оружие слишком повреждено' }
  }

  if (weaponAttack(weapon) < expedition.minWeaponAttack) {
    return { can: false, reason: `Требуется атака ${expedition.minWeaponAttack}+` }
  }

  // Проверка требований искателя
  const minAttack = adventurer.requirements?.minAttack ?? 0
  if (weaponAttack(weapon) < minAttack) {
    return { can: false, reason: `Искатель требует атаку ${minAttack}+` }
  }

  // Проверяем, что оружие не в другой экспедиции
  if (activeExpeditions.some(e => e.weaponId === weapon.id)) {
    return { can: false, reason: 'Оружие уже в экспедиции' }
  }

  // Проверяем, что искатель не в другой экспедиции
  if (activeExpeditions.some(e => e.adventurerId === adventurer.id)) {
    return { can: false, reason: 'Искатель уже в экспедиции' }
  }

  return { can: true, reason: '' }
}

// ================================
// Расчёт результата экспедиции
// ================================

export const calculateExpeditionResult = (
  expedition: ExpeditionTemplate,
  adventurer: Adventurer,
  weapon: CraftedWeaponV2,
  guildLevel: number,
  guildGlory: number,
  contract?: ContractedAdventurer
): ExpeditionResult => {
  // Рассчитываем бонусы искателя
  const adventurerBonuses = calculateAdventurerBonuses(adventurer)

  // Базовые расчёты с применением бонусов
  const baseSuccessChance = calculateSuccessChance(expedition, weaponAttack(weapon), 0)
  const baseWeaponLossChance = calculateWeaponLossChance(expedition, weapon.quality, 0)

  // Применяем бонусы к шансам
  let successChance = Math.min(95, Math.max(5, 
    baseSuccessChance + adventurerBonuses.successRateBonus
  ))
  const weaponLossChance = Math.max(0, 
    baseWeaponLossChance * (1 + adventurerBonuses.weaponLossModifier / 100)
  )

  // Бонусы от контракта
  let commissionReduction = 0
  let critBonus = 0
  
  if (contract) {
    // Бонус к успеху от лояльности
    const { bonuses } = getLoyaltyStatus(contract.loyalty)
    successChance += bonuses.critChance ?? 0
    
    // Снижение комиссии
    commissionReduction = contract.contract.commissionReduction
    
    // Бонус к криту от высокой лояльности
    if (bonuses.critChance) {
      critBonus = bonuses.critChance
    }
  }

  // Определяем успех
  const roll = Math.random() * 100
  const success = roll < successChance

  // Проверяем критический успех (удвоение наград)
  const isCrit = success && Math.random() * 100 < (adventurerBonuses.critChance + critBonus)
  const critMultiplier = isCrit ? adventurerBonuses.critMultiplier : 1

  // Определяем потерю оружия
  const weaponLost = !success && Math.random() * 100 < weaponLossChance

  // Рассчитываем награды с бонусами
  const baseCommission = calculateCommission(expedition, guildLevel, guildGlory)
  const baseWarSoul = calculateWarSoul(expedition, adventurer.skill, weapon.quality)

  // Применяем бонусы к наградам (с учётом снижения комиссии)
  const commissionMultiplier = 1 + (adventurerBonuses.goldBonus - commissionReduction) / 100
  const commission = Math.floor(baseCommission * Math.max(0.5, commissionMultiplier) * critMultiplier)
  const warSoul = Math.floor(baseWarSoul * (1 + adventurerBonuses.warSoulBonus / 100) * critMultiplier)
  const glory = Math.floor((expedition.reward.baseWarSoul * 0.1 + (success ? 5 : 2)) * critMultiplier)

  // Износ оружия (если не потеряно)
  const baseWear = 5 + Math.random() * 10
  const weaponWear = Math.max(0, Math.floor(baseWear * (1 + adventurerBonuses.wearModifier / 100)))

  // Бонусные ресурсы от "Добытчика"
  const bonusResources: { resource: string; amount: number }[] = []
  if (adventurerBonuses.resourceChance > 0 && success && Math.random() * 100 < adventurerBonuses.resourceChance) {
    const types = ['iron', 'copper', 'tin', 'coal', 'wood', 'stone']
    const resource = types[Math.floor(Math.random() * types.length)]
    const amount = 1 + Math.floor(Math.random() * 3)
    bonusResources.push({ resource, amount })
  }

  // Бонусная эссенция от "Мага"
  let bonusEssence = adventurerBonuses.essenceGuaranteed
  if (adventurerBonuses.essenceChance > 0 && success && Math.random() * 100 < adventurerBonuses.essenceChance) {
    bonusEssence += 1
  }

  // Создаём квест восстановления если оружие потеряно
  let recoveryQuest: RecoveryQuest | undefined
  if (weaponLost) {
    recoveryQuest = {
      id: generateId(),
      lostWeaponId: weapon.id,
      lostWeaponData: weapon,
      originalExpeditionId: expedition.id,
      originalExpeditionName: expedition.name,
      cost: Math.floor(expedition.cost.deposit * 0.5),
      duration: expedition.duration * 1000 * 2,
      status: 'available',
    }
  }

  // Расчёт изменения лояльности для контракта
  let loyaltyChange = 0
  let contractTerminated = false
  
  if (contract) {
    const newLoyalty = updateLoyalty(contract, success, isCrit, weaponLost)
    loyaltyChange = newLoyalty - contract.loyalty
    
    // Проверка на расторжение контракта
    if (wantsToTerminate({ ...contract, loyalty: newLoyalty })) {
      contractTerminated = true
    }
  }

  return {
    success,
    commission,
    warSoul,
    bonusGold: 0,
    glory,
    weaponWear,
    weaponLost,
    recoveryQuest,
    bonusResources: bonusResources.length > 0 ? bonusResources : undefined,
    bonusEssence: bonusEssence > 0 ? bonusEssence : undefined,
    isCrit,
    loyaltyChange,
    contractTerminated,
  }
}

/**
 * Orders Slice
 * Управление заказами NPC (рыночные заказы)
 * Использует utils для генерации
 */

import type { StateCreator } from 'zustand'

// Импорт утилит
import {
  generateAchievableOrder,
  type OrderGenerationContext,
  type MaterialAdvance
} from '@/lib/store-utils/order-achievable-utils'
import type { CraftedWeaponV2 } from '@/types/craft-v2'
import { weaponAttack } from '@/lib/weapon-v2-helpers'

// ================================
// ХЕЛПЕР: Проверка соответствия оружия заказу
// ================================

/**
 * Проверяет, соответствует ли оружие требованиям заказа
 * Использует новую систему hiddenTags с fallback на старую
 */
function checkWeaponMatchesOrder(
  weapon: CraftedWeaponV2,
  order: NPCOrder
): boolean {
  // Проверка качества
  if (weapon.quality < order.minQuality) return false
  
  // Проверка атаки
  if (order.minAttack && weaponAttack(weapon) < order.minAttack) return false
  
  // Новая система: проверяем hiddenTags
  if (weapon.hiddenTags && weapon.hiddenTags.length > 0) {
    // Проверка типа оружия
    if (!weapon.hiddenTags.includes(order.weaponType)) return false
    
    // Проверка материала
    if (order.material && !weapon.hiddenTags.includes(order.material)) return false
  } else {
    // Fallback: старая система проверки
    if (weapon.type !== order.weaponType) return false
    if (order.material && weapon.recipeId && !weapon.recipeId.includes(order.material)) {
      return false
    }
  }
  
  return true
}

// ================================
// ТИПЫ
// ================================

/** Статус заказа */
export type OrderStatus = 'available' | 'in_progress' | 'completed' | 'expired'

/** Заказ от NPC */
export interface NPCOrder {
  id: string
  clientName: string
  clientTitle: string
  clientIcon: string
  weaponType: string
  material?: string
  minQuality: number
  minAttack?: number
  goldReward: number
  fameReward: number
  bonusItems?: OrderBonusItem[]
  materialAdvance?: MaterialAdvance
  advanceTaken?: number  // Сколько аванса было взято
  materialCost?: number   // Точная стоимость материалов для расчёта награды
  status: OrderStatus
  acceptedAt?: number
  completedAt?: number
  requiredLevel: number
  requiredFame: number
}

/** Бонусный предмет за выполнение заказа */
export interface OrderBonusItem {
  resource: string
  amount: number
}

/** Состояние заказов */
export interface OrdersState {
  orders: NPCOrder[]
  activeOrderId: string | null
}

/** Actions для заказов */
export interface OrdersActions {
  generateOrder: (context: OrderGenerationContext) => NPCOrder | null
  acceptOrder: (orderId: string) => boolean
  cancelOrder: (orderId: string) => { success: boolean; penalty: number }
  takeAdvance: (orderId: string, amount: number) => { success: boolean; taken: number }
  completeOrder: (orderId: string, weaponId: string, weapon: {
    quality: number
    attack: number
    type: string
    recipeId?: string
    hiddenTags?: string[]
  }) => { success: boolean; rewards: { gold: number; fame: number; bonusItems?: OrderBonusItem[] } }
  getActiveOrder: () => NPCOrder | undefined
  refreshOrders: () => void  // Обновить список доступных заказов
}

/** Полный тип slice - только действия и состояние */
export type OrdersSlice = OrdersState & OrdersActions

// ================================
// НАЧАЛЬНОЕ СОСТОЯНИЕ
// ================================

export const initialOrdersState: OrdersState = {
  orders: [],
  activeOrderId: null,
}

// ================================
// SLICE
// ================================

export const createOrdersSlice: StateCreator<
  OrdersSlice,
  [],
  [],
  OrdersSlice
> = (set, get) => ({
  // State
  orders: [],
  activeOrderId: null,

  // Actions
  generateOrder: (context) => {
    const state = get()

    // Проверяем лимит заказов
    const activeOrders = state.orders.filter(o => o.status === 'available').length
    if (activeOrders >= 3) {
      console.log('[Orders Slice] Order limit reached (3)')
      return null
    }

    console.log('[Orders Slice] Attempting to generate order, player level:', context.playerLevel, 'unlocked recipes:', context.unlockedRecipes.weaponRecipes.length)

    // Генерируем достижимый заказ с помощью новой утилиты
    const existingClients = state.orders
      .filter(o => o.status === 'available')
      .map(o => o.clientName)

    const generationContext = {
      ...context,
      existingClients,
    }

    const order = generateAchievableOrder(generationContext)

    if (!order) {
      console.warn('[Orders Slice] Failed to generate order')
      return null
    }

    // Проверяем, нет ли уже такого клиента
    if (state.orders.some(o => o.clientName === order.clientName && o.status === 'available')) {
      console.warn('[Orders Slice] Client already has an active order:', order.clientName)
      return null
    }

    console.log('[Orders Slice] Order generated successfully:', order.id, order.weaponType, order.material)

    set((state) => ({
      orders: [...state.orders, order]
    }))

    return order
  },

  acceptOrder: (orderId) => {
    const state = get()

    const order = state.orders.find(o => o.id === orderId)
    if (!order || order.status !== 'available') return false
    if (state.activeOrderId) return false // Уже есть активный заказ

    // Если есть аванс материалов, добавляем их в ресурсы (будет списано через composed store)
    // Примечание: здесь только логика, списание ресурсов происходит в composed store

    set((state) => ({
      orders: state.orders.map(o =>
        o.id === orderId
          ? { ...o, status: 'in_progress' as const, acceptedAt: Date.now(), advanceTaken: 0 }
          : o
      ),
      activeOrderId: orderId,
    }))

    return true
  },

  takeAdvance: (orderId, amount) => {
    const state = get()

    const order = state.orders.find(o => o.id === orderId)
    if (!order || order.status !== 'in_progress') {
      return { success: false, taken: 0 }
    }

    // Максимальный аванс - 50% от награды
    const maxAdvance = Math.floor(order.goldReward * 0.5)
    const alreadyTaken = order.advanceTaken || 0
    const availableAdvance = maxAdvance - alreadyTaken

    if (availableAdvance <= 0) {
      console.warn('[Orders Slice] No advance available for order:', orderId)
      return { success: false, taken: 0 }
    }

    // Ограничиваем запрошенную сумму доступным авансом
    const amountToTake = Math.min(amount, availableAdvance)

    // Примечание: добавление золота происходит в composed store

    set((state) => ({
      orders: state.orders.map(o =>
        o.id === orderId
          ? { ...o, advanceTaken: (o.advanceTaken || 0) + amountToTake }
          : o
      ),
    }))

    console.log('[Orders Slice] Advance taken:', amountToTake, 'from order:', orderId)
    return { success: true, taken: amountToTake }
  },

  cancelOrder: (orderId) => {
    const state = get()
    
    const order = state.orders.find(o => o.id === orderId)
    if (!order || order.status !== 'in_progress') {
      return { success: false, penalty: 0 }
    }

    // Рассчитать штраф: 10% от награды или минимум 5 золота
    const penalty = Math.max(5, Math.floor(order.goldReward * 0.1))

    // Примечание: списание штрафа происходит в composed store

    // Вернуть заказ в статус available
    set((state) => ({
      orders: state.orders.map(o =>
        o.id === orderId
          ? { ...o, status: 'available' as const, acceptedAt: undefined }
          : o
      ),
      activeOrderId: null,
    }))

    return { success: true, penalty }
  },

  completeOrder: (orderId, _weaponId, weapon) => {
    const state = get()

    const order = state.orders.find(o => o.id === orderId)
    if (!order || order.status !== 'in_progress') {
      return { success: false, rewards: { gold: 0, fame: 0 } }
    }

    // Проверяем требования с помощью новой функции
    const matches = checkWeaponMatchesOrder(weapon, order)
    if (!matches) {
      return { success: false, rewards: { gold: 0, fame: 0 } }
    }

    // Награды будут рассчитаны в composed store на основе качества оружия
    const rewards = {
      gold: order.goldReward, // Временное значение, будет перезаписано в composed store
      fame: order.fameReward,
      bonusItems: order.bonusItems,
    }

    // Обновляем статус заказа
    set((state) => ({
      orders: state.orders.map(o =>
        o.id === orderId
          ? { ...o, status: 'completed' as const, completedAt: Date.now() }
          : o
      ),
      activeOrderId: null,
    }))

    return { success: true, rewards }
  },

  getActiveOrder: () => {
    const state = get()
    if (!state.activeOrderId) return undefined
    return state.orders.find(o => o.id === state.activeOrderId)
  },

  refreshOrders: () => {
    const state = get()
    
    // Удаляем все доступные заказы (не помечаем, а именно удаляем)
    // Оставляем только активные, выполненные и просроченные
    const updatedOrders = state.orders.filter(o => o.status !== 'available')
    
    set({ orders: updatedOrders })
    
    // После этого useEffect в контейнере увидит изменение orders.length 
    // и автоматически сгенерирует новые заказы
    console.log('[Orders Slice] Orders refreshed, available orders removed. Total orders:', updatedOrders.length)
  },
})

